/* ============================================================
 * ConversationSentiment - heuristic sentiment analysis with mood timeline
 *
 * Analyses each message using keyword-based sentiment scoring and
 * displays a live mood indicator + sparkline timeline showing how
 * the conversation's emotional tone evolves.
 *
 * Features:
 *   - Per-message sentiment score (-1 to +1)
 *   - Rolling mood indicator (emoji + label)
 *   - Sparkline timeline of sentiment over the conversation
 *   - Overall conversation sentiment summary
 *   - Toggle panel with Ctrl+Shift+M
 *
 * @namespace ConversationSentiment
 * ============================================================ */
const ConversationSentiment = (() => {

  /* ── Sentiment lexicon ───────────────────────────────────── */
  const POSITIVE_WORDS = new Set([
    'good', 'great', 'excellent', 'amazing', 'wonderful', 'fantastic',
    'awesome', 'love', 'happy', 'joy', 'perfect', 'brilliant', 'beautiful',
    'thanks', 'thank', 'helpful', 'nice', 'cool', 'best', 'glad',
    'appreciate', 'impressive', 'outstanding', 'superb', 'delightful',
    'exciting', 'pleased', 'enjoy', 'success', 'win', 'solved', 'works',
    'correct', 'right', 'yes', 'agree', 'exactly', 'indeed', 'sure',
    'easy', 'simple', 'clear', 'fast', 'quick', 'efficient', 'elegant',
    'clean', 'smooth', 'well', 'fine', 'interesting', 'useful', 'clever'
  ]);

  const NEGATIVE_WORDS = new Set([
    'bad', 'terrible', 'awful', 'horrible', 'wrong', 'error', 'fail',
    'failed', 'bug', 'broken', 'crash', 'issue', 'problem', 'difficult',
    'hard', 'confusing', 'confused', 'frustrating', 'frustrated', 'angry',
    'hate', 'worst', 'ugly', 'slow', 'mess', 'annoying', 'annoyed',
    'disappointed', 'unfortunately', 'sadly', 'sorry', 'stuck', 'lost',
    'impossible', 'never', 'useless', 'waste', 'complex', 'complicated',
    'unclear', 'pain', 'painful', 'struggling', 'struggle', 'nightmare',
    'ridiculous', 'stupid', 'nonsense', 'absurd', 'broken', 'cannot',
    'unable', 'reject', 'denied', 'missing', 'lack', 'poor', 'weak'
  ]);

  const INTENSIFIERS = new Set([
    'very', 'really', 'extremely', 'incredibly', 'absolutely', 'totally',
    'completely', 'utterly', 'super', 'highly', 'remarkably', 'so'
  ]);

  const NEGATORS = new Set([
    'not', 'no', 'never', 'neither', 'nor', 'none', "don't", "doesn't",
    "didn't", "won't", "wouldn't", "couldn't", "shouldn't", "isn't",
    "aren't", "wasn't", "weren't", "can't", "cannot", "hardly", "barely"
  ]);

  /* ── Mood mappings ───────────────────────────────────────── */
  const MOODS = [
    { min: 0.5,   emoji: '😄', label: 'Very Positive', color: '#27ae60' },
    { min: 0.15,  emoji: '🙂', label: 'Positive',      color: '#2ecc71' },
    { min: -0.15, emoji: '😐', label: 'Neutral',        color: '#95a5a6' },
    { min: -0.5,  emoji: '😕', label: 'Negative',       color: '#e67e22' },
    { min: -Infinity, emoji: '😞', label: 'Very Negative', color: '#e74c3c' }
  ];

  let visible = SafeStorage.getJSON('ac-sentiment-visible', false);
  let panel = null;

  /* ── Core analysis ───────────────────────────────────────── */

  /** Tokenize text into lowercase words (public API — used by tests/external callers). */
  function tokenize(text) {
    return String(text).toLowerCase().replace(/[^a-z'-]/g, ' ').split(/\s+/).filter(w => w.length > 1);
  }

  /**
   * Regex for allocation-free word iteration.
   * Matches sequences of letters/apostrophes (length ≥ 2) without
   * creating an intermediate array via split()+filter().
   */
  const _SENT_WORD_RE = /[a-z']{2,}/g;

  /**
   * Score a single message's sentiment.
   * Optimised: uses regex exec loop with a 1-word lookback variable
   * instead of allocating a full words array via tokenize().
   * Eliminates the temporary array + filter allocation per call.
   * @param {string} text
   * @returns {number} Score from -1 to +1
   */
  function scoreMessage(text) {
    const lower = String(text).toLowerCase();
    _SENT_WORD_RE.lastIndex = 0;

    let score = 0;
    let wordCount = 0;
    let prevWord = '';
    let m;

    while ((m = _SENT_WORD_RE.exec(lower)) !== null) {
      const word = m[0];
      wordCount++;
      let wordScore = 0;

      if (POSITIVE_WORDS.has(word)) wordScore = 1;
      else if (NEGATIVE_WORDS.has(word)) wordScore = -1;

      if (wordScore !== 0) {
        // Check for negation (flip sentiment)
        if (prevWord && NEGATORS.has(prevWord)) {
          wordScore *= -0.5;
        }
        // Check for intensifier
        if (prevWord && INTENSIFIERS.has(prevWord)) {
          wordScore *= 1.5;
        }
        score += wordScore;
      }
      prevWord = word;
    }

    if (wordCount === 0) return 0;

    // Normalize to -1..+1 range
    const maxPossible = Math.max(1, wordCount * 0.3);
    return Math.max(-1, Math.min(1, score / maxPossible));
  }

  /**
   * Analyse all messages in the conversation.
   * @param {Array} [messages] - optional message array; defaults to ConversationManager history
   * @returns {{ scores: number[], average: number, mood: Object, trend: string }}
   */
  function analyse(messages) {
    const msgs = messages || (typeof ConversationManager !== 'undefined'
      ? ConversationManager.getUserMessages()
      : []);

    const scores = msgs.map(m => scoreMessage(m.content || ''));

    if (scores.length === 0) {
      return {
        scores: [],
        average: 0,
        mood: MOODS.find(m => 0 >= m.min),
        trend: 'stable',
        messageCount: 0
      };
    }

    const average = scores.reduce((a, b) => a + b, 0) / scores.length;
    const mood = MOODS.find(m => average >= m.min) || MOODS[MOODS.length - 1];

    // Trend: compare first half vs second half
    let trend = 'stable';
    if (scores.length >= 4) {
      const mid = Math.floor(scores.length / 2);
      const firstHalf = scores.slice(0, mid).reduce((a, b) => a + b, 0) / mid;
      const secondHalf = scores.slice(mid).reduce((a, b) => a + b, 0) / (scores.length - mid);
      const diff = secondHalf - firstHalf;
      if (diff > 0.1) trend = 'improving';
      else if (diff < -0.1) trend = 'declining';
    }

    return { scores, average: Math.round(average * 100) / 100, mood, trend, messageCount: scores.length };
  }

  /**
   * Get the mood object for a given score.
   * @param {number} score
   * @returns {Object}
   */
  function getMood(score) {
    return MOODS.find(m => score >= m.min) || MOODS[MOODS.length - 1];
  }

  /* ── Sparkline rendering ─────────────────────────────────── */

  /**
   * Generate an SVG sparkline from scores.
   * @param {number[]} scores
   * @param {number} [width=200]
   * @param {number} [height=30]
   * @returns {string} SVG markup
   */
  function sparklineSVG(scores, width, height) {
    width = width || 200;
    height = height || 30;
    if (!scores || scores.length === 0) {
      return '<svg width="' + width + '" height="' + height + '"></svg>';
    }

    const mid = height / 2;
    const xStep = scores.length > 1 ? width / (scores.length - 1) : width / 2;
    const points = scores.map((s, i) => {
      const x = scores.length > 1 ? i * xStep : width / 2;
      const y = mid - (s * (mid - 2)); // -1 → bottom, +1 → top
      return x.toFixed(1) + ',' + y.toFixed(1);
    });

    // Color gradient based on average
    const avg = scores.reduce((a, b) => a + b, 0) / scores.length;
    const mood = getMood(avg);

    return '<svg width="' + width + '" height="' + height + '" viewBox="0 0 ' + width + ' ' + height + '">' +
      '<line x1="0" y1="' + mid + '" x2="' + width + '" y2="' + mid + '" ' +
      'stroke="#ddd" stroke-width="0.5" stroke-dasharray="2,2"/>' +
      '<polyline fill="none" stroke="' + mood.color + '" stroke-width="1.5" ' +
      'stroke-linejoin="round" stroke-linecap="round" points="' + points.join(' ') + '"/>' +
      '</svg>';
  }

  /* ── UI ──────────────────────────────────────────────────── */

  function renderPanel() {
    if (!panel) return;
    const result = analyse();
    const { scores, average, mood, trend, messageCount } = result;

    const trendIcon = trend === 'improving' ? '📈' : trend === 'declining' ? '📉' : '➡️';
    const trendLabel = trend.charAt(0).toUpperCase() + trend.slice(1);

    panel.innerHTML = '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">' +
      '<span style="font-size:20px;">' + mood.emoji + '</span>' +
      '<span style="font-weight:600;color:' + mood.color + ';">' + mood.label + '</span>' +
      '<span style="color:var(--text-secondary,#666);font-size:12px;">' +
      'Score: ' + average.toFixed(2) + ' · ' + trendIcon + ' ' + trendLabel +
      ' · ' + messageCount + ' messages</span></div>' +
      '<div style="margin-top:4px;" title="Sentiment over conversation">' +
      sparklineSVG(scores, panel.offsetWidth - 24 || 200, 30) + '</div>';
  }

  function toggle() {
    visible = !visible;
    SafeStorage.setJSON('ac-sentiment-visible', visible);
    if (panel) {
      panel.style.display = visible ? 'block' : 'none';
      if (visible) renderPanel();
    }
    return visible;
  }

  function isVisible() { return visible; }

  function init() {
    if (typeof document === 'undefined') return;

    panel = document.createElement('div');
    panel.id = 'conversation-sentiment';
    panel.style.cssText = 'padding:8px 12px;font-size:12px;font-family:inherit;' +
      'border-bottom:1px solid var(--border-color,#e0e0e0);' +
      'background:var(--bg-secondary,#f8f9fa);display:' + (visible ? 'block' : 'none') + ';';

    const chatOutput = DOMCache.get('chat-output');
    if (chatOutput && chatOutput.parentNode) {
      chatOutput.parentNode.insertBefore(panel, chatOutput);
    } else {
      document.body.appendChild(panel);
    }

    // Keyboard shortcut: Ctrl+Shift+M
    document.addEventListener('keydown', e => {
      if (e.ctrlKey && e.shiftKey && e.key === 'M') {
        e.preventDefault();
        toggle();
      }
    });

    if (visible) renderPanel();
  }

  /* ── Exports ─────────────────────────────────────────────── */

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = {
      POSITIVE_WORDS, NEGATIVE_WORDS, INTENSIFIERS, NEGATORS, MOODS,
      tokenize, scoreMessage, analyse, getMood, sparklineSVG,
      toggle, isVisible, renderPanel, init
    };
  }

  return {
    MOODS,
    tokenize, scoreMessage, analyse, getMood, sparklineSVG,
    toggle, isVisible, init
  };
})();

document.addEventListener('DOMContentLoaded', ConversationSentiment.init);

/* ---------- Quick Session Switcher (Ctrl+K) ---------- */
/**
 * VS Code / Slack-style quick session switcher.
 * Opens a fuzzy-search overlay to instantly jump between sessions.
 * Supports keyboard navigation (Up/Down/Enter/Esc) and fuzzy matching.
 *
 * @namespace QuickSwitcher
 */
const QuickSwitcher = (() => {
  let isVisible = false;
  let selectedIndex = 0;
  let filteredSessions = [];

  // fuzzyMatch / fuzzyScore — use shared top-level _fuzzyMatch / _fuzzyScore
  const fuzzyMatch = _fuzzyMatch;
  const fuzzyScore = _fuzzyScore;

  function _createOverlay() {
    let overlay = DOMCache.get('quick-switcher-overlay');
    if (overlay) return overlay;

    overlay = document.createElement('div');
    overlay.id = 'quick-switcher-overlay';
    overlay.className = 'quick-switcher-overlay';
    overlay.innerHTML = ''
      + '<div class="quick-switcher-modal">'
      + '<input type="text" id="quick-switcher-input" class="quick-switcher-input"'
      + ' placeholder="Switch to session\u2026 (type to filter)" autocomplete="off" />'
      + '<div id="quick-switcher-results" class="quick-switcher-results"></div>'
      + '<div class="quick-switcher-footer">'
      + '<span>\u2191\u2193 navigate</span> <span>\u21b5 select</span> <span>esc close</span>'
      + '</div></div>';
    document.body.appendChild(overlay);

    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) hide();
    });

    const input = DOMCache.get('quick-switcher-input');
    input.addEventListener('input', () => { _updateResults(input.value); });
    input.addEventListener('keydown', _handleKeydown);

    return overlay;
  }

  function _handleKeydown(e) {
    if (e.key === 'Escape') { e.preventDefault(); hide(); return; }
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      selectedIndex = Math.min(selectedIndex + 1, filteredSessions.length - 1);
      _highlightSelected(); return;
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault();
      selectedIndex = Math.max(selectedIndex - 1, 0);
      _highlightSelected(); return;
    }
    if (e.key === 'Enter') {
      e.preventDefault();
      const session = filteredSessions[selectedIndex];
      if (session) {
        hide();
        SessionManager.load(session.id);
        if (typeof SessionManager.refresh === 'function') SessionManager.refresh();
      }
      return;
    }
  }

  function _updateResults(query) {
    const results = DOMCache.get('quick-switcher-results');
    if (!results) return;

    let sessions;
    try { sessions = SessionManager.getAll(); } catch { sessions = []; }

    if (!query.trim()) {
      filteredSessions = sessions.slice(0, 15);
    } else {
      filteredSessions = sessions
        .filter(s => fuzzyMatch(query, s.name) || (s.preview && fuzzyMatch(query, s.preview)))
        .sort((a, b) => fuzzyScore(query, a.name) - fuzzyScore(query, b.name))
        .slice(0, 15);
    }

    selectedIndex = 0;

    if (filteredSessions.length === 0) {
      results.innerHTML = '<div class="quick-switcher-empty">No sessions found</div>';
      return;
    }

    results.innerHTML = filteredSessions.map((s, i) => {
      const date = new Date(s.updatedAt).toLocaleDateString();
      const msgCount = s.messageCount || 0;
      const preview = s.preview ? s.preview.substring(0, 80) : '';
      return '<div class="quick-switcher-item' + (i === 0 ? ' selected' : '') + '" data-index="' + i + '">'
        + '<div class="quick-switcher-item-name">' + _escapeHtml(s.name) + '</div>'
        + '<div class="quick-switcher-item-meta">' + msgCount + ' msg' + (msgCount !== 1 ? 's' : '') + ' \u00b7 ' + date + '</div>'
        + (preview ? '<div class="quick-switcher-item-preview">' + _escapeHtml(preview) + '</div>' : '')
        + '</div>';
    }).join('');

    results.querySelectorAll('.quick-switcher-item').forEach(el => {
      el.addEventListener('click', () => {
        const idx = parseInt(el.dataset.index, 10);
        const session = filteredSessions[idx];
        if (session) {
          hide();
          SessionManager.load(session.id);
          if (typeof SessionManager.refresh === 'function') SessionManager.refresh();
        }
      });
    });
  }

  function _highlightSelected() {
    const results = DOMCache.get('quick-switcher-results');
    if (!results) return;
    results.querySelectorAll('.quick-switcher-item').forEach((el, i) => {
      el.classList.toggle('selected', i === selectedIndex);
      if (i === selectedIndex) el.scrollIntoView({ block: 'nearest' });
    });
  }

  // uses global _escapeHtml

  function show() {
    const overlay = _createOverlay();
    overlay.classList.add('visible');
    isVisible = true;
    selectedIndex = 0;
    const input = DOMCache.get('quick-switcher-input');
    if (input) { input.value = ''; input.focus(); }
    _updateResults('');
  }

  function hide() {
    const overlay = DOMCache.get('quick-switcher-overlay');
    if (overlay) overlay.classList.remove('visible');
    isVisible = false;
  }

  function toggle() {
    if (isVisible) hide(); else show();
  }

  return { show, hide, toggle };
})();

/* ---------- Word Cloud (module 46) ---------- */
/**
 * Generates an interactive word cloud visualization from the current
 * conversation. Words are sized by frequency, colored by role (user vs
 * assistant), and clickable to search for that term in messages.
 * Toggle: Ctrl+Shift+W or the ☁️ button.
 */
const WordCloud = (() => {
  let panelEl = null;
  let isVisible = false;

  /* ---- stop-words — extends shared COMMON_STOP_WORDS with domain terms ---- */
  const STOP_WORDS = new Set([...COMMON_STOP_WORDS,
    'code', 'data', 'function', 'year', 'cannot', 'dare',
    'doing', 'done', 'getting', 'said', 'went', 'going',
  ]);

  const MIN_WORD_LENGTH = 3;
  const MAX_WORDS = 80;
  const MIN_FONT = 12;
  const MAX_FONT = 52;

  function _extractWords() {
    const history = ConversationManager.getHistory();
    const freq = {};   // word -> { count, userCount, assistantCount }
    for (const msg of history) {
      const text = (msg.content || '').toLowerCase().replace(/```[\s\S]*?```/g, ' ')
        .replace(/`[^`]+`/g, ' ')
        .replace(/https?:\/\/\S+/g, ' ')
        .replace(/[^a-z0-9\s'-]/g, ' ');
      const words = text.split(/\s+/).filter(w => w.length >= MIN_WORD_LENGTH && !STOP_WORDS.has(w));
      for (const w of words) {
        if (!freq[w]) freq[w] = { count: 0, userCount: 0, assistantCount: 0 };
        freq[w].count++;
        if (msg.role === 'user') freq[w].userCount++;
        else freq[w].assistantCount++;
      }
    }
    return Object.entries(freq)
      .sort((a, b) => b[1].count - a[1].count)
      .slice(0, MAX_WORDS);
  }

  function _render() {
    if (!panelEl) return;
    const words = _extractWords();
    const cloud = panelEl.querySelector('.wc-cloud');
    cloud.innerHTML = '';

    if (words.length === 0) {
      cloud.innerHTML = '<p class="wc-empty">No words yet - start a conversation!</p>';
      return;
    }

    const maxCount = words[0][1].count;
    const minCount = words[words.length - 1][1].count;
    const range = Math.max(maxCount - minCount, 1);

    for (const [word, info] of words) {
      const size = MIN_FONT + ((info.count - minCount) / range) * (MAX_FONT - MIN_FONT);
      const userRatio = info.userCount / info.count;
      // Blend: user = blue-ish (#4a90d9), assistant = green-ish (#50c878)
      const r = Math.round(74 * userRatio + 80 * (1 - userRatio));
      const g = Math.round(144 * userRatio + 200 * (1 - userRatio));
      const b = Math.round(217 * userRatio + 120 * (1 - userRatio));
      const opacity = 0.6 + 0.4 * ((info.count - minCount) / range);

      const span = document.createElement('span');
      span.className = 'wc-word';
      span.textContent = word;
      span.style.fontSize = size + 'px';
      span.style.color = `rgba(${r},${g},${b},${opacity})`;
      span.title = `"${word}" - ${info.count}× (user: ${info.userCount}, AI: ${info.assistantCount})`;
      span.addEventListener('click', () => {
        // Trigger message search if available
        if (typeof MessageSearch !== 'undefined' && MessageSearch.open) {
          close();
          MessageSearch.open(word);
        }
      });
      cloud.appendChild(span);
      cloud.appendChild(document.createTextNode(' '));
    }
  }

  function _createPanel() {
    if (panelEl) return panelEl;
    panelEl = document.createElement('div');
    panelEl.id = 'word-cloud-panel';
    panelEl.className = 'wc-panel';
    panelEl.innerHTML = ''
      + '<div class="wc-header">'
      + '<span class="wc-title">☁️ Word Cloud</span>'
      + '<div class="wc-actions">'
      + '<button class="btn-sm wc-refresh" title="Refresh">🔄</button>'
      + '<button class="btn-sm wc-close" title="Close">✕</button>'
      + '</div></div>'
      + '<div class="wc-legend">'
      + '<span class="wc-legend-user">● You</span>'
      + '<span class="wc-legend-ai">● AI</span>'
      + '<span class="wc-legend-hint">Click a word to search</span>'
      + '</div>'
      + '<div class="wc-cloud"></div>';
    document.body.appendChild(panelEl);
    panelEl.querySelector('.wc-close').addEventListener('click', close);
    panelEl.querySelector('.wc-refresh').addEventListener('click', _render);
    return panelEl;
  }

  function open() {
    _createPanel();
    panelEl.classList.add('visible');
    isVisible = true;
    _render();
  }

  function close() {
    if (panelEl) panelEl.classList.remove('visible');
    isVisible = false;
  }

  function toggle() { isVisible ? close() : open(); }

  function init() {
    const btn = DOMCache.get('wordcloud-btn');
    if (btn) btn.addEventListener('click', toggle);

    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'W') {
        e.preventDefault();
        toggle();
      }
    });
  }

  return { init, open, close, toggle };
})();

document.addEventListener('DOMContentLoaded', WordCloud.init);


/* ---------- ChatGPT Importer ---------- */
/**
 * Import ChatGPT exported conversations (conversations.json).
 * ChatGPT exports a JSON array of conversations, each with a nested
 * `mapping` tree of message nodes. This module parses that format,
 * walks the tree to extract messages in order, and creates sessions
 * via SessionManager.importSession().
 *
 * Supports both single-conversation and multi-conversation files.
 * Triggered from a dedicated button in the History panel or via
 * the /import-chatgpt slash command.
 *
 * @namespace ChatGPTImporter
 */
const ChatGPTImporter = (() => {
  const MAX_CONVERSATIONS = 200;
  const MAX_MESSAGES_PER = 500;

  /**
   * Parse a ChatGPT conversations.json structure.
   * @param {string} jsonString - raw JSON text
   * @returns {{ imported: number, skipped: number, names: string[] }}
   */
  function importFromJSON(jsonString) {
    let data;
    try {
      data = _safeParse(jsonString);
    } catch (_) {
      throw new Error('Invalid JSON file');
    }

    // Accept both array (full export) and single object
    const conversations = Array.isArray(data) ? data : [data];
    if (conversations.length === 0) throw new Error('No conversations found');

    let imported = 0, skipped = 0;
    const names = [];
    const limit = Math.min(conversations.length, MAX_CONVERSATIONS);

    for (let i = 0; i < limit; i++) {
      const conv = conversations[i];
      if (!conv || typeof conv !== 'object') { skipped++; continue; }

      const messages = _extractMessages(conv);
      if (messages.length === 0) { skipped++; continue; }

      const title = typeof conv.title === 'string' && conv.title.trim()
        ? conv.title.trim().substring(0, 200)
        : 'ChatGPT Import';

      // Build a session object compatible with SessionManager.importSession
      const sessionJSON = JSON.stringify({
        session: { name: title + ' (ChatGPT)', messages }
      });

      const result = SessionManager.importSession(sessionJSON);
      if (result) {
        imported++;
        names.push(title);
      } else {
        skipped++;
      }
    }

    return { imported, skipped, names };
  }

  /**
   * Walk the ChatGPT mapping tree and extract messages in order.
   * @param {object} conv - a single conversation object
   * @returns {Array<{role: string, content: string}>}
   */
  function _extractMessages(conv) {
    const mapping = conv.mapping;
    if (!mapping || typeof mapping !== 'object') return [];

    // Find root node (no parent)
    let rootId = null;
    for (const [id, node] of Object.entries(mapping)) {
      if (!node.parent) { rootId = id; break; }
    }
    if (!rootId) return [];

    // Walk the tree depth-first following children[0] (main branch)
    const messages = [];
    let currentId = rootId;
    let safety = 0;

    while (currentId && safety++ < 2000) {
      const node = mapping[currentId];
      if (!node) break;

      if (node.message) {
        const msg = node.message;
        const role = msg.author && msg.author.role;
        let content = '';

        // ChatGPT stores content in parts array or as string
        if (msg.content) {
          if (Array.isArray(msg.content.parts)) {
            content = msg.content.parts
              .filter(p => typeof p === 'string')
              .join('\n');
          } else if (typeof msg.content === 'string') {
            content = msg.content;
          } else if (typeof msg.content.text === 'string') {
            content = msg.content.text;
          }
        }

        // Only keep user and assistant messages with actual content
        if ((role === 'user' || role === 'assistant') && content.trim()) {
          messages.push({ role, content: content.trim() });
          if (messages.length >= MAX_MESSAGES_PER) break;
        }
      }

      // Follow first child (main conversation branch)
      const children = node.children;
      currentId = Array.isArray(children) && children.length > 0
        ? children[0] : null;
    }

    return messages;
  }

  /**
   * Open a file picker for ChatGPT's conversations.json and import all.
   */
  function openFilePicker() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.addEventListener('change', () => {
      const file = input.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = () => {
        try {
          const result = importFromJSON(reader.result);
          const msg = result.imported > 0
            ? `Imported ${result.imported} ChatGPT conversation${result.imported !== 1 ? 's' : ''}${result.skipped > 0 ? ` (${result.skipped} skipped)` : ''}.`
            : 'No conversations could be imported. Make sure this is a ChatGPT export file.';
          alert(msg);
          if (result.imported > 0 && typeof HistoryPanel !== 'undefined') {
            HistoryPanel.refresh();
          }
        } catch (e) {
          alert('Import failed: ' + e.message);
        }
      };
      reader.readAsText(file);
    });
    input.click();
  }

  return { importFromJSON, openFilePicker, _extractMessages };
})();

/* ---------- Prompt Chain Runner (module 57) ---------- */
/**
 * Multi-step prompt chains - define a sequence of prompts that execute
 * one after another, with each step able to reference the previous
 * step's response via {{prev}}.  Great for multi-stage code generation
 * workflows like "design data model" → "add API endpoints" → "write tests".
 *
 * Features:
 *   - Create, edit, duplicate, delete, and run prompt chains
 *   - {{prev}} placeholder substituted with the previous step's response
 *   - {{step.N}} placeholder for a specific earlier step's response (1-based)
 *   - Progress indicator during execution with stop button
 *   - Chain history with timestamps and step outputs
 *   - Import/export chains as JSON
 *   - /chains and /run-chain slash commands
 *
 * Storage key: ac-prompt-chains
 *
 * @namespace PromptChainRunner
 */
const PromptChainRunner = (() => {
  const STORAGE_KEY = 'ac-prompt-chains';
  const HISTORY_KEY = 'ac-chain-runs';
  const MAX_HISTORY = 20;

  let _panelEl = null;
  let _overlayEl = null;
  let _isOpen = false;
  let _isRunning = false;
  let _shouldStop = false;
  let _chains = [];
  let _runHistory = [];

  // ── Persistence ──

  function _load() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      _chains = _safeParse(raw, []);
    } catch (_) { _chains = []; }
    try {
      const raw = SafeStorage.get(HISTORY_KEY);
      _runHistory = _safeParse(raw, []);
    } catch (_) { _runHistory = []; }
  }

  function _saveChains() {
    SafeStorage.setJSON(STORAGE_KEY, _chains);
  }

  function _saveHistory() {
    while (_runHistory.length > MAX_HISTORY) _runHistory.pop();
    SafeStorage.setJSON(HISTORY_KEY, _runHistory);
  }

  // ── Chain CRUD ──

  function _newId() {
    return 'chain_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 6);
  }

  function createChain(name, steps) {
    const chain = { id: _newId(), name: name || 'Untitled Chain', steps: steps || [''], createdAt: Date.now() };
    _chains.unshift(chain);
    _saveChains();
    return chain;
  }

  function updateChain(id, updates) {
    const chain = _chains.find(c => c.id === id);
    if (!chain) return null;
    if (updates.name !== undefined) chain.name = updates.name;
    if (updates.steps !== undefined) chain.steps = updates.steps;
    chain.updatedAt = Date.now();
    _saveChains();
    return chain;
  }

  function deleteChain(id) {
    _chains = _chains.filter(c => c.id !== id);
    _saveChains();
  }

  function duplicateChain(id) {
    const src = _chains.find(c => c.id === id);
    if (!src) return null;
    return createChain(src.name + ' (copy)', [...src.steps]);
  }

  function getChains() { return _chains.slice(); }

  // ── Chain Execution ──

  function _substitute(template, stepOutputs) {
    let result = template;
    // {{prev}} → last step output
    if (stepOutputs.length > 0) {
      result = result.replace(/\{\{prev\}\}/gi, stepOutputs[stepOutputs.length - 1]);
    }
    // {{step.N}} → specific step output (1-based)
    result = result.replace(/\{\{step\.(\d+)\}\}/gi, (match, n) => {
      const idx = parseInt(n, 10) - 1;
      return idx >= 0 && idx < stepOutputs.length ? stepOutputs[idx] : match;
    });
    return result;
  }

  async function runChain(chainId) {
    if (_isRunning) {
      alert('A chain is already running. Stop it first.');
      return null;
    }

    const chain = _chains.find(c => c.id === chainId);
    if (!chain || chain.steps.length === 0) {
      alert('Chain is empty or not found.');
      return null;
    }

    // Check API key
    if (typeof ApiKeyManager !== 'undefined' && !ApiKeyManager.getOpenAIKey()) {
      alert('Set your OpenAI API key first.');
      return null;
    }

    _isRunning = true;
    _shouldStop = false;
    const stepOutputs = [];
    const runRecord = {
      chainId: chain.id,
      chainName: chain.name,
      startedAt: Date.now(),
      steps: [],
      completed: false
    };

    _renderProgress(chain, 0, chain.steps.length);

    for (let i = 0; i < chain.steps.length; i++) {
      if (_shouldStop) {
        runRecord.stoppedAt = Date.now();
        break;
      }

      const promptText = _substitute(chain.steps[i], stepOutputs);
      _renderProgress(chain, i + 1, chain.steps.length, promptText);

      // Set input and send
      UIController.setChatInput(promptText);

      try {
        await ChatController.send();
      } catch (err) {
        runRecord.steps.push({ step: i + 1, prompt: promptText, error: err.message });
        break;
      }

      // Get the response (last assistant message)
      const history = ConversationManager.getHistory();
      const lastMsg = history.length > 0 ? history[history.length - 1] : null;
      const response = lastMsg && lastMsg.role === 'assistant' ? lastMsg.content : '(no response)';

      stepOutputs.push(response);
      runRecord.steps.push({ step: i + 1, prompt: promptText, response: response.substring(0, 500) });

      // Small delay between steps to avoid rate limiting
      if (i < chain.steps.length - 1 && !_shouldStop) {
        await new Promise(r => setTimeout(r, 1000));
      }
    }

    _isRunning = false;
    _shouldStop = false;
    runRecord.completedAt = Date.now();
    runRecord.completed = runRecord.steps.length === chain.steps.length;

    _runHistory.unshift(runRecord);
    _saveHistory();

    _renderPanel();
    return runRecord;
  }

  function stopChain() {
    if (_isRunning) {
      _shouldStop = true;
      if (typeof ChatController !== 'undefined') ChatController.cancelRequest();
    }
  }

  // ── Import / Export ──

  function exportChains() {
    downloadBlob('prompt-chains-' + new Date().toISOString().slice(0, 10) + '.json', JSON.stringify(_chains, null, 2), 'application/json');
  }

  function importChains() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.addEventListener('change', () => {
      const file = input.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = () => {
        try {
          const imported = _safeParse(reader.result);
          if (!Array.isArray(imported)) throw new Error('Expected array');
          let count = 0;
          for (const c of imported) {
            if (c.name && Array.isArray(c.steps)) {
              createChain(c.name, c.steps);
              count++;
            }
          }
          alert(`Imported ${count} chain${count !== 1 ? 's' : ''}.`);
          _renderPanel();
        } catch (e) {
          alert('Import failed: ' + e.message);
        }
      };
      reader.readAsText(file);
    });
    input.click();
  }

  // ── UI ──

  function _ensurePanel() {
    if (_panelEl) return;

    _overlayEl = document.createElement('div');
    _overlayEl.id = 'chain-overlay';
    _overlayEl.style.cssText = 'display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.4);z-index:9998;';
    _overlayEl.addEventListener('click', close);

    _panelEl = document.createElement('div');
    _panelEl.id = 'chain-panel';
    _panelEl.style.cssText = `
      display:none;position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);
      width:min(90vw,640px);max-height:80vh;overflow-y:auto;
      background:var(--bg,#1e1e2e);color:var(--text,#cdd6f4);
      border:1px solid var(--border,#45475a);border-radius:12px;
      padding:24px;z-index:9999;font-family:inherit;
      box-shadow:0 20px 60px rgba(0,0,0,0.3);
    `;

    document.body.appendChild(_overlayEl);
    document.body.appendChild(_panelEl);
  }

  function toggle() {
    if (_isOpen) close(); else open();
  }

  function open() {
    _ensurePanel();
    _isOpen = true;
    _overlayEl.style.display = 'block';
    _panelEl.style.display = 'block';
    _renderPanel();
  }

  function close() {
    _isOpen = false;
    if (_overlayEl) _overlayEl.style.display = 'none';
    if (_panelEl) _panelEl.style.display = 'none';
  }

  function _renderProgress(chain, current, total, currentPrompt) {
    _ensurePanel();
    if (!_isOpen) open();

    const pct = Math.round((current / total) * 100);
    _panelEl.innerHTML = `
      <div style="text-align:center;">
        <h3 style="margin:0 0 12px 0;">⛓️ Running: ${_esc(chain.name)}</h3>
        <div style="background:var(--border,#45475a);border-radius:8px;height:24px;margin:16px 0;overflow:hidden;">
          <div style="background:#89b4fa;height:100%;width:${pct}%;transition:width 0.3s;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:600;color:#1e1e2e;">
            ${current}/${total}
          </div>
        </div>
        ${currentPrompt ? `<p style="font-size:13px;opacity:0.7;margin:8px 0;max-height:60px;overflow:hidden;text-overflow:ellipsis;">${_esc(currentPrompt).substring(0, 120)}${currentPrompt.length > 120 ? '…' : ''}</p>` : ''}
        <button data-chain-action="stop" style="margin-top:12px;padding:8px 24px;background:#f38ba8;color:#1e1e2e;border:none;border-radius:6px;cursor:pointer;font-weight:600;">
          ⏹ Stop Chain
        </button>
      </div>
    `;
    // Bind stop button
    const stopBtn = _panelEl.querySelector('[data-chain-action="stop"]');
    if (stopBtn) stopBtn.addEventListener('click', stopChain);
  }

  function _renderPanel() {
    _ensurePanel();
    const chainsHtml = _chains.length === 0
      ? '<p style="opacity:0.5;text-align:center;margin:20px 0;">No chains yet. Create one to get started!</p>'
      : _chains.map(c => `
        <div style="background:var(--input-bg,#313244);border:1px solid var(--border,#45475a);border-radius:8px;padding:12px;margin:8px 0;">
          <div style="display:flex;justify-content:space-between;align-items:center;">
            <strong style="font-size:15px;">${_esc(c.name)}</strong>
            <span style="font-size:12px;opacity:0.5;">${c.steps.length} step${c.steps.length !== 1 ? 's' : ''}</span>
          </div>
          <div style="font-size:12px;opacity:0.6;margin:4px 0;">
            ${c.steps.map((s, i) => `<span title="${_esc(s)}">Step ${i+1}: ${_esc(s.substring(0, 40))}${s.length > 40 ? '…' : ''}</span>`).join(' → ')}
          </div>
          <div style="margin-top:8px;display:flex;gap:6px;flex-wrap:wrap;">
            <button data-chain-action="run" data-chain-id="${c.id}" style="padding:4px 12px;background:#a6e3a1;color:#1e1e2e;border:none;border-radius:4px;cursor:pointer;font-size:12px;font-weight:600;" ${_isRunning ? 'disabled' : ''}>▶ Run</button>
            <button data-chain-action="edit" data-chain-id="${c.id}" style="padding:4px 12px;background:#89b4fa;color:#1e1e2e;border:none;border-radius:4px;cursor:pointer;font-size:12px;">✏️ Edit</button>
            <button data-chain-action="duplicate" data-chain-id="${c.id}" style="padding:4px 12px;background:#cba6f7;color:#1e1e2e;border:none;border-radius:4px;cursor:pointer;font-size:12px;">📋 Duplicate</button>
            <button data-chain-action="delete" data-chain-id="${c.id}" style="padding:4px 12px;background:#f38ba8;color:#1e1e2e;border:none;border-radius:4px;cursor:pointer;font-size:12px;">🗑️ Delete</button>
          </div>
        </div>
      `).join('');

    const historyHtml = _runHistory.length === 0
      ? ''
      : `<details style="margin-top:16px;"><summary style="cursor:pointer;font-weight:600;opacity:0.8;">📜 Run History (${_runHistory.length})</summary>
         ${_runHistory.slice(0, 10).map(r => `
           <div style="background:var(--input-bg,#313244);border-radius:6px;padding:8px;margin:4px 0;font-size:12px;">
             <strong>${_esc(r.chainName)}</strong> - ${new Date(r.startedAt).toLocaleString()}
             - ${r.completed ? '✅ completed' : '⏹ stopped'} (${r.steps.length} steps)
           </div>
         `).join('')}
         </details>`;

    _panelEl.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
        <h2 style="margin:0;font-size:20px;">⛓️ Prompt Chains</h2>
        <button data-chain-action="close" style="background:none;border:none;color:var(--text,#cdd6f4);font-size:20px;cursor:pointer;padding:4px 8px;" title="Close">✕</button>
      </div>
      <p style="font-size:13px;opacity:0.6;margin:0 0 12px 0;">
        Create multi-step prompt sequences. Use <code>{{prev}}</code> for the last step's output or <code>{{step.N}}</code> for a specific step.
      </p>
      <div style="display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap;">
        <button data-chain-action="new" style="padding:6px 16px;background:#a6e3a1;color:#1e1e2e;border:none;border-radius:6px;cursor:pointer;font-weight:600;">+ New Chain</button>
        <button data-chain-action="import" style="padding:6px 16px;background:var(--border,#45475a);color:var(--text,#cdd6f4);border:none;border-radius:6px;cursor:pointer;">📥 Import</button>
        <button data-chain-action="export" style="padding:6px 16px;background:var(--border,#45475a);color:var(--text,#cdd6f4);border:none;border-radius:6px;cursor:pointer;" ${_chains.length === 0 ? 'disabled' : ''}>📤 Export</button>
      </div>
      ${chainsHtml}
      ${historyHtml}
    `;

    // Bind panel actions via event delegation
    _panelEl.addEventListener('click', function _panelHandler(e) {
      const btn = e.target.closest('button[data-chain-action]');
      if (!btn) return;
      const action = btn.dataset.chainAction;
      const chainId = btn.dataset.chainId;
      switch (action) {
        case 'close': close(); break;
        case 'new': _newChainUI(); break;
        case 'import': importChains(); break;
        case 'export': exportChains(); break;
        case 'run': if (chainId) runChain(chainId); break;
        case 'edit': if (chainId) _editChain(chainId); break;
        case 'duplicate':
          if (chainId) { duplicateChain(chainId); _renderPanel(); }
          break;
        case 'delete':
          if (chainId && confirm('Delete this chain?')) {
            deleteChain(chainId); _renderPanel();
          }
          break;
      }
    });
  }

  function _newChainUI() {
    _panelEl.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
        <h2 style="margin:0;font-size:20px;">⛓️ New Chain</h2>
        <button data-chain-action="back" style="background:none;border:none;color:var(--text,#cdd6f4);font-size:20px;cursor:pointer;" title="Back">←</button>
      </div>
      <label style="font-size:13px;font-weight:600;">Chain Name</label>
      <input id="chain-name-input" type="text" placeholder="e.g. Build REST API" style="width:100%;padding:8px;margin:4px 0 12px 0;background:var(--input-bg,#313244);color:var(--text,#cdd6f4);border:1px solid var(--border,#45475a);border-radius:6px;box-sizing:border-box;" />
      <label style="font-size:13px;font-weight:600;">Steps</label>
      <div id="chain-steps-container"></div>
      <button data-chain-action="add-step" style="margin:8px 0;padding:4px 12px;background:var(--border,#45475a);color:var(--text,#cdd6f4);border:none;border-radius:4px;cursor:pointer;font-size:12px;">+ Add Step</button>
      <div style="margin-top:16px;display:flex;gap:8px;">
        <button data-chain-action="save-new" style="padding:8px 20px;background:#a6e3a1;color:#1e1e2e;border:none;border-radius:6px;cursor:pointer;font-weight:600;">💾 Save Chain</button>
        <button data-chain-action="cancel" style="padding:8px 20px;background:var(--border,#45475a);color:var(--text,#cdd6f4);border:none;border-radius:6px;cursor:pointer;">Cancel</button>
      </div>
    `;

    // Bind new-chain UI actions
    _panelEl.addEventListener('click', function _newChainHandler(e) {
      const btn = e.target.closest('button[data-chain-action]');
      if (!btn) return;
      const action = btn.dataset.chainAction;
      if (action === 'back' || action === 'cancel') _renderPanel();
      else if (action === 'add-step') _addStepInput();
      else if (action === 'save-new') _saveNewChain();
    });

    _addStepInput(); // Start with one step
  }

  let _stepCounter = 0;

  function _addStepInput(value) {
    _stepCounter++;
    const container = DOMCache.get('chain-steps-container');
    if (!container) return;

    const stepDiv = document.createElement('div');
    stepDiv.style.cssText = 'display:flex;gap:6px;align-items:flex-start;margin:4px 0;';
    stepDiv.innerHTML = `
      <span style="font-size:12px;font-weight:600;padding-top:10px;min-width:20px;opacity:0.6;">${container.children.length + 1}.</span>
      <textarea class="chain-step-input" rows="2" placeholder="Enter prompt for this step… (use {{prev}} for previous output)" style="flex:1;padding:8px;background:var(--input-bg,#313244);color:var(--text,#cdd6f4);border:1px solid var(--border,#45475a);border-radius:6px;resize:vertical;font-family:inherit;font-size:13px;">${_esc(value || '')}</textarea>
      <button data-chain-action="remove-step" style="background:none;border:none;color:#f38ba8;cursor:pointer;padding:8px;font-size:16px;" title="Remove step">✕</button>
    `;
    // Bind remove button
    stepDiv.querySelector('[data-chain-action="remove-step"]').addEventListener('click', function() {
      stepDiv.remove();
      _renumberSteps();
    });
    container.appendChild(stepDiv);
  }

  function _renumberSteps() {
    const container = DOMCache.get('chain-steps-container');
    if (!container) return;
    Array.from(container.children).forEach((div, i) => {
      const num = div.querySelector('span');
      if (num) num.textContent = (i + 1) + '.';
    });
  }

  function _saveNewChain() {
    const nameInput = DOMCache.get('chain-name-input');
    const name = nameInput ? nameInput.value.trim() : '';
    const steps = Array.from(document.querySelectorAll('.chain-step-input'))
      .map(ta => ta.value.trim())
      .filter(s => s.length > 0);

    if (steps.length === 0) {
      alert('Add at least one step.');
      return;
    }

    createChain(name || 'Untitled Chain', steps);
    _renderPanel();
  }

  function _editChain(id) {
    const chain = _chains.find(c => c.id === id);
    if (!chain) return;

    _panelEl.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
        <h2 style="margin:0;font-size:20px;">✏️ Edit: ${_esc(chain.name)}</h2>
        <button data-chain-action="back" style="background:none;border:none;color:var(--text,#cdd6f4);font-size:20px;cursor:pointer;" title="Back">←</button>
      </div>
      <label style="font-size:13px;font-weight:600;">Chain Name</label>
      <input id="chain-name-input" type="text" value="${_esc(chain.name)}" style="width:100%;padding:8px;margin:4px 0 12px 0;background:var(--input-bg,#313244);color:var(--text,#cdd6f4);border:1px solid var(--border,#45475a);border-radius:6px;box-sizing:border-box;" />
      <label style="font-size:13px;font-weight:600;">Steps</label>
      <div id="chain-steps-container"></div>
      <button data-chain-action="add-step" style="margin:8px 0;padding:4px 12px;background:var(--border,#45475a);color:var(--text,#cdd6f4);border:none;border-radius:4px;cursor:pointer;font-size:12px;">+ Add Step</button>
      <div style="margin-top:16px;display:flex;gap:8px;">
        <button data-chain-action="save-edit" data-chain-id="${chain.id}" style="padding:8px 20px;background:#a6e3a1;color:#1e1e2e;border:none;border-radius:6px;cursor:pointer;font-weight:600;">💾 Save</button>
        <button data-chain-action="cancel" style="padding:8px 20px;background:var(--border,#45475a);color:var(--text,#cdd6f4);border:none;border-radius:6px;cursor:pointer;">Cancel</button>
      </div>
    `;

    // Bind edit UI actions
    _panelEl.addEventListener('click', function _editHandler(e) {
      const btn = e.target.closest('button[data-chain-action]');
      if (!btn) return;
      const action = btn.dataset.chainAction;
      if (action === 'back' || action === 'cancel') _renderPanel();
      else if (action === 'add-step') _addStepInput();
      else if (action === 'save-edit') _saveEditedChain(btn.dataset.chainId);
    });

    // Populate existing steps
    chain.steps.forEach(s => _addStepInput(s));
  }

  function _saveEditedChain(id) {
    const nameInput = DOMCache.get('chain-name-input');
    const name = nameInput ? nameInput.value.trim() : '';
    const steps = Array.from(document.querySelectorAll('.chain-step-input'))
      .map(ta => ta.value.trim())
      .filter(s => s.length > 0);

    if (steps.length === 0) {
      alert('Add at least one step.');
      return;
    }

    updateChain(id, { name: name || 'Untitled Chain', steps });
    _renderPanel();
  }

  // ── Presets ──

  function _loadPresets() {
    if (_chains.length > 0) return; // Don't overwrite existing chains

    const presets = [
      {
        name: '🏗️ Build REST API',
        steps: [
          'Create a JavaScript data model for a simple todo list with id, title, completed, and createdAt fields. Include validation functions.',
          'Using the data model from the previous response:\n\n{{prev}}\n\nCreate Express.js REST API routes for CRUD operations (GET all, GET by id, POST, PUT, DELETE). Use in-memory storage.',
          'Using the API code from the previous response:\n\n{{prev}}\n\nWrite comprehensive unit tests using Jest. Cover all endpoints, edge cases, and error handling.'
        ]
      },
      {
        name: '🔍 Code Review Pipeline',
        steps: [
          'Analyze this code for potential bugs, security issues, and performance problems. List each issue with severity (critical/warning/info).',
          'For each issue found in the previous analysis:\n\n{{prev}}\n\nProvide a concrete fix with before/after code snippets.',
          'Based on the issues and fixes from steps 1-2:\n\n{{step.1}}\n\n{{step.2}}\n\nGenerate a code review summary report with a quality score (0-100) and prioritized action items.'
        ]
      },
      {
        name: '📊 Data Pipeline',
        steps: [
          'Generate a sample JSON dataset of 20 user records with fields: id, name, email, age, country, signupDate, lastLogin, purchases (array of {item, amount, date}).',
          'Using this dataset:\n\n{{prev}}\n\nWrite JavaScript to clean the data (validate emails, normalize dates, handle missing fields) and compute aggregate statistics (avg age, purchases per country, monthly signups).',
          'Using the cleaned data and statistics:\n\n{{prev}}\n\nCreate an HTML page with Chart.js that visualizes: signups over time (line), purchases by country (bar), and age distribution (histogram).'
        ]
      }
    ];

    presets.forEach(p => createChain(p.name, p.steps));
  }

  // ── Helpers ──

  const _esc = _escapeHtml;

  // ── Init ──

  function init() {
    _load();
    _loadPresets();

    // Register slash commands
    if (typeof SlashCommands !== 'undefined' && SlashCommands.register) {
      SlashCommands.register({
        name: 'chains',
        description: 'Open prompt chain builder - multi-step workflows',
        icon: '⛓️',
        action: () => toggle()
      });
      SlashCommands.register({
        name: 'run-chain',
        description: 'Run a prompt chain by name',
        icon: '▶',
        action: () => {
          if (_chains.length === 0) {
            alert('No chains yet. Use /chains to create one.');
            return;
          }
          const name = prompt('Enter chain name to run:');
          if (!name) return;
          const chain = _chains.find(c => c.name.toLowerCase().includes(name.toLowerCase()));
          if (!chain) {
            alert('Chain not found: ' + name);
            return;
          }
          runChain(chain.id);
        }
      });
    }
  }

  return {
    init,
    toggle,
    open,
    close,
    createChain,
    updateChain,
    deleteChain,
    duplicateChain,
    getChains,
    runChain,
    stopChain,
    exportChains,
    importChains,
    // Exposed for inline onclick handlers
    _renderPanel: _renderPanel,
    _newChainUI: _newChainUI,
    _addStepInput: _addStepInput,
    _editChain: _editChain,
    _saveNewChain: _saveNewChain,
    _saveEditedChain: _saveEditedChain,
    _renumberSteps: _renumberSteps
  };
})();


/* ---------- Conversation Health Check ---------- */
/**
 * ConversationHealthCheck - heuristic diagnostic analysis of the current
 * conversation, providing actionable feedback on prompt quality, balance,
 * context usage, repetition, and conversation patterns.
 *
 * Opens as a modal (Ctrl+Shift+H or /health slash command).
 *
 * Checks performed:
 *  1. Prompt clarity - flags very short or very long user messages
 *  2. Conversation balance - user vs assistant message ratio
 *  3. Context window usage - estimated token count vs model limit
 *  4. Repetition detection - duplicate/near-duplicate user messages
 *  5. Code block ratio - flags code-heavy conversations
 *  6. Question density - checks if user is asking enough questions
 *  7. System prompt - checks if a persona is set
 *  8. Conversation length - flags very long conversations
 *  9. Idle time warning - if conversation was abandoned mid-thread
 * 10. Response length variance - flags wildly inconsistent responses
 *
 * @namespace ConversationHealthCheck
 */
const ConversationHealthCheck = (() => {
  let isOpen = false;

  const _esc = _escapeHtml;

  /**
   * Run all health checks and return structured results.
   * @returns {{ score: number, grade: string, checks: Array }}
   */
  function analyze() {
    const allMsgs = ConversationManager.getMessages();
    // Single-pass partitioning instead of 4 separate filter() calls
    const msgs = [];
    const userMsgs = [];
    const assistantMsgs = [];
    const systemMsgs = [];
    for (let i = 0; i < allMsgs.length; i++) {
      const m = allMsgs[i];
      if (m.role === 'system') { systemMsgs.push(m); }
      else {
        msgs.push(m);
        if (m.role === 'user') userMsgs.push(m);
        else if (m.role === 'assistant') assistantMsgs.push(m);
      }
    }

    if (msgs.length === 0) {
      return { score: -1, grade: 'N/A', checks: [] };
    }

    const checks = [];
    let totalPoints = 0;
    let maxPoints = 0;

    // Helper: word count
    const wc = (s) => s.trim() ? s.trim().split(/\s+/).length : 0;

    // ─── 1. Prompt Clarity ───────────────────────────────────
    maxPoints += 15;
    const avgUserWords = userMsgs.length
      ? Math.round(userMsgs.reduce((s, m) => s + wc(m.content), 0) / userMsgs.length)
      : 0;
    const veryShort = userMsgs.filter(m => wc(m.content) < 3);
    const veryLong = userMsgs.filter(m => wc(m.content) > 500);

    if (veryShort.length > userMsgs.length * 0.5 && userMsgs.length >= 3) {
      checks.push({
        id: 'clarity', status: 'warn', points: 5,
        title: 'Prompts are very short',
        detail: `${veryShort.length} of ${userMsgs.length} prompts have fewer than 3 words. Short prompts often produce vague responses - try adding context or specifics.`,
      });
      totalPoints += 5;
    } else if (veryLong.length > userMsgs.length * 0.3 && userMsgs.length >= 2) {
      checks.push({
        id: 'clarity', status: 'warn', points: 8,
        title: 'Some prompts are very long',
        detail: `${veryLong.length} prompts exceed 500 words. Consider breaking long prompts into smaller, focused questions for more targeted responses.`,
      });
      totalPoints += 8;
    } else {
      checks.push({
        id: 'clarity', status: 'pass', points: 15,
        title: 'Prompt length is good',
        detail: `Average prompt is ${avgUserWords} words - clear and specific.`,
      });
      totalPoints += 15;
    }

    // ─── 2. Conversation Balance ─────────────────────────────
    maxPoints += 10;
    const ratio = userMsgs.length && assistantMsgs.length
      ? (userMsgs.length / assistantMsgs.length).toFixed(2)
      : 0;
    if (userMsgs.length > 0 && assistantMsgs.length === 0) {
      checks.push({
        id: 'balance', status: 'fail', points: 0,
        title: 'No responses yet',
        detail: 'You have sent messages but received no responses. Check your API key and model settings.',
      });
    } else if (ratio > 2.0) {
      checks.push({
        id: 'balance', status: 'warn', points: 5,
        title: 'Many unanswered prompts',
        detail: `User:assistant ratio is ${ratio}:1. Some messages may not have received responses.`,
      });
      totalPoints += 5;
    } else {
      checks.push({
        id: 'balance', status: 'pass', points: 10,
        title: 'Good conversation balance',
        detail: `${userMsgs.length} user messages, ${assistantMsgs.length} responses (ratio: ${ratio}:1).`,
      });
      totalPoints += 10;
    }

    // ─── 3. Context Window Usage ─────────────────────────────
    maxPoints += 20;
    const totalChars = allMsgs.reduce((s, m) => s + m.content.length, 0);
    const estTokens = Math.ceil(totalChars / 4);
    const modelLimit = 128000; // GPT-4o context window
    const usage = estTokens / modelLimit;

    if (usage > 0.85) {
      checks.push({
        id: 'context', status: 'fail', points: 0,
        title: 'Context window nearly full',
        detail: `Estimated ${estTokens.toLocaleString()} tokens (${Math.round(usage * 100)}% of ${(modelLimit / 1000)}K limit). The model may start forgetting earlier messages. Consider starting a new session or clearing history.`,
      });
    } else if (usage > 0.6) {
      checks.push({
        id: 'context', status: 'warn', points: 10,
        title: 'Context window filling up',
        detail: `Estimated ${estTokens.toLocaleString()} tokens (${Math.round(usage * 100)}%). You have room, but long conversations may lose early context.`,
      });
      totalPoints += 10;
    } else {
      checks.push({
        id: 'context', status: 'pass', points: 20,
        title: 'Context window healthy',
        detail: `Estimated ${estTokens.toLocaleString()} tokens (${Math.round(usage * 100)}% of ${(modelLimit / 1000)}K limit). Plenty of room.`,
      });
      totalPoints += 20;
    }

    // ─── 4. Repetition Detection ─────────────────────────────
    maxPoints += 15;
    const userTexts = userMsgs.map(m => m.content.toLowerCase().trim());
    const seen = new Set();
    let dupes = 0;
    for (const t of userTexts) {
      if (t.length > 5 && seen.has(t)) dupes++;
      seen.add(t);
    }
    // Near-duplicate: same first 50 chars
    let nearDupes = 0;
    const prefixes = new Set();
    for (const t of userTexts) {
      const prefix = t.substring(0, 50);
      if (prefix.length > 10 && prefixes.has(prefix)) nearDupes++;
      prefixes.add(prefix);
    }

    if (dupes > 0) {
      checks.push({
        id: 'repetition', status: 'fail', points: 0,
        title: `${dupes} duplicate prompt${dupes > 1 ? 's' : ''} detected`,
        detail: 'Exact same messages sent multiple times. This wastes tokens and suggests the AI response wasn\'t satisfactory - try rephrasing instead of repeating.',
      });
    } else if (nearDupes > 0) {
      checks.push({
        id: 'repetition', status: 'warn', points: 8,
        title: `${nearDupes} near-duplicate prompt${nearDupes > 1 ? 's' : ''}`,
        detail: 'Similar messages detected. If the AI isn\'t understanding, try a completely different approach or add more context.',
      });
      totalPoints += 8;
    } else {
      checks.push({
        id: 'repetition', status: 'pass', points: 15,
        title: 'No repetition detected',
        detail: 'All prompts are unique - good conversation flow.',
      });
      totalPoints += 15;
    }

    // ─── 5. Code Block Ratio ─────────────────────────────────
    maxPoints += 10;
    const codeBlocks = msgs.reduce((sum, m) => {
      const matches = m.content.match(/```/g);
      return sum + (matches ? Math.floor(matches.length / 2) : 0);
    }, 0);
    const codeRatio = msgs.length ? codeBlocks / msgs.length : 0;

    if (codeRatio > 0.7 && msgs.length >= 4) {
      checks.push({
        id: 'code', status: 'info', points: 7,
        title: 'Code-heavy conversation',
        detail: `${codeBlocks} code blocks in ${msgs.length} messages. Consider using /snippets to save important code for later reference.`,
      });
      totalPoints += 7;
    } else {
      checks.push({
        id: 'code', status: 'pass', points: 10,
        title: 'Code block usage is balanced',
        detail: `${codeBlocks} code block${codeBlocks !== 1 ? 's' : ''} across ${msgs.length} messages.`,
      });
      totalPoints += 10;
    }

    // ─── 6. Question Density ─────────────────────────────────
    maxPoints += 10;
    const questions = userMsgs.filter(m => m.content.includes('?'));
    const qRatio = userMsgs.length ? questions.length / userMsgs.length : 0;

    if (userMsgs.length >= 5 && qRatio < 0.1) {
      checks.push({
        id: 'questions', status: 'info', points: 5,
        title: 'Low question density',
        detail: `Only ${questions.length} of ${userMsgs.length} prompts contain questions. Asking specific questions often yields better responses.`,
      });
      totalPoints += 5;
    } else {
      checks.push({
        id: 'questions', status: 'pass', points: 10,
        title: 'Good question engagement',
        detail: `${questions.length} of ${userMsgs.length} prompts ask questions.`,
      });
      totalPoints += 10;
    }

    // ─── 7. System Prompt / Persona ──────────────────────────
    maxPoints += 10;
    if (systemMsgs.length === 0) {
      checks.push({
        id: 'persona', status: 'info', points: 5,
        title: 'No system prompt set',
        detail: 'Using a persona/system prompt helps guide the AI\'s behavior. Try /persona to set one.',
      });
      totalPoints += 5;
    } else {
      const sysLen = wc(systemMsgs[0].content);
      checks.push({
        id: 'persona', status: 'pass', points: 10,
        title: 'System prompt active',
        detail: `Active persona with ${sysLen} words guiding the conversation.`,
      });
      totalPoints += 10;
    }

    // ─── 8. Conversation Length ───────────────────────────────
    maxPoints += 10;
    if (msgs.length > 100) {
      checks.push({
        id: 'length', status: 'warn', points: 3,
        title: 'Very long conversation',
        detail: `${msgs.length} messages. Long conversations can degrade response quality as the model struggles to maintain context. Consider forking or starting fresh.`,
      });
      totalPoints += 3;
    } else if (msgs.length > 50) {
      checks.push({
        id: 'length', status: 'info', points: 7,
        title: 'Moderately long conversation',
        detail: `${msgs.length} messages. Consider bookmarking key messages for quick reference.`,
      });
      totalPoints += 7;
    } else {
      checks.push({
        id: 'length', status: 'pass', points: 10,
        title: 'Conversation length is manageable',
        detail: `${msgs.length} messages - well within comfortable limits.`,
      });
      totalPoints += 10;
    }

    // Calculate overall score
    const score = maxPoints > 0 ? Math.round((totalPoints / maxPoints) * 100) : 0;
    let grade;
    if (score >= 90) grade = 'Excellent';
    else if (score >= 75) grade = 'Good';
    else if (score >= 55) grade = 'Fair';
    else grade = 'Needs Attention';

    return { score, grade, checks, maxPoints, totalPoints };
  }

  /**
   * Render the health check results into the panel.
   */
  function render() {
    const contentEl = DOMCache.get('health-content');
    if (!contentEl) return;

    const result = analyze();

    if (result.score === -1) {
      contentEl.innerHTML = '<div class="health-empty">🩺 No messages to analyze.<br>Start a conversation first!</div>';
      return;
    }

    // Score color
    let color = '#4ade80';
    if (result.score < 55) color = '#f87171';
    else if (result.score < 75) color = '#fbbf24';
    else if (result.score < 90) color = '#60a5fa';

    // SVG ring
    const radius = 36;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (result.score / 100) * circumference;

    let html = `<div class="health-score-ring">
      <svg width="90" height="90" viewBox="0 0 90 90">
        <circle cx="45" cy="45" r="${radius}" fill="none" stroke="#333" stroke-width="6"/>
        <circle cx="45" cy="45" r="${radius}" fill="none" stroke="${color}" stroke-width="6"
          stroke-dasharray="${circumference}" stroke-dashoffset="${offset}"
          stroke-linecap="round" transform="rotate(-90 45 45)"
          style="transition: stroke-dashoffset 0.5s ease"/>
        <text x="45" y="49" text-anchor="middle" fill="${color}" font-size="20" font-weight="700">${result.score}</text>
      </svg>
      <div>
        <div class="health-score-label">Overall Health</div>
        <div class="health-score-value" style="color:${color}">${_esc(result.grade)}</div>
        <div class="health-score-desc">${result.totalPoints}/${result.maxPoints} points across ${result.checks.length} checks</div>
      </div>
    </div>`;

    html += '<div class="health-section-title">Diagnostic Results</div>';
    html += '<div class="health-checks">';

    const statusIcon = { pass: '✅', warn: '⚠️', fail: '❌', info: 'ℹ️' };

    for (const check of result.checks) {
      html += `<div class="health-check-item ${_esc(check.status)}">
        <span class="health-check-icon">${statusIcon[check.status] || '•'}</span>
        <div class="health-check-body">
          <div class="health-check-title">${_esc(check.title)}</div>
          <div class="health-check-detail">${_esc(check.detail)}</div>
        </div>
      </div>`;
    }

    html += '</div>';
    contentEl.innerHTML = html;
  }

  /** Open the health check panel. */
  function open() {
    const overlay = DOMCache.get('health-overlay');
    if (overlay) {
      overlay.style.display = 'flex';
      isOpen = true;
      render();
    }
  }

  /** Close the health check panel. */
  function close() {
    const overlay = DOMCache.get('health-overlay');
    if (overlay) {
      overlay.style.display = 'none';
      isOpen = false;
    }
  }

  /** Toggle the panel. */
  function toggle() {
    if (isOpen) close();
    else open();
  }

  return { open, close, toggle, analyze, render };
})();

/* ── Typing Speed Monitor ── */
const TypingSpeedMonitor = (() => {
  const STORAGE_KEY = 'ac_typing_speed';
  const WORD_CHARS = /[\S]+/g;
  const SAMPLE_WINDOW_MS = 3000; // rolling 3-second window

  let _keystrokes = [];   // timestamps of recent keystrokes
  let _wordTimestamps = []; // { wpm, ts } samples
  let _currentWpm = 0;
  let _peakWpm = 0;
  let _totalWords = 0;
  let _totalChars = 0;
  let _sessionStart = Date.now();
  let _lastInputLength = 0;
  let _updateTimer = null;
  let _isOpen = false;
  let _idleTimeout = null;
  const IDLE_STOP_MS = 5000; // stop polling after 5s of no typing

  function _startUpdateTimer() {
    if (_updateTimer) return;
    _updateTimer = setInterval(_updateWpm, 500);
  }

  function _stopUpdateTimer() {
    if (_updateTimer) { clearInterval(_updateTimer); _updateTimer = null; }
  }

  /** Reset the idle countdown — called on every keystroke. */
  function _resetIdleStop() {
    _startUpdateTimer();
    clearTimeout(_idleTimeout);
    _idleTimeout = setTimeout(() => {
      // Final update to show 0 WPM, then stop polling
      _currentWpm = 0;
      _updateIndicator();
      _stopUpdateTimer();
    }, IDLE_STOP_MS);
  }

  function init() {
    _loadStats();
    _createDashboardHTML();

    const input = DOMCache.get('chat-input');
    if (input) {
      input.addEventListener('keydown', _onKeydown);
      input.addEventListener('input', _onInput);
    }

    const indicator = DOMCache.get('wpm-indicator');
    if (indicator) indicator.addEventListener('click', toggle);

    // WPM update timer starts on-demand when user types (see _resetIdleStop)
    // No always-on interval — saves CPU when user is idle

    // Keyboard shortcut Ctrl+Shift+T
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'T') {
        e.preventDefault();
        toggle();
      }
    });

    // Count words on send
    const sendBtn = DOMCache.get('send-btn');
    if (sendBtn) {
      sendBtn.addEventListener('click', _onSend);
    }
  }

  function _onKeydown(e) {
    if (e.key.length === 1 || e.key === 'Backspace' || e.key === 'Delete') {
      _keystrokes.push(Date.now());
      _totalChars++;
      _resetIdleStop();
    }
  }

  function _onInput() {
    const input = DOMCache.get('chat-input');
    if (!input) return;
    const len = input.value.length;
    _lastInputLength = len;
  }

  function _onSend() {
    const input = DOMCache.get('chat-input');
    if (!input) return;
    const words = (input.value.match(WORD_CHARS) || []).length;
    _totalWords += words;
    _saveStats();
  }

  function _updateWpm() {
    const now = Date.now();
    // Remove keystrokes older than sample window
    _keystrokes = _keystrokes.filter(t => now - t < SAMPLE_WINDOW_MS);

    if (_keystrokes.length < 2) {
      _currentWpm = 0;
      _updateIndicator();
      return;
    }

    // Calculate chars per minute from keystroke rate
    const elapsed = (now - _keystrokes[0]) / 1000; // seconds
    if (elapsed <= 0) { _currentWpm = 0; _updateIndicator(); return; }

    const charsPerSec = _keystrokes.length / elapsed;
    // Average word length ~5 chars
    const wpm = Math.round((charsPerSec * 60) / 5);

    _currentWpm = wpm;
    if (wpm > _peakWpm) {
      _peakWpm = wpm;
      _saveStats();
    }

    // Record sample for sparkline
    _wordTimestamps.push({ wpm, ts: now });
    // Keep last 60 samples (30 seconds of history at 500ms interval)
    if (_wordTimestamps.length > 60) _wordTimestamps.shift();

    _updateIndicator();
    if (_isOpen) _renderDashboard();
  }

  function _updateIndicator() {
    const valEl = DOMCache.get('wpm-value');
    const indicator = DOMCache.get('wpm-indicator');
    if (!valEl || !indicator) return;

    valEl.textContent = _currentWpm;

    indicator.classList.remove('wpm-active', 'wpm-fast', 'wpm-blazing');
    if (_currentWpm >= 80) indicator.classList.add('wpm-blazing');
    else if (_currentWpm >= 50) indicator.classList.add('wpm-fast');
    else if (_currentWpm > 0) indicator.classList.add('wpm-active');
  }

  function _createDashboardHTML() {
    if (DOMCache.get('wpm-dashboard-overlay')) return;
    const overlay = document.createElement('div');
    overlay.id = 'wpm-dashboard-overlay';
    overlay.className = 'wpm-dashboard-overlay';
    overlay.addEventListener('click', (e) => { if (e.target === overlay) close(); });
    overlay.innerHTML = `
      <div class="wpm-dashboard">
        <button class="wpm-close" id="wpm-close">&times;</button>
        <h2>⌨️ Typing Speed</h2>
        <div class="wpm-stat-grid">
          <div class="wpm-stat-card">
            <div class="wpm-stat-value" id="wpm-live">0</div>
            <div class="wpm-stat-label">Current WPM</div>
          </div>
          <div class="wpm-stat-card">
            <div class="wpm-stat-value" id="wpm-peak">0</div>
            <div class="wpm-stat-label">Peak WPM</div>
          </div>
          <div class="wpm-stat-card">
            <div class="wpm-stat-value" id="wpm-words">0</div>
            <div class="wpm-stat-label">Words Sent</div>
          </div>
          <div class="wpm-stat-card">
            <div class="wpm-stat-value" id="wpm-chars">0</div>
            <div class="wpm-stat-label">Keystrokes</div>
          </div>
        </div>
        <div class="wpm-history-label">Speed History (last 30s)</div>
        <div class="wpm-sparkline"><canvas id="wpm-canvas"></canvas></div>
        <button class="wpm-reset-btn" id="wpm-reset">Reset Stats</button>
      </div>`;
    document.body.appendChild(overlay);
    DOMCache.get('wpm-close').addEventListener('click', close);
    DOMCache.get('wpm-reset').addEventListener('click', reset);
  }

  function _renderDashboard() {
    const liveEl = DOMCache.get('wpm-live');
    const peakEl = DOMCache.get('wpm-peak');
    const wordsEl = DOMCache.get('wpm-words');
    const charsEl = DOMCache.get('wpm-chars');
    if (liveEl) liveEl.textContent = _currentWpm;
    if (peakEl) peakEl.textContent = _peakWpm;
    if (wordsEl) wordsEl.textContent = _totalWords;
    if (charsEl) charsEl.textContent = _totalChars;
    _drawSparkline();
  }

  function _drawSparkline() {
    const canvas = DOMCache.get('wpm-canvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const rect = canvas.parentElement.getBoundingClientRect();
    canvas.width = rect.width - 16;
    canvas.height = rect.height - 16;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (_wordTimestamps.length < 2) return;

    // Find max WPM in a single pass — avoids allocating an intermediate
    // array via .map() + spreading into Math.max (O(n) alloc + stack).
    let maxWpm = 10;
    for (let i = 0; i < _wordTimestamps.length; i++) {
      if (_wordTimestamps[i].wpm > maxWpm) maxWpm = _wordTimestamps[i].wpm;
    }
    const w = canvas.width;
    const h = canvas.height;
    const step = w / (_wordTimestamps.length - 1);

    // Pre-compute Y coordinates once — previously the identical
    // h - (wpm / maxWpm) * h was calculated in two separate forEach
    // passes (one for fill area, one for stroke line).
    const ys = new Float32Array(_wordTimestamps.length);
    for (let i = 0; i < _wordTimestamps.length; i++) {
      ys[i] = h - (_wordTimestamps[i].wpm / maxWpm) * h;
    }

    // Gradient fill
    const grad = ctx.createLinearGradient(0, 0, 0, h);
    grad.addColorStop(0, 'rgba(79,195,247,0.3)');
    grad.addColorStop(1, 'rgba(79,195,247,0)');

    ctx.beginPath();
    ctx.moveTo(0, h);
    for (let i = 0; i < ys.length; i++) {
      ctx.lineTo(i * step, ys[i]);
    }
    ctx.lineTo(w, h);
    ctx.closePath();
    ctx.fillStyle = grad;
    ctx.fill();

    // Line — reuses pre-computed ys[]
    ctx.beginPath();
    ctx.moveTo(0, ys[0]);
    for (let i = 1; i < ys.length; i++) {
      ctx.lineTo(i * step, ys[i]);
    }
    ctx.strokeStyle = '#4fc3f7';
    ctx.lineWidth = 2;
    ctx.stroke();
  }

  function _loadStats() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      if (raw) {
        const data = _safeParse(raw);
        _peakWpm = data.peakWpm || 0;
        _totalWords = data.totalWords || 0;
        _totalChars = data.totalChars || 0;
      }
    } catch (_) {}
  }

  function _saveStats() {
    try {
      SafeStorage.setJSON(STORAGE_KEY, {
        peakWpm: _peakWpm,
        totalWords: _totalWords,
        totalChars: _totalChars,
      });
    } catch (_) {}
  }

  function open() {
    const overlay = DOMCache.get('wpm-dashboard-overlay');
    if (overlay) { overlay.style.display = 'flex'; _isOpen = true; _renderDashboard(); }
  }

  function close() {
    const overlay = DOMCache.get('wpm-dashboard-overlay');
    if (overlay) { overlay.style.display = 'none'; _isOpen = false; }
  }

  function toggle() { if (_isOpen) close(); else open(); }

  function reset() {
    _peakWpm = 0; _totalWords = 0; _totalChars = 0;
    _wordTimestamps = []; _keystrokes = [];
    _currentWpm = 0;
    _saveStats(); _updateIndicator(); _renderDashboard();
  }

  function getCurrentWpm() { return _currentWpm; }
  function getPeakWpm() { return _peakWpm; }
  function getTotalWords() { return _totalWords; }
  function getTotalChars() { return _totalChars; }

  document.addEventListener('DOMContentLoaded', init);

  return { open, close, toggle, reset, getCurrentWpm, getPeakWpm, getTotalWords, getTotalChars };
})();

/* ============================================================
 * FocusTimer - Pomodoro-style focus timer with work/break cycles,
 * session tracking, and persistent statistics.
 *
 * Toggle via Alt+P, the 🍅 toolbar button, or /pomodoro slash command.
 * Supports configurable work/break durations and long breaks.
 *
 * @namespace FocusTimer
 * ============================================================ */
const FocusTimer = (() => {
  const STORAGE_KEY = 'ac_focus_timer';
  const DEFAULTS = { work: 25, short: 5, long: 15, longAfter: 4 };

  let _state = 'idle'; // idle | work | short-break | long-break
  let _remaining = 0;  // seconds
  let _interval = null;
  let _sessionsCompleted = 0;
  let _totalFocusSeconds = 0;
  let _todaySessions = 0;
  let _todayDate = '';
  let _isOpen = false;
  let _settings = { ...DEFAULTS };
  let _history = []; // { date, sessions, focusMinutes }

  function _load() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      if (raw) {
        const d = _safeParse(raw);
        _sessionsCompleted = d.sessionsCompleted || 0;
        _totalFocusSeconds = d.totalFocusSeconds || 0;
        _todaySessions = d.todaySessions || 0;
        _todayDate = d.todayDate || '';
        if (d.settings) Object.assign(_settings, d.settings);
        _history = d.history || [];
      }
    } catch (_) {}
    const today = new Date().toISOString().slice(0, 10);
    if (_todayDate !== today) {
      if (_todayDate && _todaySessions > 0) {
        _history.push({ date: _todayDate, sessions: _todaySessions, focusMinutes: Math.round(_todaySessions * _settings.work) });
        if (_history.length > 30) _history = _history.slice(-30);
      }
      _todaySessions = 0;
      _todayDate = today;
    }
  }

  function _save() {
    SafeStorage.setJSON(STORAGE_KEY, {
      sessionsCompleted: _sessionsCompleted,
      totalFocusSeconds: _totalFocusSeconds,
      todaySessions: _todaySessions,
      todayDate: _todayDate,
      settings: _settings,
      history: _history
    });
  }

  function _formatTime(s) {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${m.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  }

  function _stateLabel() {
    if (_state === 'work') return '🍅 Focus';
    if (_state === 'short-break') return '☕ Short Break';
    if (_state === 'long-break') return '🌴 Long Break';
    return '⏸️ Idle';
  }

  function _createUI() {
    if (DOMCache.get('focus-timer-overlay')) return;

    const overlay = document.createElement('div');
    overlay.id = 'focus-timer-overlay';
    overlay.style.cssText = 'display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:10100;justify-content:center;align-items:center;';
    overlay.innerHTML = `
      <div id="focus-timer-panel" style="background:var(--bg-color,#1e1e1e);color:var(--text-color,#d4d4d4);border-radius:16px;padding:28px 32px;max-width:420px;width:90%;box-shadow:0 8px 32px rgba(0,0,0,0.4);font-family:system-ui,sans-serif;position:relative;">
        <button id="focus-timer-close" style="position:absolute;top:10px;right:14px;background:none;border:none;color:var(--text-color,#d4d4d4);font-size:20px;cursor:pointer;" title="Close">✕</button>
        <h2 style="margin:0 0 16px;font-size:18px;">🍅 Focus Timer</h2>
        <div id="ft-display" style="text-align:center;margin:16px 0;">
          <div id="ft-state-label" style="font-size:14px;opacity:0.7;margin-bottom:8px;">⏸️ Idle</div>
          <div id="ft-time" style="font-size:56px;font-weight:700;font-variant-numeric:tabular-nums;letter-spacing:2px;">25:00</div>
        </div>
        <div id="ft-controls" style="display:flex;gap:10px;justify-content:center;margin:16px 0;">
          <button id="ft-start" style="padding:8px 20px;border:none;border-radius:8px;background:#e74c3c;color:#fff;font-size:14px;cursor:pointer;font-weight:600;">▶ Start</button>
          <button id="ft-pause" style="padding:8px 20px;border:none;border-radius:8px;background:#f39c12;color:#fff;font-size:14px;cursor:pointer;font-weight:600;display:none;">⏸ Pause</button>
          <button id="ft-skip" style="padding:8px 20px;border:none;border-radius:8px;background:#3498db;color:#fff;font-size:14px;cursor:pointer;font-weight:600;display:none;">⏭ Skip</button>
          <button id="ft-reset" style="padding:8px 20px;border:none;border-radius:8px;background:#555;color:#fff;font-size:14px;cursor:pointer;font-weight:600;">↺ Reset</button>
        </div>
        <div id="ft-progress" style="display:flex;gap:6px;justify-content:center;margin:12px 0;">
        </div>
        <div style="border-top:1px solid rgba(128,128,128,0.3);margin:16px 0;padding-top:12px;">
          <div id="ft-stats" style="display:flex;justify-content:space-around;font-size:13px;opacity:0.8;">
            <div><strong id="ft-today-count">0</strong><br>Today</div>
            <div><strong id="ft-total-count">0</strong><br>Total</div>
            <div><strong id="ft-total-hours">0h</strong><br>Focus Time</div>
            <div><strong id="ft-streak">0</strong><br>Streak</div>
          </div>
        </div>
        <details style="margin-top:12px;font-size:13px;opacity:0.8;">
          <summary style="cursor:pointer;font-weight:600;">⚙️ Settings</summary>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:10px;">
            <label>Work (min): <input id="ft-set-work" type="number" min="1" max="120" style="width:50px;background:rgba(128,128,128,0.2);border:1px solid rgba(128,128,128,0.3);border-radius:4px;color:inherit;padding:2px 6px;"></label>
            <label>Short break: <input id="ft-set-short" type="number" min="1" max="30" style="width:50px;background:rgba(128,128,128,0.2);border:1px solid rgba(128,128,128,0.3);border-radius:4px;color:inherit;padding:2px 6px;"></label>
            <label>Long break: <input id="ft-set-long" type="number" min="1" max="60" style="width:50px;background:rgba(128,128,128,0.2);border:1px solid rgba(128,128,128,0.3);border-radius:4px;color:inherit;padding:2px 6px;"></label>
            <label>Long after: <input id="ft-set-after" type="number" min="2" max="10" style="width:50px;background:rgba(128,128,128,0.2);border:1px solid rgba(128,128,128,0.3);border-radius:4px;color:inherit;padding:2px 6px;"></label>
          </div>
          <button id="ft-save-settings" style="margin-top:8px;padding:4px 14px;border:none;border-radius:6px;background:#27ae60;color:#fff;font-size:12px;cursor:pointer;">Save Settings</button>
        </details>
        <details style="margin-top:8px;font-size:13px;opacity:0.8;">
          <summary style="cursor:pointer;font-weight:600;">📊 History (last 7 days)</summary>
          <div id="ft-history" style="margin-top:8px;"></div>
        </details>
      </div>
    `;
    document.body.appendChild(overlay);

    overlay.addEventListener('click', e => { if (e.target === overlay) close(); });
    DOMCache.get('focus-timer-close').addEventListener('click', close);
    DOMCache.get('ft-start').addEventListener('click', start);
    DOMCache.get('ft-pause').addEventListener('click', pause);
    DOMCache.get('ft-skip').addEventListener('click', skip);
    DOMCache.get('ft-reset').addEventListener('click', reset);
    DOMCache.get('ft-save-settings').addEventListener('click', _saveSettings);

    // Keyboard shortcut: Alt+P
    document.addEventListener('keydown', e => {
      if (e.altKey && (e.key === 'p' || e.key === 'P') && !e.ctrlKey && !e.shiftKey && !e.metaKey) {
        e.preventDefault();
        toggle();
      }
    });

    _createIndicator();
  }

  function _createIndicator() {
    if (DOMCache.get('ft-indicator')) return;
    const ind = document.createElement('div');
    ind.id = 'ft-indicator';
    ind.style.cssText = 'display:none;position:fixed;bottom:12px;left:12px;background:var(--bg-color,#1e1e1e);color:var(--text-color,#d4d4d4);border:1px solid rgba(128,128,128,0.3);border-radius:10px;padding:6px 14px;font-size:13px;font-family:system-ui,sans-serif;cursor:pointer;z-index:10050;box-shadow:0 2px 8px rgba(0,0,0,0.3);font-variant-numeric:tabular-nums;';
    ind.title = 'Focus Timer (Alt+P)';
    ind.addEventListener('click', toggle);
    document.body.appendChild(ind);
  }

  function _updateUI() {
    const timeEl = DOMCache.get('ft-time');
    const labelEl = DOMCache.get('ft-state-label');
    const startBtn = DOMCache.get('ft-start');
    const pauseBtn = DOMCache.get('ft-pause');
    const skipBtn = DOMCache.get('ft-skip');
    const todayEl = DOMCache.get('ft-today-count');
    const totalEl = DOMCache.get('ft-total-count');
    const hoursEl = DOMCache.get('ft-total-hours');
    const streakEl = DOMCache.get('ft-streak');

    if (timeEl) timeEl.textContent = _formatTime(_state === 'idle' ? _settings.work * 60 : _remaining);
    if (labelEl) labelEl.textContent = _stateLabel();

    if (startBtn && pauseBtn && skipBtn) {
      if (_state === 'idle') {
        startBtn.style.display = ''; pauseBtn.style.display = 'none'; skipBtn.style.display = 'none';
      } else if (_interval) {
        startBtn.style.display = 'none'; pauseBtn.style.display = ''; skipBtn.style.display = '';
      } else {
        startBtn.style.display = ''; startBtn.textContent = '▶ Resume'; pauseBtn.style.display = 'none'; skipBtn.style.display = '';
      }
    }

    if (todayEl) todayEl.textContent = _todaySessions;
    if (totalEl) totalEl.textContent = _sessionsCompleted;
    if (hoursEl) {
      const h = _totalFocusSeconds / 3600;
      hoursEl.textContent = h >= 1 ? `${h.toFixed(1)}h` : `${Math.round(_totalFocusSeconds / 60)}m`;
    }
    if (streakEl) streakEl.textContent = _calcStreak();

    _renderProgress();
    _renderHistory();
    _updateIndicator();
    _updateSettingsInputs();
  }

  function _renderProgress() {
    const el = DOMCache.get('ft-progress');
    if (!el) return;
    const total = _settings.longAfter;
    const done = _todaySessions % total;
    el.innerHTML = '';
    for (let i = 0; i < total; i++) {
      const dot = document.createElement('div');
      dot.style.cssText = `width:14px;height:14px;border-radius:50%;border:2px solid ${i < done ? '#e74c3c' : 'rgba(128,128,128,0.4)'};background:${i < done ? '#e74c3c' : 'transparent'};`;
      el.appendChild(dot);
    }
  }

  function _renderHistory() {
    const el = DOMCache.get('ft-history');
    if (!el) return;
    const recent = [..._history].slice(-6);
    const today = { date: _todayDate, sessions: _todaySessions, focusMinutes: Math.round(_todaySessions * _settings.work) };
    const rows = [...recent, today].slice(-7);
    if (rows.length === 0) { el.textContent = 'No history yet.'; return; }
    el.innerHTML = rows.map(r =>
      `<div style="display:flex;justify-content:space-between;padding:2px 0;"><span>${r.date}</span><span>${r.sessions} 🍅 · ${r.focusMinutes}m</span></div>`
    ).join('');
  }

  function _updateIndicator() {
    const ind = DOMCache.get('ft-indicator');
    if (!ind) return;
    if (_state === 'idle') { ind.style.display = 'none'; return; }
    ind.style.display = '';
    const emoji = _state === 'work' ? '🍅' : '☕';
    ind.textContent = `${emoji} ${_formatTime(_remaining)}`;
  }

  function _updateSettingsInputs() {
    const w = DOMCache.get('ft-set-work');
    const s = DOMCache.get('ft-set-short');
    const l = DOMCache.get('ft-set-long');
    const a = DOMCache.get('ft-set-after');
    if (w && !w.matches(':focus')) w.value = _settings.work;
    if (s && !s.matches(':focus')) s.value = _settings.short;
    if (l && !l.matches(':focus')) l.value = _settings.long;
    if (a && !a.matches(':focus')) a.value = _settings.longAfter;
  }

  function _saveSettings() {
    const w = parseInt(DOMCache.get('ft-set-work')?.value) || DEFAULTS.work;
    const s = parseInt(DOMCache.get('ft-set-short')?.value) || DEFAULTS.short;
    const l = parseInt(DOMCache.get('ft-set-long')?.value) || DEFAULTS.long;
    const a = parseInt(DOMCache.get('ft-set-after')?.value) || DEFAULTS.longAfter;
    _settings = { work: Math.max(1, Math.min(120, w)), short: Math.max(1, Math.min(30, s)), long: Math.max(1, Math.min(60, l)), longAfter: Math.max(2, Math.min(10, a)) };
    _save();
    if (_state === 'idle') _updateUI();
  }

  function _calcStreak() {
    let streak = _todaySessions > 0 ? 1 : 0;
    const today = new Date();
    for (let i = _history.length - 1; i >= 0; i--) {
      const d = new Date(_history[i].date);
      const expected = new Date(today);
      expected.setDate(expected.getDate() - (streak));
      if (d.toISOString().slice(0, 10) === expected.toISOString().slice(0, 10) && _history[i].sessions > 0) {
        streak++;
      } else { break; }
    }
    return streak;
  }

  function _tick() {
    _remaining--;
    if (_state === 'work') _totalFocusSeconds++;
    if (_remaining <= 0) {
      clearInterval(_interval);
      _interval = null;
      _onComplete();
    }
    _updateUI();
    _save();
  }

  function _onComplete() {
    if (_state === 'work') {
      _sessionsCompleted++;
      _todaySessions++;
      _save();
      _notify('Focus session complete! Time for a break. 🎉');
      // Auto-start break
      const isLong = _todaySessions % _settings.longAfter === 0;
      _state = isLong ? 'long-break' : 'short-break';
      _remaining = (isLong ? _settings.long : _settings.short) * 60;
      _startInterval();
    } else {
      _notify('Break is over! Ready to focus? 🍅');
      _state = 'idle';
    }
    _updateUI();
  }

  function _notify(msg) {
    // Try browser notification
    if (typeof Notification !== 'undefined' && Notification.permission === 'granted') {
      new Notification('Focus Timer', { body: msg, icon: '🍅' });
    } else if (typeof Notification !== 'undefined' && Notification.permission !== 'denied') {
      Notification.requestPermission();
    }
    // Also play a subtle sound via AudioContext
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.frequency.value = 800; gain.gain.value = 0.15;
      osc.start(); osc.stop(ctx.currentTime + 0.2);
      setTimeout(() => {
        const o2 = ctx.createOscillator();
        const g2 = ctx.createGain();
        o2.connect(g2); g2.connect(ctx.destination);
        o2.frequency.value = 1000; g2.gain.value = 0.15;
        o2.start(); o2.stop(ctx.currentTime + 0.3);
      }, 250);
    } catch (_) {}
  }

  function _startInterval() {
    if (_interval) clearInterval(_interval);
    _interval = setInterval(_tick, 1000);
  }

  function start() {
    if (_state === 'idle') {
      _state = 'work';
      _remaining = _settings.work * 60;
    }
    _startInterval();
    _updateUI();
  }

  function pause() {
    if (_interval) { clearInterval(_interval); _interval = null; }
    _updateUI();
  }

  function skip() {
    if (_interval) { clearInterval(_interval); _interval = null; }
    if (_state === 'work') {
      // Don't count skipped work sessions
      const isLong = (_todaySessions + 1) % _settings.longAfter === 0;
      _state = isLong ? 'long-break' : 'short-break';
      _remaining = (isLong ? _settings.long : _settings.short) * 60;
      _startInterval();
    } else {
      _state = 'idle';
    }
    _updateUI();
  }

  function reset() {
    if (_interval) { clearInterval(_interval); _interval = null; }
    _state = 'idle';
    _remaining = 0;
    _updateUI();
  }

  function open() {
    const overlay = DOMCache.get('focus-timer-overlay');
    if (overlay) { overlay.style.display = 'flex'; _isOpen = true; _updateUI(); }
  }

  function close() {
    const overlay = DOMCache.get('focus-timer-overlay');
    if (overlay) { overlay.style.display = 'none'; _isOpen = false; }
  }

  function toggle() { if (_isOpen) close(); else open(); }

  function getState() { return _state; }
  function getRemaining() { return _remaining; }
  function getTodaySessions() { return _todaySessions; }
  function getTotalSessions() { return _sessionsCompleted; }
  function getSettings() { return { ..._settings }; }

  function init() {
    _load();
    _createUI();
    _updateUI();
  }

  document.addEventListener('DOMContentLoaded', init);

  return { open, close, toggle, start, pause, skip, reset, getState, getRemaining, getTodaySessions, getTotalSessions, getSettings };
})();


/* ---------- Conversation Mind Map ---------- */
/**
 * Interactive force-directed topic graph visualization.
 * Extracts key topics from conversation messages, finds co-occurring
 * topics within messages, and renders them as an interactive network.
 * Shortcut: Ctrl+Shift+G  |  Button: 🧠
 *
 * Features:
 * - Topic extraction with TF-IDF-like scoring
 * - Co-occurrence edge detection (topics in same message)
 * - Force-directed layout with canvas rendering
 * - Drag nodes, zoom, hover for details
 * - Color-coded by dominant speaker (user vs AI)
 * - Click topic to search messages
 * - Export as PNG
 */
const ConversationMindMap = (() => {
  let _overlay = null;
  let _canvas = null;
  let _ctx = null;
  let _isOpen = false;
  let _nodes = [];
  let _edges = [];
  let _animId = null;
  let _drag = null;
  let _hover = null;
  let _zoom = 1;
  let _panX = 0;
  let _panY = 0;
  let _lastPan = null;

  const STOP_WORDS = new Set([...COMMON_STOP_WORDS,
    'code', 'data', 'function', 'year', 'cannot', 'dare',
    'doing', 'done', 'getting', 'said', 'went', 'going',
    'feel', 'kind', 'pretty', 'quite', 'maybe',
    'someone', 'anyone', 'everyone', 'already', 'always', 'never', 'often',
  ]);

  const MIN_WORD_LEN = 3;
  const MAX_TOPICS = 40;
  const MIN_OCCURRENCES = 2;

  /* ---- Topic extraction ---- */
  function _extractTopics() {
    const history = (typeof ConversationManager !== 'undefined' && ConversationManager.getHistory)
      ? ConversationManager.getHistory() : [];
    if (history.length === 0) return { topics: [], cooccur: [] };

    // Per-message word sets (for co-occurrence)
    const wordFreq = {};    // word -> { count, user, ai, msgs: Set<idx> }
    const msgWords = [];    // per message: Set of significant words

    history.forEach((msg, idx) => {
      const text = (msg.content || '').toLowerCase()
        .replace(/```[\s\S]*?```/g, ' ')
        .replace(/`[^`]+`/g, ' ')
        .replace(/https?:\/\/\S+/g, ' ')
        .replace(/[^a-z0-9\s'-]/g, ' ');
      const words = text.split(/\s+/).filter(w => w.length >= MIN_WORD_LEN && !STOP_WORDS.has(w));
      const unique = new Set(words);
      msgWords.push(unique);

      for (const w of words) {
        if (!wordFreq[w]) wordFreq[w] = { count: 0, user: 0, ai: 0, msgs: new Set() };
        wordFreq[w].count++;
        wordFreq[w].msgs.add(idx);
        if (msg.role === 'user') wordFreq[w].user++;
        else wordFreq[w].ai++;
      }
    });

    // Filter and rank by TF-IDF-like score (frequent but not in every message)
    const totalMsgs = history.length;
    const scored = Object.entries(wordFreq)
      .filter(([, v]) => v.count >= MIN_OCCURRENCES)
      .map(([word, v]) => {
        const tf = v.count;
        const df = v.msgs.size;
        const idf = Math.log((totalMsgs + 1) / (df + 1));
        return { word, score: tf * idf, ...v };
      })
      .sort((a, b) => b.score - a.score)
      .slice(0, MAX_TOPICS);

    // Build co-occurrence edges
    const topicSet = new Set(scored.map(t => t.word));
    const edgeMap = {};

    for (const mw of msgWords) {
      const relevant = [...mw].filter(w => topicSet.has(w));
      for (let i = 0; i < relevant.length; i++) {
        for (let j = i + 1; j < relevant.length; j++) {
          const key = [relevant[i], relevant[j]].sort().join('||');
          edgeMap[key] = (edgeMap[key] || 0) + 1;
        }
      }
    }

    const edges = Object.entries(edgeMap)
      .filter(([, w]) => w >= 1)
      .map(([key, weight]) => {
        const [a, b] = key.split('||');
        return { a, b, weight };
      })
      .sort((a, b) => b.weight - a.weight)
      .slice(0, 120);

    return { topics: scored, cooccur: edges };
  }

  /* ---- Force-directed layout ---- */
  function _initLayout(topics, cooccur, w, h) {
    const maxScore = topics.length > 0 ? topics[0].score : 1;
    _nodes = topics.map((t, i) => {
      const angle = (2 * Math.PI * i) / topics.length;
      const r = Math.min(w, h) * 0.3;
      return {
        id: t.word,
        x: w / 2 + r * Math.cos(angle) + (Math.random() - 0.5) * 40,
        y: h / 2 + r * Math.sin(angle) + (Math.random() - 0.5) * 40,
        vx: 0, vy: 0,
        radius: 8 + 22 * (t.score / maxScore),
        score: t.score,
        count: t.count,
        user: t.user,
        ai: t.ai,
        userRatio: t.user / t.count
      };
    });

    const nodeMap = {};
    _nodes.forEach((n, i) => nodeMap[n.id] = i);

    _edges = cooccur
      .filter(e => nodeMap[e.a] !== undefined && nodeMap[e.b] !== undefined)
      .map(e => ({ source: nodeMap[e.a], target: nodeMap[e.b], weight: e.weight }));
  }

  function _simulate() {
    const alpha = 0.3;
    const repulsion = 2000;
    const attraction = 0.005;
    const damping = 0.85;
    const centerGravity = 0.01;
    const cw = _canvas.width;
    const ch = _canvas.height;
    const cx = cw / 2;
    const cy = ch / 2;

    // Repulsion
    for (let i = 0; i < _nodes.length; i++) {
      for (let j = i + 1; j < _nodes.length; j++) {
        const a = _nodes[i], b = _nodes[j];
        let dx = b.x - a.x, dy = b.y - a.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;
        const force = repulsion / (dist * dist);
        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;
        a.vx -= fx; a.vy -= fy;
        b.vx += fx; b.vy += fy;
      }
    }

    // Attraction (edges)
    for (const e of _edges) {
      const a = _nodes[e.source], b = _nodes[e.target];
      let dx = b.x - a.x, dy = b.y - a.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      const force = attraction * dist * (1 + e.weight * 0.3);
      const fx = (dx / dist) * force;
      const fy = (dy / dist) * force;
      a.vx += fx; a.vy += fy;
      b.vx -= fx; b.vy -= fy;
    }

    // Center gravity
    for (const n of _nodes) {
      n.vx += (cx - n.x) * centerGravity;
      n.vy += (cy - n.y) * centerGravity;
    }

    // Integrate
    for (const n of _nodes) {
      if (n === (_drag && _drag.node)) continue;
      n.vx *= damping;
      n.vy *= damping;
      n.x += n.vx * alpha;
      n.y += n.vy * alpha;
      // Boundary
      n.x = Math.max(n.radius, Math.min(cw - n.radius, n.x));
      n.y = Math.max(n.radius, Math.min(ch - n.radius, n.y));
    }
  }

  /* ---- Rendering ---- */
  function _draw() {
    if (!_ctx || !_canvas) return;
    const w = _canvas.width, h = _canvas.height;
    _ctx.clearRect(0, 0, w, h);
    _ctx.save();
    _ctx.translate(_panX, _panY);
    _ctx.scale(_zoom, _zoom);

    // Edges
    for (const e of _edges) {
      const a = _nodes[e.source], b = _nodes[e.target];
      _ctx.beginPath();
      _ctx.moveTo(a.x, a.y);
      _ctx.lineTo(b.x, b.y);
      const maxW = 6;
      _ctx.lineWidth = Math.min(maxW, 0.5 + e.weight * 0.8);
      _ctx.strokeStyle = `rgba(150,150,200,${Math.min(0.6, 0.1 + e.weight * 0.1)})`;
      _ctx.stroke();
    }

    // Nodes
    for (const n of _nodes) {
      // Color by user/ai ratio
      const ur = n.userRatio;
      const r = Math.round(74 * ur + 80 * (1 - ur));
      const g = Math.round(144 * ur + 200 * (1 - ur));
      const b = Math.round(217 * ur + 120 * (1 - ur));

      _ctx.beginPath();
      _ctx.arc(n.x, n.y, n.radius, 0, Math.PI * 2);
      _ctx.fillStyle = `rgba(${r},${g},${b},0.85)`;
      _ctx.fill();

      if (_hover === n) {
        _ctx.lineWidth = 3;
        _ctx.strokeStyle = '#fff';
        _ctx.stroke();
      }

      // Label
      const fontSize = Math.max(10, Math.min(16, n.radius * 0.8));
      _ctx.font = `bold ${fontSize}px -apple-system, BlinkMacSystemFont, sans-serif`;
      _ctx.fillStyle = '#fff';
      _ctx.textAlign = 'center';
      _ctx.textBaseline = 'middle';
      _ctx.fillText(n.id, n.x, n.y);
    }

    // Tooltip for hovered node
    if (_hover) {
      const n = _hover;
      const tip = `"${n.id}" - ${n.count}× (you: ${n.user}, AI: ${n.ai})`;
      _ctx.font = '13px -apple-system, BlinkMacSystemFont, sans-serif';
      const tw = _ctx.measureText(tip).width;
      const tx = Math.min(n.x - tw / 2, (w / _zoom) - tw - 16);
      const ty = n.y - n.radius - 28;
      _ctx.fillStyle = 'rgba(0,0,0,0.85)';
      _ctx.beginPath();
      _ctx.roundRect(tx - 6, ty - 14, tw + 12, 24, 6);
      _ctx.fill();
      _ctx.fillStyle = '#fff';
      _ctx.fillText(tip, tx + tw / 2, ty);
    }

    _ctx.restore();
  }

  function _loop() {
    _simulate();
    _draw();
    _animId = requestAnimationFrame(_loop);
  }

  /* ---- Mouse interaction ---- */
  function _toWorld(cx, cy) {
    return { x: (cx - _panX) / _zoom, y: (cy - _panY) / _zoom };
  }

  function _hitTest(mx, my) {
    const { x, y } = _toWorld(mx, my);
    for (let i = _nodes.length - 1; i >= 0; i--) {
      const n = _nodes[i];
      const dx = n.x - x, dy = n.y - y;
      if (dx * dx + dy * dy <= n.radius * n.radius) return n;
    }
    return null;
  }

  function _onMouseDown(e) {
    const rect = _canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left, my = e.clientY - rect.top;
    const node = _hitTest(mx, my);
    if (node) {
      _drag = { node, offsetX: 0, offsetY: 0 };
      _canvas.style.cursor = 'grabbing';
    } else {
      _lastPan = { x: e.clientX, y: e.clientY };
      _canvas.style.cursor = 'move';
    }
  }

  function _onMouseMove(e) {
    const rect = _canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left, my = e.clientY - rect.top;

    if (_drag) {
      const { x, y } = _toWorld(mx, my);
      _drag.node.x = x;
      _drag.node.y = y;
      _drag.node.vx = 0;
      _drag.node.vy = 0;
    } else if (_lastPan) {
      _panX += e.clientX - _lastPan.x;
      _panY += e.clientY - _lastPan.y;
      _lastPan = { x: e.clientX, y: e.clientY };
    } else {
      const node = _hitTest(mx, my);
      _hover = node;
      _canvas.style.cursor = node ? 'pointer' : 'default';
    }
  }

  function _onMouseUp(e) {
    if (_drag) {
      _canvas.style.cursor = 'pointer';
      _drag = null;
    } else if (_lastPan) {
      _canvas.style.cursor = 'default';
      _lastPan = null;
    }
  }

  function _onClick(e) {
    if (_drag || _lastPan) return;
    const rect = _canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left, my = e.clientY - rect.top;
    const node = _hitTest(mx, my);
    if (node && typeof MessageSearch !== 'undefined' && MessageSearch.open) {
      close();
      MessageSearch.open(node.id);
    }
  }

  function _onWheel(e) {
    e.preventDefault();
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    _zoom = Math.max(0.3, Math.min(3, _zoom * delta));
  }

  /* ---- Export PNG ---- */
  function _exportPNG() {
    if (!_canvas) return;
    const link = document.createElement('a');
    link.download = 'mindmap.png';
    link.href = _canvas.toDataURL('image/png');
    link.click();
  }

  /* ---- UI ---- */
  function _createUI() {
    if (_overlay) return;
    _overlay = document.createElement('div');
    _overlay.id = 'mindmap-overlay';
    _overlay.innerHTML = ''
      + '<div class="mm-container">'
      + '<div class="mm-header">'
      + '<span class="mm-title">🧠 Conversation Mind Map</span>'
      + '<div class="mm-controls">'
      + '<button class="btn-sm mm-export" title="Export PNG">📷</button>'
      + '<button class="btn-sm mm-refresh" title="Refresh">🔄</button>'
      + '<button class="btn-sm mm-close" title="Close">✕</button>'
      + '</div></div>'
      + '<div class="mm-legend">'
      + '<span class="mm-leg-user">● You</span> '
      + '<span class="mm-leg-ai">● AI</span> '
      + '<span class="mm-leg-hint">Drag nodes · Scroll to zoom · Click topic to search</span>'
      + '</div>'
      + '<canvas class="mm-canvas"></canvas>'
      + '</div>';

    // Styles
    const style = document.createElement('style');
    style.textContent = `
      #mindmap-overlay {
        display:none; position:fixed; inset:0; z-index:10000;
        background:rgba(0,0,0,0.75); justify-content:center; align-items:center;
      }
      #mindmap-overlay.visible { display:flex; }
      .mm-container {
        width:90vw; max-width:1000px; height:80vh; background:var(--bg-primary,#0f0f23);
        border-radius:12px; border:1px solid var(--border,#333); display:flex;
        flex-direction:column; overflow:hidden; box-shadow:0 20px 60px rgba(0,0,0,0.5);
      }
      .mm-header {
        display:flex; justify-content:space-between; align-items:center;
        padding:12px 16px; border-bottom:1px solid var(--border,#333);
      }
      .mm-title { font-weight:700; font-size:1rem; color:var(--text,#e0e0e0); }
      .mm-controls { display:flex; gap:6px; }
      .mm-controls .btn-sm {
        background:transparent; border:1px solid var(--border,#444); color:var(--text,#ccc);
        border-radius:6px; padding:4px 8px; cursor:pointer; font-size:0.85rem;
      }
      .mm-controls .btn-sm:hover { background:var(--accent,#6366f1); color:#fff; }
      .mm-legend {
        padding:6px 16px; font-size:0.75rem; color:var(--text-muted,#888);
        border-bottom:1px solid var(--border,#222);
      }
      .mm-leg-user { color:rgb(74,144,217); }
      .mm-leg-ai { color:rgb(80,200,120); }
      .mm-leg-hint { margin-left:12px; opacity:0.7; }
      .mm-canvas { flex:1; width:100%; cursor:default; }
      .mm-empty {
        flex:1; display:flex; align-items:center; justify-content:center;
        color:var(--text-muted,#888); font-size:1.1rem;
      }
    `;
    document.head.appendChild(style);
    document.body.appendChild(_overlay);

    _overlay.querySelector('.mm-close').addEventListener('click', close);
    _overlay.querySelector('.mm-refresh').addEventListener('click', _refresh);
    _overlay.querySelector('.mm-export').addEventListener('click', _exportPNG);
    _overlay.addEventListener('click', (e) => { if (e.target === _overlay) close(); });
  }

  function _refresh() {
    if (_animId) { cancelAnimationFrame(_animId); _animId = null; }
    const { topics, cooccur } = _extractTopics();
    const container = _overlay.querySelector('.mm-container');

    // Remove existing empty message if any
    const existingEmpty = container.querySelector('.mm-empty');
    if (existingEmpty) existingEmpty.remove();

    _canvas = _overlay.querySelector('.mm-canvas');

    if (topics.length === 0) {
      _canvas.style.display = 'none';
      const empty = document.createElement('div');
      empty.className = 'mm-empty';
      empty.textContent = 'No topics yet - start a conversation!';
      container.appendChild(empty);
      return;
    }

    _canvas.style.display = 'block';
    const rect = _canvas.parentElement.getBoundingClientRect();
    _canvas.width = _canvas.clientWidth || rect.width || 800;
    _canvas.height = _canvas.clientHeight || rect.height || 500;
    _ctx = _canvas.getContext('2d');

    _zoom = 1; _panX = 0; _panY = 0;
    _initLayout(topics, cooccur, _canvas.width, _canvas.height);

    // Attach events
    _canvas.onmousedown = _onMouseDown;
    _canvas.onmousemove = _onMouseMove;
    _canvas.onmouseup = _onMouseUp;
    _canvas.onclick = _onClick;
    _canvas.onwheel = _onWheel;
    window.onmouseleave = _onMouseUp;

    _loop();
  }

  function open() {
    _createUI();
    _overlay.classList.add('visible');
    _isOpen = true;
    // Delay refresh to let layout settle
    setTimeout(_refresh, 50);
  }

  function close() {
    if (_overlay) _overlay.classList.remove('visible');
    _isOpen = false;
    if (_animId) { cancelAnimationFrame(_animId); _animId = null; }
  }

  function toggle() { _isOpen ? close() : open(); }

  function init() {
    const btn = DOMCache.get('mindmap-btn');
    if (btn) btn.addEventListener('click', toggle);
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'G') {
        e.preventDefault();
        toggle();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { open, close, toggle, init };
})();

/* ============================================================
 * Command Palette - VS Code-style universal command launcher
 *
 * Ctrl+Shift+P opens a fuzzy-searchable palette of all app commands.
 * Modules register commands via CommandPalette.register(). Each command
 * has a label, optional category/icon/shortcut, and an action callback.
 *
 * Features:
 *   - Fuzzy search across all registered commands
 *   - Category grouping with headers
 *   - Recent commands tracked and shown first
 *   - Keyboard navigation (↑/↓/Enter/Escape)
 *   - Shortcut hints displayed per command
 *   - Fuzzy match highlighting in results
 *   - 36 built-in commands for all app modules
 *   - Extensible: any module can register custom commands
 *
 * @namespace CommandPalette
 * ============================================================ */
const CommandPalette = (() => {
  const _commands = [];
  let _overlay = null;
  let _input = null;
  let _list = null;
  let _filtered = [];
  let _selectedIndex = 0;
  let _isOpen = false;
  let _recentIds = [];
  const MAX_RECENT = 10;

  function register(cmd) {
    if (!cmd || !cmd.id || !cmd.label || typeof cmd.action !== 'function') return;
    const idx = _commands.findIndex(c => c.id === cmd.id);
    if (idx !== -1) { _commands[idx] = cmd; return; }
    _commands.push(cmd);
  }

  function registerMany(cmds) {
    if (!Array.isArray(cmds)) return;
    cmds.forEach(register);
  }

  function unregister(id) {
    const idx = _commands.findIndex(c => c.id === id);
    if (idx !== -1) _commands.splice(idx, 1);
  }

  // _fuzzyMatch / _fuzzyScore — use shared top-level definitions

  function _loadRecent() {
    try {
      const raw = (typeof SafeStorage !== 'undefined' ? SafeStorage : localStorage).getItem('cp_recent');
      if (raw) _recentIds = _safeParse(raw);
    } catch (e) { _recentIds = []; }
  }

  function _saveRecent() {
    try {
      (typeof SafeStorage !== 'undefined' ? SafeStorage : localStorage).setItem('cp_recent', JSON.stringify(_recentIds));
    } catch (e) { /* ignore */ }
  }

  function _addRecent(id) {
    _recentIds = _recentIds.filter(r => r !== id);
    _recentIds.unshift(id);
    if (_recentIds.length > MAX_RECENT) _recentIds.length = MAX_RECENT;
    _saveRecent();
  }

  function _filter(query) {
    if (!query) {
      const recent = _recentIds
        .map(id => _commands.find(c => c.id === id))
        .filter(Boolean)
        .map(c => ({ ...c, _recent: true }));
      const recentIds = new Set(_recentIds);
      const rest = _commands.filter(c => !recentIds.has(c.id));
      _filtered = [...recent, ...rest];
    } else {
      const searchText = (c) => `${c.category || ''} ${c.label}`;
      _filtered = _commands
        .filter(c => _fuzzyMatch(query, searchText(c)))
        .sort((a, b) => _fuzzyScore(query, searchText(a)) - _fuzzyScore(query, searchText(b)));
    }
    _selectedIndex = 0;
  }

  function _highlightMatch(text, query) {
    if (!query) return _escapeHtml(text);
    const q = query.toLowerCase();
    const t = text.toLowerCase();
    let result = '';
    let qi = 0;
    for (let i = 0; i < text.length; i++) {
      const safe = _escapeHtml(text[i]);
      if (qi < q.length && t[i] === q[qi]) {
        result += '<b>' + safe + '</b>';
        qi++;
      } else {
        result += safe;
      }
    }
    return result;
  }

  function _render() {
    if (!_list) return;
    const query = _input ? _input.value : '';
    _list.innerHTML = '';
    if (_filtered.length === 0) {
      const empty = document.createElement('div');
      empty.className = 'cp-empty';
      empty.textContent = 'No matching commands';
      _list.appendChild(empty);
      return;
    }
    let lastCategory = null;
    _filtered.forEach((cmd, i) => {
      const cat = cmd._recent ? '\u23F1\uFE0F Recent' : (cmd.category || 'General');
      if (cat !== lastCategory && !query) {
        const header = document.createElement('div');
        header.className = 'cp-category';
        header.textContent = cat;
        _list.appendChild(header);
        lastCategory = cat;
      }
      const item = document.createElement('div');
      item.className = 'cp-item' + (i === _selectedIndex ? ' cp-selected' : '');
      item.setAttribute('role', 'option');
      item.setAttribute('aria-selected', i === _selectedIndex ? 'true' : 'false');

      const icon = cmd.icon ? '<span class="cp-icon">' + cmd.icon + '</span>' : '';
      const label = _highlightMatch(cmd.label, query);
      const shortcut = cmd.shortcut ? '<span class="cp-shortcut">' + cmd.shortcut + '</span>' : '';
      item.innerHTML = icon + '<span class="cp-label">' + label + '</span>' + shortcut;

      item.addEventListener('click', () => _execute(i));
      item.addEventListener('mouseenter', () => {
        _selectedIndex = i;
        _render();
      });
      _list.appendChild(item);
    });
    const selected = _list.querySelector('.cp-selected');
    if (selected) selected.scrollIntoView({ block: 'nearest' });
  }

  function _execute(index) {
    const cmd = _filtered[index];
    if (!cmd) return;
    _addRecent(cmd.id);
    close();
    try { cmd.action(); } catch (e) { /* ignore */ }
  }

  function _createUI() {
    if (_overlay) return;
    _overlay = document.createElement('div');
    _overlay.id = 'command-palette-overlay';
    _overlay.className = 'cp-overlay';
    _overlay.setAttribute('role', 'dialog');
    _overlay.setAttribute('aria-label', 'Command Palette');
    _overlay.innerHTML =
      '<div class="cp-dialog">' +
        '<input class="cp-input" type="text" placeholder="Type a command\u2026" aria-label="Search commands" autocomplete="off" />' +
        '<div class="cp-list" role="listbox"></div>' +
      '</div>';
    document.body.appendChild(_overlay);
    _input = _overlay.querySelector('.cp-input');
    _list = _overlay.querySelector('.cp-list');

    _input.addEventListener('input', () => {
      _filter(_input.value.trim());
      _render();
    });

    _input.addEventListener('keydown', (e) => {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        _selectedIndex = Math.min(_selectedIndex + 1, _filtered.length - 1);
        _render();
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        _selectedIndex = Math.max(_selectedIndex - 1, 0);
        _render();
      } else if (e.key === 'Enter') {
        e.preventDefault();
        _execute(_selectedIndex);
      } else if (e.key === 'Escape') {
        e.preventDefault();
        close();
      }
    });

    _overlay.addEventListener('click', (e) => {
      if (e.target === _overlay) close();
    });
  }

  function open() {
    _createUI();
    _loadRecent();
    _overlay.classList.add('cp-visible');
    _isOpen = true;
    _input.value = '';
    _filter('');
    _render();
    _input.focus();
  }

  function close() {
    if (_overlay) _overlay.classList.remove('cp-visible');
    _isOpen = false;
  }

  function toggle() { _isOpen ? close() : open(); }

  function getCommands() { return _commands.slice(); }
  function getFiltered() { return _filtered.slice(); }
  function isOpen() { return _isOpen; }

  function _registerBuiltInCommands() {
    const builtIn = [
      { id: 'cp:theme', label: 'Toggle Theme (Dark/Light)', icon: '\u2600\uFE0F', shortcut: 'Ctrl+D', category: 'Appearance', action: () => { if (typeof ThemeManager !== 'undefined') ThemeManager.toggle(); } },
      { id: 'cp:zen', label: 'Toggle Focus Mode', icon: '\uD83E\uDDD8', shortcut: 'Ctrl+Shift+F', category: 'Appearance', action: () => { if (typeof FocusMode !== 'undefined') FocusMode.toggle(); } },
      { id: 'cp:new-session', label: 'New Session', icon: '\u2795', category: 'Sessions', action: () => { if (typeof SessionManager !== 'undefined') SessionManager.newSession(); } },
      { id: 'cp:switch-session', label: 'Quick Switch Session', icon: '\u26A1', shortcut: 'Ctrl+K', category: 'Sessions', action: () => { if (typeof QuickSwitcher !== 'undefined') QuickSwitcher.toggle(); } },
      { id: 'cp:search', label: 'Search Messages', icon: '\uD83D\uDD0D', shortcut: 'Ctrl+F', category: 'Search', action: () => { if (typeof MessageSearch !== 'undefined') MessageSearch.toggle(); } },
      { id: 'cp:global-search', label: 'Search All Sessions', icon: '\uD83D\uDD0E', shortcut: 'Ctrl+Shift+S', category: 'Search', action: () => { if (typeof GlobalSessionSearch !== 'undefined') GlobalSessionSearch.toggle(); } },
      { id: 'cp:history', label: 'Conversation History', icon: '\uD83D\uDCDC', shortcut: 'Ctrl+H', category: 'Navigation', action: () => { if (typeof HistoryPanel !== 'undefined') HistoryPanel.toggle(); } },
      { id: 'cp:bookmarks', label: 'View Bookmarks', icon: '\uD83D\uDD16', shortcut: 'Ctrl+B', category: 'Navigation', action: () => { if (typeof ChatBookmarks !== 'undefined') ChatBookmarks.toggle(); } },
      { id: 'cp:stats', label: 'Chat Statistics', icon: '\uD83D\uDCCA', shortcut: 'Ctrl+I', category: 'Analytics', action: () => { if (typeof ChatStats !== 'undefined') ChatStats.toggle(); } },
      { id: 'cp:cost', label: 'Cost Dashboard', icon: '\uD83D\uDCB0', category: 'Analytics', action: () => { if (typeof CostDashboard !== 'undefined') CostDashboard.toggle(); } },
      { id: 'cp:heatmap', label: 'Usage Heatmap', icon: '\uD83D\uDCC5', category: 'Analytics', action: () => { if (typeof UsageHeatmap !== 'undefined') UsageHeatmap.toggle(); } },
      { id: 'cp:summary', label: 'Conversation Summary', icon: '\uD83D\uDCCB', shortcut: 'Alt+S', category: 'Tools', action: () => { if (typeof ConversationSummarizer !== 'undefined') ConversationSummarizer.toggle(); } },
      { id: 'cp:scratchpad', label: 'Open Scratchpad', icon: '\uD83D\uDCDD', shortcut: 'Ctrl+.', category: 'Tools', action: () => { if (typeof Scratchpad !== 'undefined') Scratchpad.toggle(); } },
      { id: 'cp:snippets', label: 'Snippet Library', icon: '\u2702\uFE0F', shortcut: 'Ctrl+Shift+L', category: 'Tools', action: () => { if (typeof SnippetLibrary !== 'undefined') SnippetLibrary.toggle(); } },
      { id: 'cp:prompt-library', label: 'Prompt Library', icon: '\uD83D\uDCDA', shortcut: 'Ctrl+L', category: 'Tools', action: () => { if (typeof PromptLibrary !== 'undefined') PromptLibrary.toggle(); } },
      { id: 'cp:templates', label: 'Prompt Templates', icon: '\uD83D\uDCC4', category: 'Tools', action: () => { if (typeof PromptTemplates !== 'undefined') PromptTemplates.toggle(); } },
      { id: 'cp:chains', label: 'Prompt Chains', icon: '\u26D3\uFE0F', category: 'Tools', action: () => { if (typeof PromptChainRunner !== 'undefined') PromptChainRunner.toggle(); } },
      { id: 'cp:agenda', label: 'Conversation Agenda', icon: '\uD83C\uDFAF', shortcut: 'Alt+G', category: 'Tools', action: () => { if (typeof ConversationAgenda !== 'undefined') ConversationAgenda.toggle(); } },
      { id: 'cp:chapters', label: 'Conversation Chapters', icon: '\uD83D\uDCD1', shortcut: 'Alt+Shift+C', category: 'Tools', action: () => { if (typeof ConversationChapters !== 'undefined') ConversationChapters.toggle(); } },
      { id: 'cp:annotations', label: 'Message Annotations', icon: '\uD83C\uDFF7\uFE0F', category: 'Tools', action: () => { if (typeof MessageAnnotations !== 'undefined') MessageAnnotations.toggle(); } },
      { id: 'cp:tags', label: 'Manage Tags', icon: '\uD83C\uDFF7\uFE0F', category: 'Sessions', action: () => { if (typeof ConversationTags !== 'undefined') ConversationTags.toggle(); } },
      { id: 'cp:wordcloud', label: 'Word Cloud', icon: '\u2601\uFE0F', shortcut: 'Ctrl+Shift+W', category: 'Visualization', action: () => { if (typeof WordCloudPanel !== 'undefined') WordCloudPanel.toggle(); } },
      { id: 'cp:reader', label: 'Reader View', icon: '\uD83D\uDCD6', shortcut: 'Alt+R', category: 'Tools', action: () => { if (typeof MessageReaderView !== 'undefined') MessageReaderView.toggle(); } },
      { id: 'cp:mindmap', label: 'Mind Map', icon: '\uD83E\uDDE0', shortcut: 'Ctrl+Shift+G', category: 'Visualization', action: () => { if (typeof ConversationMindMap !== 'undefined') ConversationMindMap.toggle(); } },
      { id: 'cp:timeline', label: 'Conversation Timeline', icon: '\uD83D\uDCC8', category: 'Visualization', action: () => { if (typeof ConversationTimeline !== 'undefined') ConversationTimeline.toggle(); } },
      { id: 'cp:sentiment', label: 'Sentiment Analysis', icon: '\uD83D\uDE0A', shortcut: 'Ctrl+Shift+M', category: 'Analytics', action: () => { if (typeof ConversationSentiment !== 'undefined') ConversationSentiment.toggle(); } },
      { id: 'cp:health', label: 'Conversation Health Check', icon: '\uD83E\uDE7A', shortcut: 'Ctrl+Shift+H', category: 'Analytics', action: () => { if (typeof ConversationHealthCheck !== 'undefined') ConversationHealthCheck.toggle(); } },
      { id: 'cp:typing', label: 'Typing Speed Dashboard', icon: '\u2328\uFE0F', shortcut: 'Ctrl+Shift+T', category: 'Analytics', action: () => { if (typeof TypingSpeedMonitor !== 'undefined') TypingSpeedMonitor.toggleDashboard(); } },
      { id: 'cp:pomodoro', label: 'Focus Timer (Pomodoro)', icon: '\uD83C\uDF45', shortcut: 'Alt+P', category: 'Tools', action: () => { if (typeof FocusTimer !== 'undefined') FocusTimer.toggle(); } },
      { id: 'cp:theme-creator', label: 'Custom Theme Creator', icon: '\uD83C\uDFA8', shortcut: 'Ctrl+Shift+E', category: 'Tools', action: () => { if (typeof CustomThemeCreator !== 'undefined') CustomThemeCreator.toggle(); } },
      { id: 'cp:ratings', label: 'Response Ratings', icon: '\u2B50', category: 'Analytics', action: () => { if (typeof ResponseRating !== 'undefined') ResponseRating.toggle(); } },
      { id: 'cp:clipboard', label: 'Clipboard History', icon: '\uD83D\uDCCB', shortcut: 'Ctrl+Shift+V', category: 'Tools', action: () => { if (typeof ClipboardHistory !== 'undefined') ClipboardHistory.toggle(); } },
      { id: 'cp:readaloud', label: 'Read Aloud', icon: '\uD83D\uDD0A', category: 'Tools', action: () => { if (typeof ReadAloud !== 'undefined') ReadAloud.toggle(); } },
      { id: 'cp:replay', label: 'Conversation Replay', icon: '\u25B6\uFE0F', category: 'Tools', action: () => { if (typeof ConversationReplay !== 'undefined') ConversationReplay.toggle(); } },
      { id: 'cp:import-chatgpt', label: 'Import ChatGPT Conversations', icon: '\uD83D\uDCE5', category: 'Import/Export', action: () => { if (typeof ChatGPTImporter !== 'undefined') ChatGPTImporter.toggle(); } },
      { id: 'cp:filter', label: 'Message Filters', icon: '\uD83D\uDD3D', category: 'Search', action: () => { if (typeof MessageFilter !== 'undefined') MessageFilter.toggle(); } },
      { id: 'cp:share-link', label: 'Share Conversation Link', icon: '🔗', shortcut: 'Alt+S', category: 'Import/Export', action: () => { if (typeof ConversationShareLink !== 'undefined') ConversationShareLink.toggle(); } },
      { id: 'cp:clear', label: 'Clear Conversation', icon: '\uD83D\uDDD1\uFE0F', category: 'Sessions', action: () => { if (typeof ConversationManager !== 'undefined') ConversationManager.clear(); if (typeof UIController !== 'undefined') UIController.clearMessages(); } },
      { id: 'cp:conv-timer', label: 'Conversation Timer', icon: '⏱️', shortcut: 'Alt+T', category: 'Tools', action: () => { if (typeof ConversationTimer !== 'undefined') ConversationTimer.toggle(); } },
      { id: 'cp:shortcuts', label: 'Keyboard Shortcuts', icon: '\u2328\uFE0F', shortcut: '?', category: 'Help', action: () => { if (typeof KeyboardShortcuts !== 'undefined') KeyboardShortcuts.showHelp(); } },
    ];
    registerMany(builtIn);
  }

  function init() {
    _registerBuiltInCommands();
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'P') {
        e.preventDefault();
        toggle();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { register, registerMany, unregister, open, close, toggle, getCommands, getFiltered, isOpen, init };
})();

/* ---------- Split View ---------- */
/**
 * Side-by-side session comparison view. Pick two saved sessions and view
 * their messages in parallel panes with synchronized scrolling, message
 * counts, and role highlighting.
 *
 * Shortcut: Ctrl+Shift+2
 * Slash command: /splitview
 *
 * @namespace SplitView
 */
const SplitView = (() => {
  const MAX_PREVIEW_CHARS = 300;
  let _overlay = null;
  let _isOpen = false;
  let _leftSession = null;
  let _rightSession = null;
  let _syncScroll = true;

  // uses global _escapeHtml
  // uses shared top-level _truncate

  function _getSessions() {
    if (typeof SessionManager === 'undefined') return [];
    try {
      const all = SessionManager.getAll();
      return Array.isArray(all) ? all : [];
    } catch { return []; }
  }

  function _createOverlay() {
    if (_overlay) { _overlay.remove(); }
    _overlay = document.createElement('div');
    _overlay.id = 'splitview-overlay';
    _overlay.className = 'modal-overlay splitview-overlay';
    _overlay.setAttribute('role', 'dialog');
    _overlay.setAttribute('aria-modal', 'true');
    _overlay.setAttribute('aria-label', 'Split View - Compare Sessions');

    const panel = document.createElement('div');
    panel.className = 'splitview-panel';

    // Header
    const header = document.createElement('div');
    header.className = 'splitview-header';
    header.innerHTML = `
      <h3>📖 Split View - Compare Sessions</h3>
      <div class="splitview-controls">
        <label class="splitview-sync-label" title="Synchronize scrolling between panes">
          <input type="checkbox" id="splitview-sync" ${_syncScroll ? 'checked' : ''}> Sync scroll
        </label>
        <button id="splitview-swap-btn" class="btn-sm" title="Swap left and right sessions">⇄ Swap</button>
        <button id="splitview-close-btn" class="btn-sm" title="Close split view">✕</button>
      </div>
    `;
    panel.appendChild(header);

    // Session selectors
    const selectors = document.createElement('div');
    selectors.className = 'splitview-selectors';
    const sessions = _getSessions();
    const optionsHtml = sessions.map((s, i) => {
      const name = _escapeHtml(s.name || `Session ${i + 1}`);
      const count = Array.isArray(s.messages) ? s.messages.length : 0;
      return `<option value="${i}">${name} (${count} msgs)</option>`;
    }).join('');

    selectors.innerHTML = `
      <div class="splitview-selector">
        <label for="splitview-left-select">Left:</label>
        <select id="splitview-left-select">
          <option value="">- select session -</option>
          ${optionsHtml}
        </select>
      </div>
      <div class="splitview-selector">
        <label for="splitview-right-select">Right:</label>
        <select id="splitview-right-select">
          <option value="">- select session -</option>
          ${optionsHtml}
        </select>
      </div>
    `;
    panel.appendChild(selectors);

    // Stats bar
    const stats = document.createElement('div');
    stats.className = 'splitview-stats';
    stats.id = 'splitview-stats';
    panel.appendChild(stats);

    // Split panes
    const panes = document.createElement('div');
    panes.className = 'splitview-panes';
    panes.innerHTML = `
      <div class="splitview-pane" id="splitview-left-pane">
        <div class="splitview-pane-empty">Select a session on the left</div>
      </div>
      <div class="splitview-divider"></div>
      <div class="splitview-pane" id="splitview-right-pane">
        <div class="splitview-pane-empty">Select a session on the right</div>
      </div>
    `;
    panel.appendChild(panes);

    _overlay.appendChild(panel);
    document.body.appendChild(_overlay);

    // Event listeners
    const closeBtn = _overlay.querySelector('#splitview-close-btn');
    closeBtn.addEventListener('click', close);

    const swapBtn = _overlay.querySelector('#splitview-swap-btn');
    swapBtn.addEventListener('click', _swap);

    const syncCheck = _overlay.querySelector('#splitview-sync');
    syncCheck.addEventListener('change', (e) => { _syncScroll = e.target.checked; _setupSyncScroll(); });

    const leftSelect = _overlay.querySelector('#splitview-left-select');
    const rightSelect = _overlay.querySelector('#splitview-right-select');
    leftSelect.addEventListener('change', () => { _selectSession('left', leftSelect.value); });
    rightSelect.addEventListener('change', () => { _selectSession('right', rightSelect.value); });

    _overlay.addEventListener('click', (e) => { if (e.target === _overlay) close(); });

    document.addEventListener('keydown', _onKey);
  }

  function _onKey(e) {
    if (e.key === 'Escape' && _isOpen) { close(); e.preventDefault(); }
  }

  function _selectSession(side, indexStr) {
    const sessions = _getSessions();
    const idx = parseInt(indexStr, 10);
    const session = isNaN(idx) ? null : sessions[idx] || null;

    if (side === 'left') _leftSession = session;
    else _rightSession = session;

    _renderPane(side, session);
    _renderStats();
    _setupSyncScroll();
  }

  function _renderPane(side, session) {
    const paneId = side === 'left' ? 'splitview-left-pane' : 'splitview-right-pane';
    const pane = DOMCache.get(paneId);
    if (!pane) return;
    pane.innerHTML = '';

    if (!session || !Array.isArray(session.messages) || session.messages.length === 0) {
      const empty = document.createElement('div');
      empty.className = 'splitview-pane-empty';
      empty.textContent = session ? 'This session has no messages.' : `Select a session on the ${side}`;
      pane.appendChild(empty);
      return;
    }

    session.messages.forEach((msg, i) => {
      const el = document.createElement('div');
      const role = (msg.role || 'user').toLowerCase();
      el.className = `splitview-msg splitview-msg-${role}`;

      const badge = document.createElement('span');
      badge.className = 'splitview-msg-role';
      badge.textContent = role === 'user' ? '👤' : role === 'system' ? '⚙️' : '🤖';

      const num = document.createElement('span');
      num.className = 'splitview-msg-num';
      num.textContent = `#${i + 1}`;

      const content = document.createElement('div');
      content.className = 'splitview-msg-content';
      content.textContent = _truncate(msg.content || '', MAX_PREVIEW_CHARS);

      el.appendChild(badge);
      el.appendChild(num);
      el.appendChild(content);
      pane.appendChild(el);
    });
  }

  function _renderStats() {
    const el = DOMCache.get('splitview-stats');
    if (!el) return;

    const leftMsgs = _leftSession && Array.isArray(_leftSession.messages) ? _leftSession.messages : [];
    const rightMsgs = _rightSession && Array.isArray(_rightSession.messages) ? _rightSession.messages : [];

    if (leftMsgs.length === 0 && rightMsgs.length === 0) {
      el.innerHTML = '';
      return;
    }

    // Single-pass aggregation instead of 3 separate filter/reduce passes per side
    let leftWords = 0, leftUser = 0, leftAI = 0;
    for (let i = 0; i < leftMsgs.length; i++) {
      const m = leftMsgs[i];
      const c = m.content || '';
      if (c) { let j = 0, len = c.length, inWord = false; for (; j < len; j++) { const ch = c.charCodeAt(j); if (ch <= 32 || ch === 9 || ch === 10 || ch === 13) { inWord = false; } else if (!inWord) { inWord = true; leftWords++; } } }
      if (m.role === 'user') leftUser++;
      else if (m.role === 'assistant') leftAI++;
    }
    let rightWords = 0, rightUser = 0, rightAI = 0;
    for (let i = 0; i < rightMsgs.length; i++) {
      const m = rightMsgs[i];
      const c = m.content || '';
      if (c) { let j = 0, len = c.length, inWord = false; for (; j < len; j++) { const ch = c.charCodeAt(j); if (ch <= 32 || ch === 9 || ch === 10 || ch === 13) { inWord = false; } else if (!inWord) { inWord = true; rightWords++; } } }
      if (m.role === 'user') rightUser++;
      else if (m.role === 'assistant') rightAI++;
    }

    el.innerHTML = `
      <div class="splitview-stat-group">
        <span class="splitview-stat-label">Left:</span>
        <span>${leftMsgs.length} msgs (${leftUser} user, ${leftAI} AI) · ${leftWords.toLocaleString()} words</span>
      </div>
      <div class="splitview-stat-group">
        <span class="splitview-stat-label">Right:</span>
        <span>${rightMsgs.length} msgs (${rightUser} user, ${rightAI} AI) · ${rightWords.toLocaleString()} words</span>
      </div>
    `;
  }

  function _setupSyncScroll() {
    const left = DOMCache.get('splitview-left-pane');
    const right = DOMCache.get('splitview-right-pane');
    if (!left || !right) return;

    // Remove old listeners
    left.onscroll = null;
    right.onscroll = null;

    if (!_syncScroll) return;

    let syncing = false;
    left.onscroll = () => {
      if (syncing) return;
      syncing = true;
      const ratio = left.scrollTop / (left.scrollHeight - left.clientHeight || 1);
      right.scrollTop = ratio * (right.scrollHeight - right.clientHeight || 1);
      syncing = false;
    };
    right.onscroll = () => {
      if (syncing) return;
      syncing = true;
      const ratio = right.scrollTop / (right.scrollHeight - right.clientHeight || 1);
      left.scrollTop = ratio * (left.scrollHeight - left.clientHeight || 1);
      syncing = false;
    };
  }

  function _swap() {
    const leftSelect = DOMCache.get('splitview-left-select');
    const rightSelect = DOMCache.get('splitview-right-select');
    if (!leftSelect || !rightSelect) return;

    const temp = leftSelect.value;
    leftSelect.value = rightSelect.value;
    rightSelect.value = temp;

    const tempSession = _leftSession;
    _leftSession = _rightSession;
    _rightSession = tempSession;

    _renderPane('left', _leftSession);
    _renderPane('right', _rightSession);
    _renderStats();
    _setupSyncScroll();
  }

  function open() {
    _createOverlay();
    _overlay.style.display = '';
    _isOpen = true;
    _leftSession = null;
    _rightSession = null;
  }

  function close() {
    if (_overlay) {
      _overlay.remove();
      _overlay = null;
    }
    _isOpen = false;
    _leftSession = null;
    _rightSession = null;
    document.removeEventListener('keydown', _onKey);
  }

  function toggle() { _isOpen ? close() : open(); }
  function isOpen() { return _isOpen; }

  function getLeftSession() { return _leftSession; }
  function getRightSession() { return _rightSession; }
  function isSyncScrollEnabled() { return _syncScroll; }

  // Keyboard shortcut: Ctrl+Shift+2
  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey && e.shiftKey && e.key === '2') {
      e.preventDefault();
      toggle();
    }
  });

  return {
    open, close, toggle, isOpen,
    getLeftSession, getRightSession, isSyncScrollEnabled,
    _escapeHtml, _truncate, _getSessions, _renderStats, _swap,
    MAX_PREVIEW_CHARS
  };
})();

/* ---------- Session Streak Tracker ---------- */
/**
 * StreakTracker - tracks consecutive-day chat activity streaks,
 * shows current/longest streak, 90-day activity calendar, and
 * milestone achievements. Gamifies consistent usage.
 *
 * Shortcut: Ctrl+Shift+K
 * Button: 🔥 in toolbar
 */
const StreakTracker = (() => {
  let _overlay = null;
  let _isOpen = false;

  const MILESTONES = [
    { days: 3, emoji: '🌱', label: 'Seedling', desc: 'Chat 3 days in a row' },
    { days: 7, emoji: '🔥', label: 'On Fire', desc: 'One week streak' },
    { days: 14, emoji: '⚡', label: 'Unstoppable', desc: 'Two week streak' },
    { days: 30, emoji: '🏆', label: 'Champion', desc: '30-day streak' },
    { days: 60, emoji: '💎', label: 'Diamond', desc: '60-day streak' },
    { days: 100, emoji: '👑', label: 'Legend', desc: '100-day streak' },
    { days: 365, emoji: '🌟', label: 'Eternal', desc: 'Full year streak' },
  ];

  function _getSessions() {
    if (typeof SessionManager === 'undefined') return [];
    try {
      // Use getAllUnsorted() — StreakTracker only needs session data,
      // not presentation order.  Avoids the sort + pinned-set overhead
      // of getAll() which runs on every toggle/render.
      const all = SessionManager.getAllUnsorted ? SessionManager.getAllUnsorted() : SessionManager.getAll();
      return Array.isArray(all) ? all : [];
    } catch { return []; }
  }

  /** Get unique active dates (YYYY-MM-DD) from all sessions.
   *  Optimised: avoids `new Date(ts)` for ISO-formatted timestamps.
   *  Timestamps stored as ISO 8601 strings ("2026-04-28T...") can have
   *  their date portion extracted via substring(0,10) — skipping the
   *  Date constructor overhead for potentially thousands of messages.
   *  For numeric epoch timestamps we fall back to `new Date(ts)` but
   *  use a pre-allocated formatter instead of toISOString().substring().
   */
  function _getActiveDates() {
    const sessions = _getSessions();
    const dates = new Set();
    for (const s of sessions) {
      if (s.createdAt) dates.add(s.createdAt.substring(0, 10));
      if (s.updatedAt) dates.add(s.updatedAt.substring(0, 10));
      // Also check individual message timestamps if available
      if (Array.isArray(s.messages)) {
        for (const m of s.messages) {
          const ts = m.timestamp;
          if (!ts) continue;
          // Fast path: ISO string "YYYY-MM-DD..." — no Date allocation needed
          if (typeof ts === 'string' && ts.length >= 10 && ts[4] === '-' && ts[7] === '-') {
            dates.add(ts.substring(0, 10));
          } else {
            // Numeric or non-ISO timestamp — fallback to Date
            const d = new Date(ts);
            if (!isNaN(d.getTime())) dates.add(d.toISOString().substring(0, 10));
          }
        }
      }
    }
    return dates;
  }

  /** Calculate streak info from a set of date strings. */
  function _calcStreaks(dateSet) {
    if (dateSet.size === 0) return { current: 0, longest: 0, totalDays: 0, streakDates: [] };

    const sorted = [...dateSet].sort();
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayStr = today.toISOString().substring(0, 10);
    const yesterdayDate = new Date(today);
    yesterdayDate.setDate(yesterdayDate.getDate() - 1);
    const yesterdayStr = yesterdayDate.toISOString().substring(0, 10);

    // Calculate all streaks
    let longest = 1;
    let currentStreak = 1;
    const streaks = [{ start: sorted[0], length: 1 }];

    for (let i = 1; i < sorted.length; i++) {
      const prev = new Date(sorted[i - 1]);
      const curr = new Date(sorted[i]);
      const diffDays = Math.round((curr - prev) / (1000 * 60 * 60 * 24));
      if (diffDays === 1) {
        currentStreak++;
        streaks[streaks.length - 1].length = currentStreak;
      } else {
        currentStreak = 1;
        streaks.push({ start: sorted[i], length: 1 });
      }
      if (currentStreak > longest) longest = currentStreak;
    }

    // Current streak: must include today or yesterday
    const lastDate = sorted[sorted.length - 1];
    let current = 0;
    if (lastDate === todayStr || lastDate === yesterdayStr) {
      current = streaks[streaks.length - 1].length;
    }

    return {
      current,
      longest,
      totalDays: dateSet.size,
      streaks,
    };
  }

  // uses global _escapeHtml

  function _buildCalendar(dateSet) {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const cells = [];

    // 90 days back
    for (let i = 89; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().substring(0, 10);
      const active = dateSet.has(ds);
      const dayName = d.toLocaleDateString('en-US', { weekday: 'short' });
      const fullDate = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      cells.push(
        `<div class="streak-cal-cell ${active ? 'streak-cal-active' : ''}" title="${fullDate} (${dayName})${active ? ' - active' : ''}"></div>`
      );
    }

    // Month labels
    const months = [];
    let lastMonth = -1;
    for (let i = 89; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(d.getDate() - i);
      const m = d.getMonth();
      if (m !== lastMonth) {
        months.push(`<span style="grid-column: ${90 - i}">${d.toLocaleDateString('en-US', { month: 'short' })}</span>`);
        lastMonth = m;
      }
    }

    return `
      <div class="streak-cal-months">${months.join('')}</div>
      <div class="streak-cal-grid">${cells.join('')}</div>
    `;
  }

  function _buildMilestones(longestStreak) {
    return MILESTONES.map(m => {
      const achieved = longestStreak >= m.days;
      return `<div class="streak-milestone ${achieved ? 'streak-milestone-achieved' : ''}">
        <span class="streak-milestone-emoji">${m.emoji}</span>
        <div class="streak-milestone-info">
          <strong>${m.label}</strong> - ${m.desc}
          ${achieved ? '<span class="streak-milestone-check">✅</span>' : `<span class="streak-milestone-remaining">${m.days - longestStreak} days to go</span>`}
        </div>
      </div>`;
    }).join('');
  }

  function _buildWeekdayStats(dateSet) {
    const counts = [0, 0, 0, 0, 0, 0, 0]; // Sun-Sat
    const names = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    for (const ds of dateSet) {
      const d = new Date(ds + 'T00:00:00');
      counts[d.getDay()]++;
    }
    const max = Math.max(...counts, 1);
    return `<div class="streak-weekday-chart">${counts.map((c, i) =>
      `<div class="streak-weekday-bar-wrap">
        <div class="streak-weekday-bar" style="height:${Math.round((c / max) * 100)}%" title="${c} days"></div>
        <span class="streak-weekday-label">${names[i]}</span>
      </div>`
    ).join('')}</div>`;
  }

  function open() {
    if (_overlay) _overlay.remove();

    const dateSet = _getActiveDates();
    const info = _calcStreaks(dateSet);

    _overlay = document.createElement('div');
    _overlay.id = 'streak-overlay';
    _overlay.className = 'modal-overlay';
    _overlay.setAttribute('role', 'dialog');
    _overlay.setAttribute('aria-modal', 'true');
    _overlay.setAttribute('aria-label', 'Session Streak Tracker');

    const panel = document.createElement('div');
    panel.className = 'streak-panel';
    panel.innerHTML = `
      <div class="streak-header">
        <h3>🔥 Session Streak Tracker</h3>
        <button class="streak-close btn-sm" title="Close">✕</button>
      </div>
      <div class="streak-stats-row">
        <div class="streak-stat-card streak-stat-current">
          <div class="streak-stat-value">${info.current}</div>
          <div class="streak-stat-label">Current Streak</div>
        </div>
        <div class="streak-stat-card streak-stat-longest">
          <div class="streak-stat-value">${info.longest}</div>
          <div class="streak-stat-label">Longest Streak</div>
        </div>
        <div class="streak-stat-card streak-stat-total">
          <div class="streak-stat-value">${info.totalDays}</div>
          <div class="streak-stat-label">Active Days</div>
        </div>
      </div>
      <div class="streak-section">
        <h4>📅 Last 90 Days</h4>
        ${_buildCalendar(dateSet)}
      </div>
      <div class="streak-section">
        <h4>📊 Most Active Days</h4>
        ${_buildWeekdayStats(dateSet)}
      </div>
      <div class="streak-section">
        <h4>🏅 Milestones</h4>
        <div class="streak-milestones">${_buildMilestones(info.longest)}</div>
      </div>
    `;

    _overlay.appendChild(panel);
    document.body.appendChild(_overlay);
    _isOpen = true;

    panel.querySelector('.streak-close').addEventListener('click', close);
    _overlay.addEventListener('click', (e) => { if (e.target === _overlay) close(); });
    document.addEventListener('keydown', _onKey);
  }

  function _onKey(e) {
    if (e.key === 'Escape' && _isOpen) {
      e.preventDefault();
      close();
    }
  }

  function close() {
    if (_overlay) { _overlay.remove(); _overlay = null; }
    _isOpen = false;
    document.removeEventListener('keydown', _onKey);
  }

  function toggle() { _isOpen ? close() : open(); }
  function isOpen() { return _isOpen; }

  // Keyboard shortcut: Ctrl+Shift+K
  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey && e.shiftKey && e.key === 'K') {
      e.preventDefault();
      toggle();
    }
  });

  return {
    open, close, toggle, isOpen,
    _getActiveDates, _calcStreaks, _buildCalendar, _buildMilestones, _buildWeekdayStats,
    MILESTONES
  };
})();

/* ============================================================
 * DraftRecovery - auto-save unsent message drafts per session
 *
 * Saves the chat input text as you type (debounced 500ms) and
 * restores it when switching sessions or reloading the page.
 * Shows a subtle toast when a draft is recovered.
 *
 * Keyboard shortcut: Ctrl+Shift+D - discard current draft
 * ============================================================ */
const DraftRecovery = (() => {
  const STORAGE_KEY = 'agenticchat_drafts';
  const DEBOUNCE_MS = 500;
  let _timer = null;
  let _lastSavedText = '';
  let _toastEl = null;

  /** Load all drafts from storage. */
  function _loadDrafts() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      return _safeParse(raw, {});
    } catch { return {}; }
  }

  /** Save all drafts to storage. */
  function _saveDrafts(drafts) {
    SafeStorage.trySetJSON(STORAGE_KEY, drafts);
  }

  /** Get the current session ID (or '__default__' if none). */
  function _sessionId() {
    try {
      const id = SafeStorage.get('agenticchat_active_session');
      return id || '__default__';
    } catch { return '__default__'; }
  }

  /** Save the current input text as a draft. */
  function saveDraft() {
    const input = DOMCache.get('chat-input');
    if (!input) return;
    const text = input.value.trim();
    const sid = _sessionId();
    const drafts = _loadDrafts();

    if (text) {
      drafts[sid] = { text, ts: Date.now() };
    } else {
      delete drafts[sid];
    }
    _saveDrafts(drafts);
    _lastSavedText = text;
  }

  /** Restore draft for the current session. Returns true if recovered. */
  function restoreDraft() {
    const input = DOMCache.get('chat-input');
    if (!input) return false;
    const sid = _sessionId();
    const drafts = _loadDrafts();
    const draft = drafts[sid];

    if (draft && draft.text) {
      // Don't overwrite if user already typed something
      if (input.value.trim()) return false;
      input.value = draft.text;
      _lastSavedText = draft.text;
      _showToast(draft.ts);
      return true;
    }
    return false;
  }

  /** Clear draft for the current session. */
  function clearDraft() {
    const sid = _sessionId();
    const drafts = _loadDrafts();
    delete drafts[sid];
    _saveDrafts(drafts);
    _lastSavedText = '';
  }

  /** Discard draft and clear input. */
  function discardDraft() {
    const input = DOMCache.get('chat-input');
    if (input) input.value = '';
    clearDraft();
    _showDiscardToast();
  }

  /** Get draft for a specific session ID. */
  function getDraft(sessionId) {
    const drafts = _loadDrafts();
    return drafts[sessionId || _sessionId()] || null;
  }

  /** Get count of saved drafts. */
  function getDraftCount() {
    return Object.keys(_loadDrafts()).length;
  }

  /** Remove drafts older than maxAgeDays. */
  function pruneOldDrafts(maxAgeDays) {
    const cutoff = Date.now() - (maxAgeDays || 30) * 86400000;
    const drafts = _loadDrafts();
    let pruned = 0;
    for (const sid of Object.keys(drafts)) {
      if (drafts[sid].ts < cutoff) {
        delete drafts[sid];
        pruned++;
      }
    }
    if (pruned > 0) _saveDrafts(drafts);
    return pruned;
  }

  /** Show a subtle toast when a draft is recovered. */
  function _showToast(ts) {
    _removeToast();
    const age = _formatAge(ts);
    _toastEl = document.createElement('div');
    _toastEl.className = 'draft-toast';
    _toastEl.setAttribute('role', 'status');
    _toastEl.setAttribute('aria-live', 'polite');
    _toastEl.innerHTML = `📝 Draft recovered <span class="draft-toast-age">${age}</span> <button class="draft-toast-discard" title="Discard draft">✕</button>`;
    _toastEl.querySelector('.draft-toast-discard').addEventListener('click', () => {
      discardDraft();
      _removeToast();
    });
    document.body.appendChild(_toastEl);
    // Auto-dismiss after 4 seconds
    setTimeout(() => _removeToast(), 4000);
  }

  /** Show discard confirmation toast. */
  function _showDiscardToast() {
    _removeToast();
    _toastEl = document.createElement('div');
    _toastEl.className = 'draft-toast draft-toast-discard-confirm';
    _toastEl.setAttribute('role', 'status');
    _toastEl.textContent = '🗑️ Draft discarded';
    document.body.appendChild(_toastEl);
    setTimeout(() => _removeToast(), 2000);
  }

  function _removeToast() {
    if (_toastEl) { _toastEl.remove(); _toastEl = null; }
  }

  /** Format age as human-readable relative time. */
  function _formatAge(ts) { return formatRelativeTime(ts); }

  /** Debounced save handler for input events. */
  function _onInput() {
    if (_timer) clearTimeout(_timer);
    _timer = setTimeout(() => {
      const input = DOMCache.get('chat-input');
      if (input && input.value.trim() !== _lastSavedText) {
        saveDraft();
      }
    }, DEBOUNCE_MS);
  }

  /** Initialize - attach listeners and restore draft. */
  function load() {
    const input = DOMCache.get('chat-input');
    if (input) {
      input.addEventListener('input', _onInput);
    }

    // Clear draft when a message is sent (Enter key is handled by ChatController,
    // so we listen for the input being cleared after send)
    const sendBtn = DOMCache.get('send-btn');
    if (sendBtn) {
      sendBtn.addEventListener('click', () => {
        // Delay slightly so ChatController processes first
        setTimeout(() => {
          const inp = DOMCache.get('chat-input');
          if (inp && !inp.value.trim()) clearDraft();
        }, 100);
      });
    }

    // Prune old drafts on startup
    pruneOldDrafts(30);

    // Restore draft for current session
    restoreDraft();

    // Keyboard shortcut: Ctrl+Shift+D to discard
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'D') {
        e.preventDefault();
        discardDraft();
      }
    });
  }

  return {
    load, saveDraft, restoreDraft, clearDraft, discardDraft,
    getDraft, getDraftCount, pruneOldDrafts,
    _loadDrafts, _saveDrafts, _sessionId, _formatAge, _onInput
  };
})();

/* ---------- Custom Theme Creator ---------- */
/**
 * Interactive theme builder with live color pickers for all CSS variables,
 * preset themes, save/load custom themes, and import/export.
 *
 * Toggle: Ctrl+Shift+E or /theme-creator slash command.
 *
 * Extends ThemeManager with custom theme support. Custom themes are stored
 * in localStorage and applied via CSS custom properties.
 */
const CustomThemeCreator = (() => {
  const STORAGE_KEY = 'agenticchat_custom_themes';
  const ACTIVE_KEY = 'agenticchat_active_custom_theme';
  let panel = null;
  let isOpen = false;

  /* All CSS variables the theme system uses */
  const THEME_VARS = [
    { key: '--bg-primary',         label: 'Background Primary',    group: 'Background' },
    { key: '--bg-secondary',       label: 'Background Secondary',  group: 'Background' },
    { key: '--bg-blackbox',        label: 'Background Blackbox',   group: 'Background' },
    { key: '--bg-console',         label: 'Background Console',    group: 'Background' },
    { key: '--text-primary',       label: 'Text Primary',          group: 'Text' },
    { key: '--text-muted',         label: 'Text Muted',            group: 'Text' },
    { key: '--text-dim',           label: 'Text Dim',              group: 'Text' },
    { key: '--accent',             label: 'Accent',                group: 'Colors' },
    { key: '--accent-hover',       label: 'Accent Hover',          group: 'Colors' },
    { key: '--danger',             label: 'Danger',                group: 'Colors' },
    { key: '--success',            label: 'Success',               group: 'Colors' },
    { key: '--border',             label: 'Border',                group: 'Borders' },
    { key: '--border-box',         label: 'Border Box',            group: 'Borders' },
    { key: '--disabled-bg',        label: 'Disabled Background',   group: 'States' },
    { key: '--disabled-text',      label: 'Disabled Text',         group: 'States' },
    { key: '--msg-user-bg',        label: 'User Message BG',       group: 'Messages' },
    { key: '--msg-assistant-bg',   label: 'Assistant Message BG',  group: 'Messages' },
  ];

  /* Preset themes beyond dark/light */
  const PRESETS = {
    'Nord': {
      '--bg-primary': '#2e3440', '--bg-secondary': '#3b4252', '--bg-blackbox': '#272c36',
      '--bg-console': '#434c5e', '--text-primary': '#eceff4', '--text-muted': '#d8dee9',
      '--text-dim': '#7b88a1', '--accent': '#88c0d0', '--accent-hover': '#81a1c1',
      '--danger': '#bf616a', '--success': '#a3be8c', '--border': '#4c566a',
      '--border-box': '#434c5e', '--disabled-bg': '#4c566a', '--disabled-text': '#7b88a1',
      '--msg-user-bg': '#2e3a4d', '--msg-assistant-bg': '#2e3e2e',
    },
    'Solarized Dark': {
      '--bg-primary': '#002b36', '--bg-secondary': '#073642', '--bg-blackbox': '#001f27',
      '--bg-console': '#0a4050', '--text-primary': '#fdf6e3', '--text-muted': '#93a1a1',
      '--text-dim': '#586e75', '--accent': '#268bd2', '--accent-hover': '#2aa198',
      '--danger': '#dc322f', '--success': '#859900', '--border': '#586e75',
      '--border-box': '#073642', '--disabled-bg': '#586e75', '--disabled-text': '#657b83',
      '--msg-user-bg': '#0a3d5c', '--msg-assistant-bg': '#1a3a1a',
    },
    'Solarized Light': {
      '--bg-primary': '#fdf6e3', '--bg-secondary': '#eee8d5', '--bg-blackbox': '#f5efdc',
      '--bg-console': '#eee8d5', '--text-primary': '#073642', '--text-muted': '#586e75',
      '--text-dim': '#93a1a1', '--accent': '#268bd2', '--accent-hover': '#2aa198',
      '--danger': '#dc322f', '--success': '#859900', '--border': '#93a1a1',
      '--border-box': '#eee8d5', '--disabled-bg': '#d3cdb8', '--disabled-text': '#93a1a1',
      '--msg-user-bg': '#d4e6f1', '--msg-assistant-bg': '#d5f5d0',
    },
    'Monokai': {
      '--bg-primary': '#272822', '--bg-secondary': '#2e2f2a', '--bg-blackbox': '#1e1f1c',
      '--bg-console': '#3e3d32', '--text-primary': '#f8f8f2', '--text-muted': '#c0bfb4',
      '--text-dim': '#75715e', '--accent': '#66d9ef', '--accent-hover': '#a6e22e',
      '--danger': '#f92672', '--success': '#a6e22e', '--border': '#49483e',
      '--border-box': '#3e3d32', '--disabled-bg': '#49483e', '--disabled-text': '#75715e',
      '--msg-user-bg': '#2a3a4a', '--msg-assistant-bg': '#2a3e2a',
    },
    'Dracula': {
      '--bg-primary': '#282a36', '--bg-secondary': '#343746', '--bg-blackbox': '#21222c',
      '--bg-console': '#3c3f58', '--text-primary': '#f8f8f2', '--text-muted': '#bfbfbf',
      '--text-dim': '#6272a4', '--accent': '#bd93f9', '--accent-hover': '#ff79c6',
      '--danger': '#ff5555', '--success': '#50fa7b', '--border': '#6272a4',
      '--border-box': '#44475a', '--disabled-bg': '#44475a', '--disabled-text': '#6272a4',
      '--msg-user-bg': '#2e3350', '--msg-assistant-bg': '#253325',
    },
    'Gruvbox': {
      '--bg-primary': '#282828', '--bg-secondary': '#3c3836', '--bg-blackbox': '#1d2021',
      '--bg-console': '#504945', '--text-primary': '#ebdbb2', '--text-muted': '#bdae93',
      '--text-dim': '#7c6f64', '--accent': '#83a598', '--accent-hover': '#b8bb26',
      '--danger': '#fb4934', '--success': '#b8bb26', '--border': '#665c54',
      '--border-box': '#504945', '--disabled-bg': '#665c54', '--disabled-text': '#7c6f64',
      '--msg-user-bg': '#3c4a3c', '--msg-assistant-bg': '#3a3c2e',
    },
    'Catppuccin Mocha': {
      '--bg-primary': '#1e1e2e', '--bg-secondary': '#302d41', '--bg-blackbox': '#181825',
      '--bg-console': '#3b3850', '--text-primary': '#cdd6f4', '--text-muted': '#a6adc8',
      '--text-dim': '#6c7086', '--accent': '#89b4fa', '--accent-hover': '#cba6f7',
      '--danger': '#f38ba8', '--success': '#a6e3a1', '--border': '#585b70',
      '--border-box': '#45475a', '--disabled-bg': '#45475a', '--disabled-text': '#6c7086',
      '--msg-user-bg': '#2a3050', '--msg-assistant-bg': '#253528',
    },
    'High Contrast': {
      '--bg-primary': '#000000', '--bg-secondary': '#0a0a0a', '--bg-blackbox': '#000000',
      '--bg-console': '#111111', '--text-primary': '#ffffff', '--text-muted': '#e0e0e0',
      '--text-dim': '#999999', '--accent': '#00ffff', '--accent-hover': '#00cccc',
      '--danger': '#ff0000', '--success': '#00ff00', '--border': '#ffffff',
      '--border-box': '#666666', '--disabled-bg': '#333333', '--disabled-text': '#666666',
      '--msg-user-bg': '#001a33', '--msg-assistant-bg': '#001a00',
    },
  };

  function _loadCustomThemes() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      return _safeParse(raw, {});
    } catch (_) { return {}; }
  }

  function _saveCustomThemes(themes) {
    SafeStorage.trySetJSON(STORAGE_KEY, themes);
  }

  function _getActiveCustomTheme() {
    try { return SafeStorage.get(ACTIVE_KEY) || null; } catch (_) { return null; }
  }

  function _setActiveCustomTheme(name) {
    SafeStorage.trySet(ACTIVE_KEY, name || '');
  }

  function _getCurrentValues() {
    const vals = {};
    if (typeof document === 'undefined') return vals;
    const style = getComputedStyle(document.documentElement);
    THEME_VARS.forEach(v => {
      vals[v.key] = style.getPropertyValue(v.key).trim();
    });
    return vals;
  }

  // Validate that a CSS variable value looks like a safe color/font value.
  // Blocks url(), expression(), and other potentially dangerous CSS functions.
  // Also blocks backslash-escape bypasses (e.g. \75rl() decodes to url() in
  // CSS but would evade a naive regex), -moz-binding (historic Firefox XSS),
  // image-set/cross-fade/element (can reference external resources),
  // and raw backslashes which enable character-code escaping in CSS.
  const _UNSAFE_CSS_RE = /url\s*\(|expression\s*\(|javascript:|@import|behavior\s*:|-moz-binding\s*:|image-set\s*\(|cross-fade\s*\(|element\s*\(|\\/i;

  function _applyThemeValues(values) {
    if (typeof document === 'undefined') return;
    const root = document.documentElement;
    Object.entries(values).forEach(([key, val]) => {
      // Only apply CSS custom properties (--prefixed) with safe values
      if (typeof key !== 'string' || !key.startsWith('--')) return;
      if (typeof val !== 'string' || _UNSAFE_CSS_RE.test(val)) return;
      root.style.setProperty(key, val);
    });
  }

  function _clearCustomProperties() {
    if (typeof document === 'undefined') return;
    const root = document.documentElement;
    THEME_VARS.forEach(v => {
      root.style.removeProperty(v.key);
    });
  }

  /** Convert any CSS color to hex for the color picker */
  function _toHex(cssColor) {
    if (!cssColor) return '#000000';
    if (cssColor.startsWith('#') && (cssColor.length === 7 || cssColor.length === 4)) {
      if (cssColor.length === 4) {
        return '#' + cssColor[1]+cssColor[1] + cssColor[2]+cssColor[2] + cssColor[3]+cssColor[3];
      }
      return cssColor;
    }
    // Use canvas to resolve
    if (typeof document !== 'undefined') {
      const ctx = document.createElement('canvas').getContext('2d');
      ctx.fillStyle = cssColor;
      return ctx.fillStyle; // returns hex
    }
    return '#000000';
  }

  function toggle() {
    if (isOpen) { close(); } else { open(); }
    return isOpen;
  }

  function open() {
    if (isOpen && panel) return;
    isOpen = true;
    _buildPanel();
  }

  function close() {
    if (panel && panel.parentNode) panel.parentNode.removeChild(panel);
    panel = null;
    isOpen = false;
  }

  function _buildPanel() {
    if (panel && panel.parentNode) panel.parentNode.removeChild(panel);

    panel = document.createElement('div');
    panel.id = 'theme-creator-panel';
    panel.style.cssText = `
      position: fixed; top: 0; right: 0; bottom: 0; width: 360px; max-width: 90vw;
      background: var(--bg-secondary); color: var(--text-primary);
      border-left: 2px solid var(--accent); z-index: 100000;
      display: flex; flex-direction: column; font-family: system-ui, sans-serif;
      box-shadow: -4px 0 20px var(--shadow); overflow: hidden;
    `;

    /* Header */
    const header = document.createElement('div');
    header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;padding:12px 16px;border-bottom:1px solid var(--border);flex-shrink:0;';
    header.innerHTML = `<span style="font-weight:700;font-size:16px;">🎨 Theme Creator</span>`;
    const closeBtn = document.createElement('button');
    closeBtn.textContent = '✕';
    closeBtn.style.cssText = 'background:none;border:none;color:var(--text-primary);font-size:18px;cursor:pointer;padding:4px 8px;';
    closeBtn.onclick = close;
    header.appendChild(closeBtn);
    panel.appendChild(header);

    /* Toolbar: presets, save, import/export */
    const toolbar = document.createElement('div');
    toolbar.style.cssText = 'padding:8px 16px;border-bottom:1px solid var(--border);display:flex;flex-wrap:wrap;gap:6px;flex-shrink:0;';

    // Preset dropdown
    const presetSelect = document.createElement('select');
    presetSelect.style.cssText = 'flex:1;min-width:100px;padding:4px 8px;background:var(--bg-primary);color:var(--text-primary);border:1px solid var(--border);border-radius:4px;font-size:12px;';
    presetSelect.innerHTML = '<option value="">- Apply Preset -</option>';
    Object.keys(PRESETS).forEach(name => {
      presetSelect.innerHTML += `<option value="${name}">${name}</option>`;
    });
    // Add saved custom themes
    const customs = _loadCustomThemes();
    Object.keys(customs).forEach(name => {
      presetSelect.innerHTML += `<option value="custom:${_escapeHtml(name)}">★ ${_escapeHtml(name)}</option>`;
    });
    presetSelect.onchange = () => {
      const val = presetSelect.value;
      if (!val) return;
      if (val.startsWith('custom:')) {
        const name = val.slice(7);
        const themes = _loadCustomThemes();
        if (themes[name]) {
          _applyThemeValues(themes[name]);
          _setActiveCustomTheme(name);
          _refreshPickers();
        }
      } else if (PRESETS[val]) {
        _applyThemeValues(PRESETS[val]);
        _setActiveCustomTheme('');
        _refreshPickers();
      }
      presetSelect.value = '';
    };
    toolbar.appendChild(presetSelect);

    // Save button
    const saveBtn = document.createElement('button');
    saveBtn.textContent = '💾 Save';
    saveBtn.title = 'Save current colors as custom theme';
    saveBtn.style.cssText = 'padding:4px 10px;background:var(--accent);color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:12px;';
    saveBtn.onclick = () => _saveCurrentTheme();
    toolbar.appendChild(saveBtn);

    // Delete button
    const delBtn = document.createElement('button');
    delBtn.textContent = '🗑️';
    delBtn.title = 'Delete saved custom theme';
    delBtn.style.cssText = 'padding:4px 8px;background:var(--danger);color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:12px;';
    delBtn.onclick = () => _deleteThemePrompt();
    toolbar.appendChild(delBtn);

    // Export button
    const exportBtn = document.createElement('button');
    exportBtn.textContent = '📤';
    exportBtn.title = 'Export all custom themes as JSON';
    exportBtn.style.cssText = 'padding:4px 8px;background:var(--bg-primary);color:var(--text-primary);border:1px solid var(--border);border-radius:4px;cursor:pointer;font-size:12px;';
    exportBtn.onclick = _exportThemes;
    toolbar.appendChild(exportBtn);

    // Import button
    const importBtn = document.createElement('button');
    importBtn.textContent = '📥';
    importBtn.title = 'Import custom themes from JSON';
    importBtn.style.cssText = 'padding:4px 8px;background:var(--bg-primary);color:var(--text-primary);border:1px solid var(--border);border-radius:4px;cursor:pointer;font-size:12px;';
    importBtn.onclick = _importThemes;
    toolbar.appendChild(importBtn);

    // Reset button
    const resetBtn = document.createElement('button');
    resetBtn.textContent = '↺';
    resetBtn.title = 'Reset to default dark/light theme';
    resetBtn.style.cssText = 'padding:4px 8px;background:var(--bg-primary);color:var(--text-primary);border:1px solid var(--border);border-radius:4px;cursor:pointer;font-size:12px;';
    resetBtn.onclick = () => {
      _clearCustomProperties();
      _setActiveCustomTheme('');
      ThemeManager.setTheme(ThemeManager.getTheme());
      _refreshPickers();
    };
    toolbar.appendChild(resetBtn);

    panel.appendChild(toolbar);

    /* Color pickers area */
    const body = document.createElement('div');
    body.id = 'theme-creator-body';
    body.style.cssText = 'flex:1;overflow-y:auto;padding:12px 16px;';

    const groups = {};
    THEME_VARS.forEach(v => {
      if (!groups[v.group]) groups[v.group] = [];
      groups[v.group].push(v);
    });

    const currentVals = _getCurrentValues();

    Object.entries(groups).forEach(([groupName, vars]) => {
      const section = document.createElement('div');
      section.style.cssText = 'margin-bottom:16px;';
      const heading = document.createElement('div');
      heading.textContent = groupName;
      heading.style.cssText = 'font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--text-muted);margin-bottom:8px;';
      section.appendChild(heading);

      vars.forEach(v => {
        const row = document.createElement('div');
        row.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:6px;';

        const colorInput = document.createElement('input');
        colorInput.type = 'color';
        colorInput.value = _toHex(currentVals[v.key] || '#000000');
        colorInput.dataset.varKey = v.key;
        colorInput.className = 'theme-creator-picker';
        colorInput.style.cssText = 'width:32px;height:28px;border:1px solid var(--border);border-radius:4px;cursor:pointer;padding:0;background:none;';
        colorInput.oninput = (e) => {
          document.documentElement.style.setProperty(v.key, e.target.value);
          hexInput.value = e.target.value;
        };

        const label = document.createElement('span');
        label.textContent = v.label;
        label.style.cssText = 'flex:1;font-size:13px;';

        const hexInput = document.createElement('input');
        hexInput.type = 'text';
        hexInput.value = _toHex(currentVals[v.key] || '#000000');
        hexInput.dataset.varKey = v.key;
        hexInput.className = 'theme-creator-hex';
        hexInput.style.cssText = 'width:72px;padding:3px 6px;font-size:11px;font-family:monospace;background:var(--bg-primary);color:var(--text-primary);border:1px solid var(--border);border-radius:3px;';
        hexInput.onchange = (e) => {
          let val = e.target.value.trim();
          if (!val.startsWith('#')) val = '#' + val;
          if (/^#[0-9a-fA-F]{3,8}$/.test(val)) {
            document.documentElement.style.setProperty(v.key, val);
            colorInput.value = _toHex(val);
          }
        };

        row.appendChild(colorInput);
        row.appendChild(label);
        row.appendChild(hexInput);
        section.appendChild(row);
      });

      body.appendChild(section);
    });

    panel.appendChild(body);
    document.body.appendChild(panel);
  }

  function _refreshPickers() {
    if (!panel) return;
    const vals = _getCurrentValues();
    panel.querySelectorAll('.theme-creator-picker').forEach(input => {
      const key = input.dataset.varKey;
      if (vals[key]) input.value = _toHex(vals[key]);
    });
    panel.querySelectorAll('.theme-creator-hex').forEach(input => {
      const key = input.dataset.varKey;
      if (vals[key]) input.value = _toHex(vals[key]);
    });
  }

  function _saveCurrentTheme() {
    const raw = prompt('Theme name:');
    if (!raw || !raw.trim()) return;
    // Sanitize: strip control characters, limit length
    const name = raw.trim().replace(/[\x00-\x1f]/g, '').slice(0, 100);
    if (!name) return;
    const themes = _loadCustomThemes();
    themes[name] = _getCurrentValues();
    _saveCustomThemes(themes);
    _setActiveCustomTheme(name);
    if (typeof UIController !== 'undefined') {
      UIController.setChatOutput(`Custom theme "${name}" saved! 🎨`);
    }
    // Rebuild panel to refresh preset list
    _buildPanel();
  }

  function _deleteThemePrompt() {
    const themes = _loadCustomThemes();
    const names = Object.keys(themes);
    if (names.length === 0) {
      alert('No custom themes saved.');
      return;
    }
    const name = prompt('Delete which theme?\n\n' + names.join('\n'));
    if (!name || !themes[name]) return;
    delete themes[name];
    _saveCustomThemes(themes);
    const active = _getActiveCustomTheme();
    if (active === name) _setActiveCustomTheme('');
    if (typeof UIController !== 'undefined') {
      UIController.setChatOutput(`Custom theme "${name}" deleted.`);
    }
    _buildPanel();
  }

  function _exportThemes() {
    const themes = _loadCustomThemes();
    if (Object.keys(themes).length === 0) {
      alert('No custom themes to export.');
      return;
    }
    const json = JSON.stringify(themes, null, 2);
    downloadBlob('agenticchat-themes.json', json, 'application/json');
  }

  function _importThemes() {
    const input = document.createElement('input');
    input.type = 'file'; input.accept = '.json';
    input.onchange = () => {
      const file = input.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const imported = _safeParse(e.target.result);
          if (typeof imported !== 'object' || Array.isArray(imported)) {
            alert('Invalid theme file format.');
            return;
          }
          const existing = _loadCustomThemes();
          let count = 0;
          Object.entries(imported).forEach(([name, vars]) => {
            if (typeof vars === 'object' && !Array.isArray(vars)) {
              // Sanitize theme name: limit length, strip control characters
              const safeName = String(name).replace(/[\x00-\x1f]/g, '').slice(0, 100);
              if (!safeName) return;
              existing[safeName] = vars;
              count++;
            }
          });
          _saveCustomThemes(existing);
          if (typeof UIController !== 'undefined') {
            UIController.setChatOutput(`Imported ${count} custom theme${count !== 1 ? 's' : ''}! 🎨`);
          }
          _buildPanel();
        } catch (err) {
          alert('Error parsing theme file: ' + err.message);
        }
      };
      reader.readAsText(file);
    };
    input.click();
  }

  /** Apply saved custom theme on startup */
  function init() {
    const activeName = _getActiveCustomTheme();
    if (activeName) {
      const themes = _loadCustomThemes();
      if (themes[activeName]) {
        _applyThemeValues(themes[activeName]);
      }
    }

    // Keyboard shortcut: Ctrl+Shift+E
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'E') {
        e.preventDefault();
        toggle();
      }
    });
  }

  /** Get list of all available themes (built-in presets + custom) */
  function getAvailableThemes() {
    const result = { presets: Object.keys(PRESETS), custom: Object.keys(_loadCustomThemes()) };
    return result;
  }

  /** Apply a preset by name */
  function applyPreset(name) {
    if (PRESETS[name]) {
      _applyThemeValues(PRESETS[name]);
      _setActiveCustomTheme('');
      return true;
    }
    return false;
  }

  /** Apply a saved custom theme by name */
  function applyCustom(name) {
    const themes = _loadCustomThemes();
    if (themes[name]) {
      _applyThemeValues(themes[name]);
      _setActiveCustomTheme(name);
      return true;
    }
    return false;
  }

  return {
    init, toggle, open, close,
    getAvailableThemes, applyPreset, applyCustom,
    PRESETS, THEME_VARS,
    _loadCustomThemes, _saveCustomThemes, _getCurrentValues,
    _applyThemeValues, _toHex, _getActiveCustomTheme, _setActiveCustomTheme
  };
})();

document.addEventListener('DOMContentLoaded', CustomThemeCreator.init);

/* ============================================================
 * TextExpander - auto-expanding text shortcuts in chat input.
 *
 * Users define trigger → expansion pairs (e.g. "/sig" → full signature).
 * Triggers expand automatically when followed by Space or Tab.
 * Built-in dynamic expansions: /date, /time, /now, /shrug.
 * Manage snippets via panel (Ctrl+Shift+X): add, edit, delete,
 * import/export JSON, search, usage tracking.
 *
 * @namespace TextExpander
 * ============================================================ */
const TextExpander = (() => {
  const STORAGE_KEY = 'agenticchat_text_expander';
  const USAGE_KEY = 'agenticchat_text_expander_usage';
  let _overlay = null;
  let _panel = null;
  let _visible = false;

  /* --- Built-in dynamic expansions --- */
  const BUILTINS = {
    '/date': () => new Date().toLocaleDateString(),
    '/time': () => new Date().toLocaleTimeString(),
    '/now':  () => new Date().toLocaleString(),
    '/shrug': () => '¯\\_(ツ)_/¯',
    '/tableflip': () => '(╯°□°)╯︵ ┻━┻',
    '/lenny': () => '( ͡° ͜ʖ ͡°)',
  };

  /* --- Storage helpers --- */
  function _load() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      return _safeParse(raw, {});
    } catch { return {}; }
  }

  function _save(snippets) {
    SafeStorage.trySetJSON(STORAGE_KEY, snippets);
  }

  function _loadUsage() {
    try {
      const raw = SafeStorage.get(USAGE_KEY);
      return _safeParse(raw, {});
    } catch { return {}; }
  }

  function _saveUsage(usage) {
    SafeStorage.trySetJSON(USAGE_KEY, usage);
  }

  function _trackUsage(trigger) {
    const usage = _loadUsage();
    usage[trigger] = (usage[trigger] || 0) + 1;
    _saveUsage(usage);
  }

  /* --- Core expansion --- */

  /** Get expansion for a trigger. Returns string or null. */
  function getExpansion(trigger) {
    if (BUILTINS[trigger]) return BUILTINS[trigger]();
    const snippets = _load();
    return snippets[trigger] || null;
  }

  /** Get all triggers (user + builtin). */
  function getAllTriggers() {
    const snippets = _load();
    return [...new Set([...Object.keys(snippets), ...Object.keys(BUILTINS)])];
  }

  /** Add or update a user snippet. */
  function set(trigger, expansion) {
    if (!trigger || !expansion) return false;
    const t = trigger.startsWith('/') ? trigger : '/' + trigger;
    if (BUILTINS[t]) return false; // can't override builtins
    const snippets = _load();
    snippets[t] = expansion;
    _save(snippets);
    return true;
  }

  /** Remove a user snippet. */
  function remove(trigger) {
    const snippets = _load();
    if (!snippets[trigger]) return false;
    delete snippets[trigger];
    _save(snippets);
    return true;
  }

  /** Get user snippets (not builtins). */
  function getUserSnippets() {
    return _load();
  }

  /** Get usage stats. */
  function getUsage() {
    return _loadUsage();
  }

  /** Export all user snippets as JSON string. */
  function exportJSON() {
    return JSON.stringify(_load(), null, 2);
  }

  /** Import snippets from JSON string. Returns count imported. */
  function importJSON(jsonStr) {
    try {
      const data = _safeParse(jsonStr);
      if (typeof data !== 'object' || Array.isArray(data)) return 0;
      const snippets = _load();
      let count = 0;
      for (const [k, v] of Object.entries(data)) {
        if (typeof v === 'string' && v.trim()) {
          const t = k.startsWith('/') ? k : '/' + k;
          if (!BUILTINS[t]) {
            snippets[t] = v;
            count++;
          }
        }
      }
      _save(snippets);
      return count;
    } catch { return 0; }
  }

  /** Clear all user snippets. */
  function clearAll() {
    _save({});
  }

  /** Clear usage stats. */
  function clearUsage() {
    _saveUsage({});
  }

  /* --- Input handler (auto-expand on Space/Tab) --- */
  function _handleInput(e) {
    if (e.key !== ' ' && e.key !== 'Tab') return;
    const input = e.target;
    if (input.id !== 'chat-input') return;

    const cursorPos = input.selectionStart;
    const text = input.value.substring(0, cursorPos);
    // Find last word (trigger candidate)
    const match = text.match(/(\/\S+)$/);
    if (!match) return;

    const trigger = match[1];
    const expansion = getExpansion(trigger);
    if (!expansion) return;

    e.preventDefault();
    const before = text.substring(0, text.length - trigger.length);
    const after = input.value.substring(cursorPos);
    const suffix = e.key === ' ' ? ' ' : '';
    input.value = before + expansion + suffix + after;
    const newPos = before.length + expansion.length + suffix.length;
    input.selectionStart = input.selectionEnd = newPos;
    _trackUsage(trigger);

    // Dispatch input event for other listeners
    input.dispatchEvent(new Event('input', { bubbles: true }));
  }

  /* --- Panel UI --- */
  function _buildPanel() {
    const snippets = _load();
    const usage = _loadUsage();
    const allTriggers = [...Object.entries(snippets), ...Object.entries(BUILTINS).map(([k]) => [k, null])];

    let rows = '';
    for (const [trigger, expansion] of allTriggers) {
      const isBuiltin = !!BUILTINS[trigger];
      const display = isBuiltin ? BUILTINS[trigger]() : expansion;
      const usageCount = usage[trigger] || 0;
      const escapedExpansion = (display || '').replace(/</g, '&lt;').replace(/"/g, '&quot;');
      const escapedTrigger = trigger.replace(/</g, '&lt;');
      rows += `<tr class="te-row${isBuiltin ? ' te-builtin' : ''}">
        <td class="te-trigger"><code>${escapedTrigger}</code></td>
        <td class="te-expansion" title="${escapedExpansion}">${escapedExpansion.length > 60 ? escapedExpansion.substring(0, 57) + '...' : escapedExpansion}</td>
        <td class="te-usage">${usageCount}</td>
        <td class="te-actions">${isBuiltin ? '<span class="te-builtin-badge">built-in</span>' : `<button class="te-edit-btn" data-trigger="${escapedTrigger}">✏️</button><button class="te-del-btn" data-trigger="${escapedTrigger}">🗑️</button>`}</td>
      </tr>`;
    }

    if (!allTriggers.length) {
      rows = '<tr><td colspan="4" style="text-align:center;color:var(--muted,#6c7086);padding:24px;">No snippets yet. Add one below!</td></tr>';
    }

    _panel.innerHTML = `
      <div class="te-header">
        <h3>⚡ Text Expander</h3>
        <button class="te-close" aria-label="Close">✕</button>
      </div>
      <p class="te-desc">Type a trigger in chat and press <kbd>Space</kbd> or <kbd>Tab</kbd> to expand it.</p>
      <div class="te-search-row">
        <input type="text" class="te-search" placeholder="Search snippets..." />
      </div>
      <div class="te-table-wrap">
        <table class="te-table">
          <thead><tr><th>Trigger</th><th>Expansion</th><th>Used</th><th></th></tr></thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
      <div class="te-add-section">
        <h4>Add Snippet</h4>
        <div class="te-add-row">
          <input type="text" class="te-add-trigger" placeholder="/trigger" />
          <input type="text" class="te-add-expansion" placeholder="Expansion text..." />
          <button class="te-add-btn">Add</button>
        </div>
      </div>
      <div class="te-footer">
        <button class="te-export-btn">📤 Export</button>
        <button class="te-import-btn">📥 Import</button>
        <span class="te-count">${Object.keys(snippets).length} custom · ${Object.keys(BUILTINS).length} built-in</span>
      </div>
    `;

    // Event listeners
    _panel.querySelector('.te-close').addEventListener('click', close);
    _panel.querySelector('.te-add-btn').addEventListener('click', _handleAdd);
    _panel.querySelector('.te-export-btn').addEventListener('click', _handleExport);
    _panel.querySelector('.te-import-btn').addEventListener('click', _handleImport);
    _panel.querySelector('.te-search').addEventListener('input', _handleSearch);

    _panel.querySelectorAll('.te-del-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        const t = btn.dataset.trigger;
        if (remove(t)) _buildPanel();
      });
    });

    _panel.querySelectorAll('.te-edit-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        const t = btn.dataset.trigger;
        const snippets = _load();
        const newVal = prompt('Edit expansion for ' + t + ':', snippets[t] || '');
        if (newVal !== null && newVal.trim()) {
          set(t, newVal.trim());
          _buildPanel();
        }
      });
    });

    // Enter key in add fields
    const addTrigger = _panel.querySelector('.te-add-trigger');
    const addExpansion = _panel.querySelector('.te-add-expansion');
    [addTrigger, addExpansion].forEach(el => {
      el.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') _handleAdd();
      });
    });
  }

  function _handleAdd() {
    const triggerInput = _panel.querySelector('.te-add-trigger');
    const expansionInput = _panel.querySelector('.te-add-expansion');
    const t = triggerInput.value.trim();
    const exp = expansionInput.value.trim();
    if (!t || !exp) return;
    if (set(t, exp)) {
      _buildPanel();
    }
  }

  function _handleSearch(e) {
    const q = e.target.value.toLowerCase();
    _panel.querySelectorAll('.te-row').forEach(row => {
      const trigger = row.querySelector('.te-trigger')?.textContent?.toLowerCase() || '';
      const expansion = row.querySelector('.te-expansion')?.textContent?.toLowerCase() || '';
      row.style.display = (!q || trigger.includes(q) || expansion.includes(q)) ? '' : 'none';
    });
  }

  function _handleExport() {
    downloadBlob('text-expander-snippets.json', exportJSON(), 'application/json');
  }

  function _handleImport() {
    const input = document.createElement('input');
    input.type = 'file'; input.accept = '.json';
    input.onchange = (e) => {
      const file = e.target.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (ev) => {
        const count = importJSON(ev.target.result);
        if (typeof UIController !== 'undefined') {
          UIController.setChatOutput(`Imported ${count} text expander snippet${count !== 1 ? 's' : ''}! ⚡`);
        }
        _buildPanel();
      };
      reader.readAsText(file);
    };
    input.click();
  }

  /* --- Toggle / Open / Close --- */
  function toggle() { _visible ? close() : open(); }

  function open() {
    if (!_overlay) _createOverlay();
    _buildPanel();
    _overlay.classList.add('te-visible');
    _visible = true;
  }

  function close() {
    if (_overlay) _overlay.classList.remove('te-visible');
    _visible = false;
  }

  function _createOverlay() {
    const pair = _makeOverlayPair('te-overlay', 'te-panel', close);
    _overlay = pair.overlay;
    _panel = pair.panel;
  }

  /* --- Init --- */
  function init() {
    document.addEventListener('keydown', _handleInput, true);

    // Ctrl+Shift+X shortcut
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'X') {
        e.preventDefault();
        toggle();
      }
    });
  }

  return {
    init, toggle, open, close,
    getExpansion, getAllTriggers,
    set, remove, getUserSnippets,
    getUsage, clearUsage,
    exportJSON, importJSON, clearAll,
    BUILTINS,
    _load, _save, _loadUsage, _saveUsage, _trackUsage, _handleInput
  };
})();

document.addEventListener('DOMContentLoaded', TextExpander.init);

/* ---------- Preferences Panel (module 57) ---------- */
/**
 * Centralised settings panel for configuring app behaviour.
 * Consolidates scattered settings into one discoverable UI.
 * Toggle via Ctrl+, or /preferences slash command or ⚙️ button.
 *
 * @namespace PreferencesPanel
 */
const PreferencesPanel = (() => {
  let _overlay = null;
  let _panel = null;
  let _isOpen = false;

  const STORAGE_KEY = 'ac-preferences';

  const DEFAULTS = Object.freeze({
    autoSave: true,
    maxHistoryPairs: 20,
    maxInputChars: 50000,
    streaming: true,
    sandboxTimeoutMs: 30000,
    fontSize: 14,
    messageSounds: false,
    compactMode: false,
    codeLineNumbers: false,
    timestampFormat: '12h'  // '12h' or '24h'
  });

  let _prefs = { ...DEFAULTS };

  function _load() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      if (raw) {
        const parsed = _safeParse(raw);
        if (parsed && typeof parsed === 'object') {
          Object.assign(_prefs, parsed);
        }
      }
    } catch (_) { /* use defaults */ }
  }

  function _save() {
    SafeStorage.trySetJSON(STORAGE_KEY, _prefs);
  }

  /** Apply preferences to the running config. */
  function _apply() {
    ChatConfig.MAX_HISTORY_PAIRS = _prefs.maxHistoryPairs;
    ChatConfig.MAX_INPUT_CHARS = _prefs.maxInputChars;
    ChatConfig.STREAMING_ENABLED = _prefs.streaming;
    ChatConfig.SANDBOX_TIMEOUT_MS = _prefs.sandboxTimeoutMs;
    SafeStorage.trySetJSON('ac-streaming', _prefs.streaming);
    document.documentElement.style.setProperty('--ac-font-size', _prefs.fontSize + 'px');
    document.body.classList.toggle('ac-compact', _prefs.compactMode);
  }

  function _row(label, desc, inputHTML) {
    return `<div class="pref-row">
      <div class="pref-label">
        <strong>${label}</strong>
        <small>${desc}</small>
      </div>
      <div class="pref-control">${inputHTML}</div>
    </div>`;
  }

  function _buildPanel() {
    if (!_panel) return;
    _panel.innerHTML = `
      <div class="pref-header">
        <span>⚙️ Preferences</span>
        <button class="btn-sm pref-close" title="Close (Escape)">✕</button>
      </div>
      <div class="pref-body">
        <div class="pref-section">
          <h4>💬 Chat</h4>
          ${_row('Streaming', 'Stream responses token-by-token',
            `<label class="pref-toggle"><input type="checkbox" id="pref-streaming" ${_prefs.streaming ? 'checked' : ''}><span class="pref-slider"></span></label>`)}
          ${_row('Auto-save', 'Automatically save sessions after each message',
            `<label class="pref-toggle"><input type="checkbox" id="pref-autosave" ${_prefs.autoSave ? 'checked' : ''}><span class="pref-slider"></span></label>`)}
          ${_row('History pairs', 'Max user+assistant exchanges to keep (1-50)',
            `<input type="number" id="pref-history" min="1" max="50" value="${_prefs.maxHistoryPairs}" class="pref-number">`)}
          ${_row('Max input chars', 'Character limit for input field',
            `<input type="number" id="pref-maxinput" min="1000" max="200000" step="1000" value="${_prefs.maxInputChars}" class="pref-number">`)}
        </div>
        <div class="pref-section">
          <h4>🎨 Appearance</h4>
          ${_row('Font size', 'Base font size in pixels (10-24)',
            `<input type="range" id="pref-fontsize" min="10" max="24" value="${_prefs.fontSize}" class="pref-range"><span id="pref-fontsize-val">${_prefs.fontSize}px</span>`)}
          ${_row('Compact mode', 'Reduce padding and spacing',
            `<label class="pref-toggle"><input type="checkbox" id="pref-compact" ${_prefs.compactMode ? 'checked' : ''}><span class="pref-slider"></span></label>`)}
          ${_row('Timestamp format', '12-hour or 24-hour clock',
            `<select id="pref-timestamp" class="pref-select"><option value="12h" ${_prefs.timestampFormat === '12h' ? 'selected' : ''}>12h (3:45 PM)</option><option value="24h" ${_prefs.timestampFormat === '24h' ? 'selected' : ''}>24h (15:45)</option></select>`)}
        </div>
        <div class="pref-section">
          <h4>🔧 Advanced</h4>
          ${_row('Sandbox timeout', 'Code execution timeout in seconds',
            `<input type="number" id="pref-timeout" min="5" max="120" value="${Math.round(_prefs.sandboxTimeoutMs / 1000)}" class="pref-number">`)}
          ${_row('Notification sounds', 'Play sound on response complete',
            `<label class="pref-toggle"><input type="checkbox" id="pref-sounds" ${_prefs.messageSounds ? 'checked' : ''}><span class="pref-slider"></span></label>`)}
          ${_row('Code line numbers', 'Show line numbers in code blocks',
            `<label class="pref-toggle"><input type="checkbox" id="pref-linenums" ${_prefs.codeLineNumbers ? 'checked' : ''}><span class="pref-slider"></span></label>`)}
        </div>
        <div class="pref-actions">
          <button id="pref-reset" class="btn-sm btn-danger" title="Reset all preferences to defaults">Reset to defaults</button>
          <span class="pref-saved-msg" id="pref-saved" style="display:none">✓ Saved</span>
        </div>
      </div>
    `;

    // Wire up events
    _panel.querySelector('.pref-close').addEventListener('click', close);

    // Checkboxes
    const wire = (id, key) => {
      const el = _panel.querySelector('#' + id);
      if (el) el.addEventListener('change', () => { _prefs[key] = el.checked; _saveAndApply(); });
    };
    wire('pref-streaming', 'streaming');
    wire('pref-autosave', 'autoSave');
    wire('pref-compact', 'compactMode');
    wire('pref-sounds', 'messageSounds');
    wire('pref-linenums', 'codeLineNumbers');

    // Number inputs
    const wireNum = (id, key, transform) => {
      const el = _panel.querySelector('#' + id);
      if (el) el.addEventListener('change', () => {
        const v = parseInt(el.value, 10);
        if (!isNaN(v)) { _prefs[key] = transform ? transform(v) : v; _saveAndApply(); }
      });
    };
    wireNum('pref-history', 'maxHistoryPairs');
    wireNum('pref-maxinput', 'maxInputChars');
    wireNum('pref-timeout', 'sandboxTimeoutMs', v => v * 1000);

    // Range (font size)
    const fontRange = _panel.querySelector('#pref-fontsize');
    const fontVal = _panel.querySelector('#pref-fontsize-val');
    if (fontRange) fontRange.addEventListener('input', () => {
      const v = parseInt(fontRange.value, 10);
      if (fontVal) fontVal.textContent = v + 'px';
      _prefs.fontSize = v;
      _saveAndApply();
    });

    // Select (timestamp format)
    const tsSelect = _panel.querySelector('#pref-timestamp');
    if (tsSelect) tsSelect.addEventListener('change', () => {
      _prefs.timestampFormat = tsSelect.value;
      _saveAndApply();
    });

    // Reset button
    const resetBtn = _panel.querySelector('#pref-reset');
    if (resetBtn) resetBtn.addEventListener('click', () => {
      if (confirm('Reset all preferences to defaults?')) {
        Object.assign(_prefs, DEFAULTS);
        _saveAndApply();
        _buildPanel(); // re-render with defaults
      }
    });
  }

  function _saveAndApply() {
    _save();
    _apply();
    // Flash saved indicator
    const msg = _panel && _panel.querySelector('#pref-saved');
    if (msg) {
      msg.style.display = 'inline';
      clearTimeout(msg._t);
      msg._t = setTimeout(() => { msg.style.display = 'none'; }, 1500);
    }
  }

  function _createOverlay() {
    const pair = _makeOverlayPair('pref-overlay', 'pref-panel', close);
    _overlay = pair.overlay;
    _panel = pair.panel;
  }

  function toggle() { _isOpen ? close() : open(); }

  function open() {
    if (!_overlay) _createOverlay();
    _buildPanel();
    _overlay.classList.add('pref-visible');
    _isOpen = true;
  }

  function close() {
    if (_overlay) _overlay.classList.remove('pref-visible');
    _isOpen = false;
  }

  /** Get a preference value by key. */
  function get(key) { return _prefs[key]; }

  function init() {
    _load();
    _apply();

    // Ctrl+, shortcut
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.key === ',') {
        e.preventDefault();
        toggle();
      }
    });

    // Button
    const btn = DOMCache.get('preferences-btn');
    if (btn) btn.addEventListener('click', toggle);
  }

  return { init, toggle, open, close, get, _prefs, DEFAULTS };
})();

document.addEventListener('DOMContentLoaded', PreferencesPanel.init);

/* ---------- Smart Title Generator ---------- */
/**
 * Generates concise, descriptive session titles from conversation content
 * using heuristic text analysis (no LLM call). Extracts key topics,
 * programming languages, and question types to produce human-readable
 * titles like "Python Sorting Algorithm Help" instead of truncated first messages.
 *
 * Public API:
 *   SmartTitle.generate(messages?)  → string title
 *   SmartTitle.init()               → wire up suggest button
 */
const SmartTitle = (() => {
  /* ── Title cache — avoid re-running 36 regexes on every auto-save ── */
  let _cachedTitle = null;
  let _cachedMsgCount = -1;
  let _cachedLastContent = '';

  /* ── Stop words — extends shared COMMON_STOP_WORDS with code/chat terms ── */
  const STOP_WORDS = new Set([...COMMON_STOP_WORDS,
    'code', 'data', 'function', 'year', 'cannot',
    'doing', 'done', 'getting', 'said', 'went', 'going',
    'feel', 'kind', 'pretty', 'quite', 'maybe',
    'someone', 'anyone', 'everyone', 'already', 'always', 'never', 'often',
    'came', 'goes', 'gone', 'part', 'place', 'point', 'write',
    'dont', 'doesnt', 'cant', 'wont', 'im', 'ive', 'id',
    'youre', 'youve', 'youd', 'hes', 'shes',
    'theyre', 'theyve', 'theyd', 'weve', 'wed',
    'thats', 'whats', 'hows', 'whys', 'wheres', 'whos',
    'while', 'whose', 'else',
    // Programming-specific stop words
    'question', 'problem', 'issue', 'error', 'message', 'result',
    'output', 'input', 'file', 'line', 'number', 'string', 'value',
    'type', 'name', 'list', 'array', 'object', 'class', 'method',
    'variable', 'return', 'true', 'false', 'null', 'undefined',
    'const', 'let', 'var', 'def', 'import', 'print',
  ]);

  /* ── Programming language detection ───────────────────────── */
  const LANG_PATTERNS = [
    { lang: 'Python', re: /\b(python|pandas|numpy|django|flask|pip|pytest|scipy|matplotlib|pytorch|tensorflow)\b/i },
    { lang: 'JavaScript', re: /\b(javascript|js|node\.?js|react|vue|angular|express|npm|typescript|ts|webpack|nextjs|next\.js)\b/i },
    { lang: 'Java', re: /\b(java(?!script)|spring|maven|gradle|jvm|junit|hibernate)\b/i },
    { lang: 'C\+\+', re: /\b(c\+\+|cpp|cmake|stl|boost|gcc|clang)\b/i },
    { lang: 'C#', re: /\b(c#|csharp|dotnet|\.net|asp\.net|blazor|unity)\b/i },
    { lang: 'Rust', re: /\b(rust|cargo|rustc|tokio|serde)\b/i },
    { lang: 'Go', re: /\b(golang|go\s+(?:module|routine|func))\b/i },
    { lang: 'SQL', re: /\b(sql|mysql|postgres|sqlite|database|query|select\s+from|insert\s+into)\b/i },
    { lang: 'HTML\/CSS', re: /\b(html|css|scss|sass|tailwind|bootstrap|flexbox|grid\s+layout)\b/i },
    { lang: 'Ruby', re: /\b(ruby|rails|gem|bundler|rake)\b/i },
    { lang: 'Swift', re: /\b(swift|swiftui|xcode|ios\s+app|uikit)\b/i },
    { lang: 'Kotlin', re: /\b(kotlin|android\s+studio|jetpack\s+compose)\b/i },
    { lang: 'PHP', re: /\b(php|laravel|composer|wordpress|symfony)\b/i },
    { lang: 'Shell', re: /\b(bash|shell|zsh|powershell|terminal|command\s+line|cli)\b/i },
  ];

  /* ── Topic/domain keywords ────────────────────────────────── */
  const TOPIC_PATTERNS = [
    { topic: 'API', re: /\b(api|rest|graphql|endpoint|webhook|http|request|response|fetch|axios)\b/i },
    { topic: 'Algorithm', re: /\b(algorithm|sort|search|binary|tree|graph|dynamic\s+programming|recursion|bfs|dfs|hash)\b/i },
    { topic: 'Testing', re: /\b(test|testing|unit\s+test|integration\s+test|mock|assert|coverage|tdd|jest|mocha)\b/i },
    { topic: 'Debugging', re: /\b(debug|bug|fix|error|exception|traceback|stack\s+trace|breakpoint)\b/i },
    { topic: 'Database', re: /\b(database|db|schema|migration|orm|model|table|index|query|join)\b/i },
    { topic: 'DevOps', re: /\b(docker|kubernetes|ci\/cd|deploy|pipeline|jenkins|github\s+actions|terraform|aws|azure|gcp)\b/i },
    { topic: 'Security', re: /\b(security|auth|authentication|authorization|oauth|jwt|encrypt|ssl|csrf|xss|vulnerability)\b/i },
    { topic: 'UI\/UX', re: /\b(ui|ux|design|layout|responsive|animation|component|modal|form|button|styling)\b/i },
    { topic: 'Machine Learning', re: /\b(machine\s+learning|ml|neural|deep\s+learning|model\s+training|classification|regression|nlp|llm|gpt|transformer)\b/i },
    { topic: 'Performance', re: /\b(performance|optimize|optimization|cache|memory|latency|profil|benchmark|speed)\b/i },
    { topic: 'Architecture', re: /\b(architecture|design\s+pattern|microservice|monolith|mvc|clean\s+code|solid|refactor)\b/i },
    { topic: 'Math', re: /\b(math|equation|formula|calculus|algebra|statistics|probability|matrix|vector|integral)\b/i },
    { topic: 'Writing', re: /\b(write|writing|essay|article|blog|story|poem|letter|email\s+draft|content)\b/i },
    { topic: 'Data Analysis', re: /\b(data\s+analysis|visualization|chart|plot|csv|excel|dashboard|report|analytics)\b/i },
  ];

  /* ── Action verbs that describe what the conversation is about ── */
  const ACTION_PATTERNS = [
    { action: 'Setup', re: /\b(setup|install|configure|initialization|getting\s+started|scaffold)\b/i },
    { action: 'Migration', re: /\b(migrat|upgrad|convert|port|transition)\b/i },
    { action: 'Comparison', re: /\b(compar|vs\.?|versus|difference|which\s+is\s+better|pros\s+and\s+cons)\b/i },
    { action: 'Tutorial', re: /\b(tutorial|how\s+to|step\s+by\s+step|guide|walkthrough|learn)\b/i },
    { action: 'Review', re: /\b(review|feedback|critique|improve|suggestion|refactor)\b/i },
    { action: 'Troubleshooting', re: /\b(troubleshoot|not\s+working|broken|fail|crash|issue|problem|stuck)\b/i },
    { action: 'Explanation', re: /\b(explain|what\s+is|what\s+are|how\s+does|why\s+does|concept|understand)\b/i },
    { action: 'Implementation', re: /\b(implement|build|create|develop|make|code\s+for|program|construct)\b/i },
  ];

  /**
   * Extract significant words from text (lowercased, deduplicated, no stop words).
   */
  function _extractKeywords(text, maxWords) {
    const words = text.toLowerCase().replace(/[^a-z0-9\s\-\_\.\/\+\#]/g, ' ').split(/\s+/);
    const freq = {};
    for (const w of words) {
      if (w.length < 2 || STOP_WORDS.has(w) || /^\d+$/.test(w)) continue;
      freq[w] = (freq[w] || 0) + 1;
    }
    return Object.entries(freq)
      .sort((a, b) => b[1] - a[1])
      .slice(0, maxWords || 10)
      .map(e => e[0]);
  }

  /**
   * Capitalize a word (first letter uppercase).
   */
  function _capitalize(w) {
    if (!w) return '';
    return w.charAt(0).toUpperCase() + w.slice(1);
  }

  /**
   * Generate a smart title from conversation messages.
   * @param {Array} [messages] - Array of {role, content}. Defaults to current conversation.
   * @returns {string} Generated title (3-8 words).
   */
  function generate(messages) {
    const msgs = messages || ConversationManager.getUserMessages();
    if (!msgs || msgs.length === 0) return 'Empty Conversation';

    // Cache: skip expensive regex analysis if messages haven't changed.
    // Check message count + last message content as a cheap fingerprint.
    const lastContent = msgs.length > 0 ? (msgs[msgs.length - 1].content || '') : '';
    if (_cachedTitle && msgs.length === _cachedMsgCount && lastContent === _cachedLastContent) {
      return _cachedTitle;
    }

    // Combine all text
    const allText = msgs.map(m => m.content || '').join(' ');
    if (allText.trim().length === 0) return 'Empty Conversation';

    // Detect programming language
    let detectedLang = null;
    for (const lp of LANG_PATTERNS) {
      if (lp.re.test(allText)) { detectedLang = lp.lang; break; }
    }

    // Detect topics (up to 2)
    const detectedTopics = [];
    for (const tp of TOPIC_PATTERNS) {
      if (tp.re.test(allText)) {
        detectedTopics.push(tp.topic);
        if (detectedTopics.length >= 2) break;
      }
    }

    // Detect action type
    let detectedAction = null;
    for (const ap of ACTION_PATTERNS) {
      if (ap.re.test(allText)) { detectedAction = ap.action; break; }
    }

    // Extract top keywords
    const keywords = _extractKeywords(allText, 8);

    // Build title parts
    const parts = [];

    if (detectedLang) parts.push(detectedLang);
    if (detectedTopics.length > 0) parts.push(detectedTopics[0]);
    if (detectedTopics.length > 1 && parts.length < 4) parts.push(detectedTopics[1]);
    if (detectedAction && parts.length < 4) parts.push(detectedAction);

    // Fill with keywords if title is too short
    if (parts.length < 2) {
      for (const kw of keywords) {
        if (parts.length >= 4) break;
        const cap = _capitalize(kw);
        if (!parts.includes(cap) && !parts.some(p => p.toLowerCase() === kw)) {
          parts.push(cap);
        }
      }
    }

    // Fallback: use first user message
    if (parts.length === 0) {
      const firstUser = msgs.find(m => m.role === 'user');
      if (firstUser) {
        const text = firstUser.content.trim();
        return text.length <= 50 ? text : text.substring(0, 47) + '…';
      }
      return 'Chat Session';
    }

    const title = parts.join(' ');
    const result = title.length > 60 ? title.substring(0, 57) + '…' : title;
    _cachedTitle = result;
    _cachedMsgCount = msgs.length;
    _cachedLastContent = lastContent;
    return result;
  }

  /**
   * Initialize: wire up the suggest button.
   */
  function init() {
    const btn = DOMCache.get('session-suggest-title');
    if (!btn) return;
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      const input = DOMCache.get('session-name-input');
      if (input) {
        const title = generate();
        input.value = title;
        input.focus();
        input.select();
      }
    });
  }

  return { generate, init, _extractKeywords, _capitalize };
})();

document.addEventListener('DOMContentLoaded', SmartTitle.init);

/* ---------- Session Templates (Ctrl+Shift+N) ---------- */
/**
 * Save and load reusable session templates. A template captures:
 * - Name & description
 * - System prompt / persona preset
 * - Model selection
 * - Tags
 * - Optional starter messages (first N messages from the session)
 *
 * Templates are stored in localStorage and can be exported/imported as JSON.
 * Slash command: /templates
 * Keyboard shortcut: Ctrl+Shift+N
 *
 * @namespace SessionTemplates
 */
const SessionTemplates = (() => {
  const STORAGE_KEY = 'agenticchat_session_templates';
  let _overlay = null;
  let _isOpen = false;

  const _esc = (s) => {
    if (typeof s !== 'string') return '';
    const d = document.createElement('div');
    d.textContent = s;
    return d.innerHTML;
  };

  /* ---- Storage ---- */
  function _loadTemplates() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      return _safeParse(raw, []);
    } catch { return []; }
  }

  function _saveTemplates(templates) {
    SafeStorage.setJSON(STORAGE_KEY, templates);
  }

  /* ---- Capture current session config as template ---- */
  function captureFromCurrent(opts = {}) {
    const template = {
      id: 'tpl_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
      name: opts.name || 'Untitled Template',
      description: opts.description || '',
      createdAt: new Date().toISOString(),
      // Capture persona / system prompt
      persona: SafeStorage.get('agenticchat_persona') || 'default',
      // Capture model
      model: ChatConfig.MODEL || 'gpt-4o',
      // Capture tags from current session
      tags: _getCurrentTags(),
      // Optionally capture starter messages
      starterMessages: opts.includeStarters ? _getStarterMessages(opts.starterCount || 4) : [],
    };
    return template;
  }

  function _getCurrentTags() {
    try {
      if (typeof ConversationTags !== 'undefined' && ConversationTags.getSessionTags) {
        const activeId = SessionManager.getActiveId();
        if (activeId) return ConversationTags.getSessionTags(activeId) || [];
      }
    } catch {}
    return [];
  }

  function _getStarterMessages(count) {
    try {
      const history = ConversationManager.getHistory ? ConversationManager.getHistory() : [];
      // Skip system messages, take first N user/assistant pairs
      const msgs = history.filter(m => m.role !== 'system');
      return msgs.slice(0, Math.min(count, msgs.length)).map(m => ({
        role: m.role,
        content: typeof m.content === 'string' ? m.content.substring(0, 2000) : ''
      }));
    } catch { return []; }
  }

  /* ---- Save template ---- */
  function save(template) {
    const templates = _loadTemplates();
    templates.unshift(template);
    _saveTemplates(templates);
  }

  /* ---- Delete template ---- */
  function remove(id) {
    const templates = _loadTemplates().filter(t => t.id !== id);
    _saveTemplates(templates);
  }

  /* ---- Apply template to new session ---- */
  function apply(templateId) {
    const templates = _loadTemplates();
    const tpl = templates.find(t => t.id === templateId);
    if (!tpl) return;

    // Create new session
    if (typeof SessionManager !== 'undefined' && SessionManager.newSession) {
      SessionManager.newSession();
    }

    // Apply persona
    if (tpl.persona && typeof SafeStorage !== 'undefined') {
      SafeStorage.set('agenticchat_persona', tpl.persona);
      // Try to refresh persona UI
      if (typeof PersonaPresets !== 'undefined' && PersonaPresets.refresh) {
        PersonaPresets.refresh();
      }
    }

    // Apply model
    if (tpl.model) {
      ChatConfig.MODEL = tpl.model;
      const label = DOMCache.get('model-label');
      const m = (ChatConfig.AVAILABLE_MODELS || []).find(x => x.id === tpl.model);
      if (label && m) label.textContent = m.label;
    }

    // Apply tags
    if (tpl.tags && tpl.tags.length > 0 && typeof ConversationTags !== 'undefined') {
      const activeId = SessionManager.getActiveId ? SessionManager.getActiveId() : null;
      if (activeId && ConversationTags.addTag) {
        tpl.tags.forEach(tag => {
          try { ConversationTags.addTag(activeId, tag); } catch {}
        });
      }
    }

    // Apply starter messages
    if (tpl.starterMessages && tpl.starterMessages.length > 0) {
      tpl.starterMessages.forEach(msg => {
        if (typeof ConversationManager !== 'undefined' && ConversationManager.addMessage) {
          ConversationManager.addMessage(msg.role, msg.content);
        }
      });
      // Refresh UI
      if (typeof UIController !== 'undefined' && UIController.renderHistory) {
        UIController.renderHistory();
      }
    }

    close();
  }

  /* ---- Export / Import ---- */
  function exportAll() {
    downloadBlob('session-templates.json', JSON.stringify(_loadTemplates(), null, 2), 'application/json');
  }

  function importFromJSON(jsonString) {
    try {
      const imported = _safeParse(jsonString);
      if (!Array.isArray(imported)) return 0;
      const existing = _loadTemplates();
      const existingIds = new Set(existing.map(t => t.id));
      let added = 0;
      imported.forEach(tpl => {
        if (tpl.id && tpl.name && !existingIds.has(tpl.id)) {
          existing.unshift(tpl);
          added++;
        }
      });
      _saveTemplates(existing);
      return added;
    } catch { return 0; }
  }

  /* ---- UI ---- */
  function _createOverlay() {
    if (_overlay) return _overlay;

    _overlay = document.createElement('div');
    _overlay.id = 'session-templates-overlay';
    _overlay.innerHTML = `
      <div class="stpl-panel">
        <div class="stpl-header">
          <h3>📋 Session Templates</h3>
          <div class="stpl-header-actions">
            <button class="btn-sm stpl-save-btn" title="Save current session as template">💾 Save Current</button>
            <button class="btn-sm stpl-import-btn" title="Import templates">📥 Import</button>
            <button class="btn-sm stpl-export-btn" title="Export all templates">📤 Export</button>
            <button class="btn-sm stpl-close-btn" title="Close">✕</button>
          </div>
        </div>
        <div class="stpl-save-form" style="display:none">
          <input class="stpl-name-input" type="text" placeholder="Template name" maxlength="80" />
          <input class="stpl-desc-input" type="text" placeholder="Description (optional)" maxlength="200" />
          <label class="stpl-starter-label">
            <input type="checkbox" class="stpl-include-starters" />
            Include first 4 messages as starters
          </label>
          <div class="stpl-save-actions">
            <button class="btn-sm stpl-confirm-save">Save Template</button>
            <button class="btn-sm stpl-cancel-save">Cancel</button>
          </div>
        </div>
        <div class="stpl-list"></div>
        <input type="file" class="stpl-file-input" accept=".json" style="display:none" />
      </div>
    `;

    const style = document.createElement('style');
    style.textContent = `
      #session-templates-overlay {
        display: none; position: fixed; inset: 0; z-index: 10000;
        background: rgba(0,0,0,0.5); justify-content: center; align-items: center;
      }
      #session-templates-overlay.visible { display: flex; }
      .stpl-panel {
        background: var(--bg, #1e1e2e); color: var(--fg, #cdd6f4);
        border: 1px solid var(--border, #45475a); border-radius: 12px;
        width: 520px; max-width: 95vw; max-height: 80vh; overflow: hidden;
        display: flex; flex-direction: column; box-shadow: 0 8px 32px rgba(0,0,0,0.4);
      }
      .stpl-header {
        display: flex; justify-content: space-between; align-items: center;
        padding: 14px 18px; border-bottom: 1px solid var(--border, #45475a);
      }
      .stpl-header h3 { margin: 0; font-size: 16px; }
      .stpl-header-actions { display: flex; gap: 6px; }
      .stpl-header-actions .btn-sm {
        background: var(--btn-bg, #313244); border: 1px solid var(--border, #45475a);
        color: var(--fg, #cdd6f4); border-radius: 6px; padding: 4px 10px;
        cursor: pointer; font-size: 12px;
      }
      .stpl-header-actions .btn-sm:hover { background: var(--btn-hover, #45475a); }
      .stpl-save-form {
        padding: 12px 18px; border-bottom: 1px solid var(--border, #45475a);
        display: flex; flex-direction: column; gap: 8px;
      }
      .stpl-save-form input[type="text"] {
        background: var(--input-bg, #313244); color: var(--fg, #cdd6f4);
        border: 1px solid var(--border, #45475a); border-radius: 6px;
        padding: 8px 10px; font-size: 13px; outline: none;
      }
      .stpl-save-form input[type="text"]:focus { border-color: var(--accent, #89b4fa); }
      .stpl-starter-label {
        font-size: 12px; display: flex; align-items: center; gap: 6px; opacity: 0.8;
      }
      .stpl-save-actions { display: flex; gap: 8px; }
      .stpl-save-actions .btn-sm {
        background: var(--accent, #89b4fa); color: #1e1e2e; border: none;
        border-radius: 6px; padding: 6px 14px; cursor: pointer; font-size: 12px; font-weight: 600;
      }
      .stpl-save-actions .btn-sm:last-child { background: var(--btn-bg, #313244); color: var(--fg, #cdd6f4); }
      .stpl-list {
        overflow-y: auto; padding: 12px 18px; flex: 1;
      }
      .stpl-empty {
        text-align: center; opacity: 0.5; padding: 40px 0; font-size: 14px;
      }
      .stpl-card {
        background: var(--btn-bg, #313244); border: 1px solid var(--border, #45475a);
        border-radius: 8px; padding: 12px 14px; margin-bottom: 8px;
        display: flex; flex-direction: column; gap: 6px;
      }
      .stpl-card-top { display: flex; justify-content: space-between; align-items: center; }
      .stpl-card-name { font-weight: 600; font-size: 14px; }
      .stpl-card-desc { font-size: 12px; opacity: 0.7; }
      .stpl-card-meta { display: flex; gap: 8px; font-size: 11px; opacity: 0.5; flex-wrap: wrap; }
      .stpl-card-meta span { background: var(--bg, #1e1e2e); padding: 2px 6px; border-radius: 4px; }
      .stpl-card-actions { display: flex; gap: 6px; }
      .stpl-card-actions button {
        background: var(--accent, #89b4fa); color: #1e1e2e; border: none;
        border-radius: 5px; padding: 4px 12px; cursor: pointer; font-size: 11px; font-weight: 600;
      }
      .stpl-card-actions button.stpl-delete-btn {
        background: transparent; color: var(--fg, #cdd6f4); opacity: 0.5;
      }
      .stpl-card-actions button.stpl-delete-btn:hover { opacity: 1; color: #f38ba8; }
      .stpl-card-tags { display: flex; gap: 4px; flex-wrap: wrap; }
      .stpl-card-tags span {
        background: var(--accent, #89b4fa); color: #1e1e2e; font-size: 10px;
        padding: 1px 6px; border-radius: 3px; font-weight: 600;
      }
    `;
    document.head.appendChild(style);
    document.body.appendChild(_overlay);

    // Wire events
    _overlay.querySelector('.stpl-close-btn').addEventListener('click', close);
    _overlay.addEventListener('click', (e) => { if (e.target === _overlay) close(); });

    const saveBtn = _overlay.querySelector('.stpl-save-btn');
    const saveForm = _overlay.querySelector('.stpl-save-form');
    const confirmBtn = _overlay.querySelector('.stpl-confirm-save');
    const cancelBtn = _overlay.querySelector('.stpl-cancel-save');

    saveBtn.addEventListener('click', () => {
      saveForm.style.display = saveForm.style.display === 'none' ? 'flex' : 'none';
      if (saveForm.style.display === 'flex') {
        _overlay.querySelector('.stpl-name-input').focus();
      }
    });

    cancelBtn.addEventListener('click', () => { saveForm.style.display = 'none'; });

    confirmBtn.addEventListener('click', () => {
      const name = _overlay.querySelector('.stpl-name-input').value.trim();
      if (!name) { _overlay.querySelector('.stpl-name-input').focus(); return; }
      const desc = _overlay.querySelector('.stpl-desc-input').value.trim();
      const includeStarters = _overlay.querySelector('.stpl-include-starters').checked;
      const tpl = captureFromCurrent({ name, description: desc, includeStarters });
      save(tpl);
      saveForm.style.display = 'none';
      _overlay.querySelector('.stpl-name-input').value = '';
      _overlay.querySelector('.stpl-desc-input').value = '';
      _overlay.querySelector('.stpl-include-starters').checked = false;
      _renderList();
    });

    _overlay.querySelector('.stpl-export-btn').addEventListener('click', exportAll);
    _overlay.querySelector('.stpl-import-btn').addEventListener('click', () => {
      _overlay.querySelector('.stpl-file-input').click();
    });
    _overlay.querySelector('.stpl-file-input').addEventListener('change', (e) => {
      const file = e.target.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = () => {
        const count = importFromJSON(reader.result);
        if (count > 0) _renderList();
        alert(count > 0 ? `Imported ${count} template(s).` : 'No new templates found.');
      };
      reader.readAsText(file);
      e.target.value = '';
    });

    // Keyboard: Esc to close
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && _isOpen) close();
    });

    return _overlay;
  }

  function _renderList() {
    const list = _overlay.querySelector('.stpl-list');
    const templates = _loadTemplates();

    if (templates.length === 0) {
      list.innerHTML = '<div class="stpl-empty">No templates yet.<br>Save your current session setup as a reusable template!</div>';
      return;
    }

    list.innerHTML = '';
    templates.forEach(tpl => {
      const modelInfo = (ChatConfig.AVAILABLE_MODELS || []).find(m => m.id === tpl.model);
      const modelLabel = modelInfo ? modelInfo.label : (tpl.model || 'default');
      const date = new Date(tpl.createdAt).toLocaleDateString();

      const card = document.createElement('div');
      card.className = 'stpl-card';
      card.innerHTML = `
        <div class="stpl-card-top">
          <span class="stpl-card-name">${_esc(tpl.name)}</span>
        </div>
        ${tpl.description ? `<div class="stpl-card-desc">${_esc(tpl.description)}</div>` : ''}
        <div class="stpl-card-meta">
          <span>🤖 ${_esc(modelLabel)}</span>
          <span>🎭 ${_esc(tpl.persona || 'default')}</span>
          ${tpl.starterMessages && tpl.starterMessages.length ? `<span>💬 ${tpl.starterMessages.length} starters</span>` : ''}
          <span>📅 ${date}</span>
        </div>
        ${tpl.tags && tpl.tags.length ? `<div class="stpl-card-tags">${tpl.tags.map(t => `<span>${_esc(typeof t === 'string' ? t : t.name || '')}</span>`).join('')}</div>` : ''}
        <div class="stpl-card-actions">
          <button class="stpl-use-btn">▶ Use Template</button>
          <button class="stpl-delete-btn">🗑</button>
        </div>
      `;

      card.querySelector('.stpl-use-btn').addEventListener('click', () => {
        if (confirm(`Start new session from "${tpl.name}"?`)) apply(tpl.id);
      });
      card.querySelector('.stpl-delete-btn').addEventListener('click', () => {
        if (confirm(`Delete template "${tpl.name}"?`)) {
          remove(tpl.id);
          _renderList();
        }
      });

      list.appendChild(card);
    });
  }

  function open() {
    const overlay = _createOverlay();
    _renderList();
    overlay.classList.add('visible');
    _isOpen = true;
  }

  function close() {
    if (_overlay) _overlay.classList.remove('visible');
    _isOpen = false;
  }

  function toggle() { _isOpen ? close() : open(); }

  function getAll() { return _loadTemplates(); }

  /* ---- Init: register slash command + keyboard shortcut ---- */
  function init() {
    // Register slash command
    if (typeof SlashCommands !== 'undefined' && SlashCommands.register) {
      SlashCommands.register({
        command: '/templates',
        description: 'Open session templates manager',
        action: open
      });
    }

    // Register keyboard shortcut: Ctrl+Shift+N
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'N') {
        e.preventDefault();
        toggle();
      }
    });

    // Register in command palette if available
    if (typeof CommandPalette !== 'undefined' && CommandPalette.registerCommand) {
      CommandPalette.registerCommand({
        id: 'session-templates',
        label: '📋 Session Templates',
        action: open
      });
    }
  }

  return {
    init, open, close, toggle,
    captureFromCurrent, save, remove, apply,
    getAll, exportAll, importFromJSON,
    _loadTemplates, _saveTemplates
  };
})();

document.addEventListener('DOMContentLoaded', SessionTemplates.init);


/* ---------- Conversation Flashcards ---------- */
/**
 * Extract Q&A pairs from conversation history and present them as
 * interactive study flashcards with flip animation.
 *
 * Heuristically pairs user questions with assistant answers, lets users
 * curate the deck, and supports keyboard navigation (arrow keys, Space to flip).
 * Persists custom decks to localStorage.
 *
 * Shortcut: Alt+F  |  Slash command: /flashcards
 * @namespace ConversationFlashcards
 */
const ConversationFlashcards = (() => {
  const STORAGE_KEY = 'ac-flashcard-decks';
  const MAX_DECKS = 20;
  const MAX_CARDS_PER_DECK = 100;
  let _panel = null;
  let _visible = false;
  let _currentDeck = [];
  let _cardIndex = 0;
  let _flipped = false;

  /* ---- persistence ---- */
  function _loadDecks() {
    try {
      return sanitizeStorageObject(SafeStorage.getJSON(STORAGE_KEY)) || [];
    } catch (e) { return []; }
  }
  function _saveDecks(decks) {
    SafeStorage.setJSON(STORAGE_KEY, decks.slice(0, MAX_DECKS));
  }

  /* ---- extraction ---- */
  function extractFromConversation() {
    if (typeof ConversationManager === 'undefined') return [];
    var msgs = ConversationManager.getMessages ? ConversationManager.getMessages() : [];
    var cards = [];
    var qPattern = /^(what|how|why|when|where|who|which|can|could|would|should|is|are|do|does|did|explain|describe|tell)/i;
    for (var i = 0; i < msgs.length - 1; i++) {
      if (msgs[i].role !== 'user') continue;
      var text = (msgs[i].content || '').trim();
      if (!text) continue;
      var isQuestion = text.endsWith('?') || qPattern.test(text);
      if (!isQuestion) continue;
      for (var j = i + 1; j < msgs.length; j++) {
        if (msgs[j].role === 'assistant') {
          var answer = (msgs[j].content || '').trim();
          if (answer) {
            cards.push({
              id: 'fc-' + Date.now() + '-' + cards.length,
              front: text.length > 200 ? text.slice(0, 197) + '...' : text,
              back: answer.length > 500 ? answer.slice(0, 497) + '...' : answer,
              created: Date.now()
            });
          }
          break;
        }
      }
    }
    return cards.slice(0, MAX_CARDS_PER_DECK);
  }

  /* ---- helpers ---- */
  const _escHtml = _escapeHtml;



  /* ---- UI ---- */
  function _createPanel() {
    if (_panel) return _panel;
    _panel = document.createElement('div');
    _panel.id = 'flashcard-panel';
    _panel.style.cssText = 'position:fixed;top:0;right:0;width:480px;height:100vh;background:var(--bg-primary,#1e1e2e);color:var(--text-primary,#cdd6f4);border-left:1px solid var(--border-color,#45475a);z-index:9200;display:none;flex-direction:column;font-family:inherit;box-shadow:-4px 0 20px rgba(0,0,0,0.3)';

    // Build header
    var header = document.createElement('div');
    header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;padding:16px 20px;border-bottom:1px solid var(--border-color,#45475a)';
    var title = document.createElement('h3');
    title.style.cssText = 'margin:0;font-size:16px';
    title.textContent = '\uD83C\uDCCF Flashcards';
    header.appendChild(title);

    var btnGroup = document.createElement('div');
    btnGroup.style.cssText = 'display:flex;gap:8px';

    var extractBtn = document.createElement('button');
    extractBtn.id = 'fc-extract-btn';
    extractBtn.textContent = 'Extract Q&A';
    extractBtn.title = 'Extract from conversation';
    extractBtn.style.cssText = 'background:var(--accent,#89b4fa);color:#1e1e2e;border:none;border-radius:6px;padding:6px 12px;cursor:pointer;font-size:13px';

    var saveBtn = document.createElement('button');
    saveBtn.id = 'fc-save-btn';
    saveBtn.textContent = 'Save Deck';
    saveBtn.title = 'Save current deck';
    saveBtn.style.cssText = 'background:var(--success,#a6e3a1);color:#1e1e2e;border:none;border-radius:6px;padding:6px 12px;cursor:pointer;font-size:13px';

    var closeBtn = document.createElement('button');
    closeBtn.id = 'fc-close-btn';
    closeBtn.textContent = '\u2715';
    closeBtn.title = 'Close';
    closeBtn.style.cssText = 'background:none;border:none;color:var(--text-primary,#cdd6f4);font-size:20px;cursor:pointer';

    btnGroup.appendChild(extractBtn);
    btnGroup.appendChild(saveBtn);
    btnGroup.appendChild(closeBtn);
    header.appendChild(btnGroup);
    _panel.appendChild(header);

    // Deck selector
    var deckSel = document.createElement('div');
    deckSel.id = 'fc-deck-selector';
    deckSel.style.cssText = 'padding:8px 20px;border-bottom:1px solid var(--border-color,#45475a);display:flex;gap:8px;align-items:center;flex-wrap:wrap';
    var label = document.createElement('label');
    label.style.cssText = 'font-size:12px;opacity:0.7';
    label.textContent = 'Saved Decks:';
    var select = document.createElement('select');
    select.id = 'fc-deck-list';
    select.style.cssText = 'flex:1;background:var(--bg-secondary,#313244);color:var(--text-primary,#cdd6f4);border:1px solid var(--border-color,#45475a);border-radius:4px;padding:4px 8px;font-size:13px';
    var defOpt = document.createElement('option');
    defOpt.value = '';
    defOpt.textContent = '- current extraction -';
    select.appendChild(defOpt);
    var delBtn = document.createElement('button');
    delBtn.id = 'fc-delete-deck-btn';
    delBtn.title = 'Delete selected deck';
    delBtn.textContent = '\uD83D\uDDD1';
    delBtn.style.cssText = 'background:var(--error,#f38ba8);color:#1e1e2e;border:none;border-radius:4px;padding:4px 8px;cursor:pointer;font-size:12px';
    deckSel.appendChild(label);
    deckSel.appendChild(select);
    deckSel.appendChild(delBtn);
    _panel.appendChild(deckSel);

    // Card area
    var cardArea = document.createElement('div');
    cardArea.id = 'fc-card-area';
    cardArea.style.cssText = 'flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;overflow-y:auto';

    var emptyEl = document.createElement('div');
    emptyEl.id = 'fc-empty';
    emptyEl.style.cssText = 'text-align:center;opacity:0.5;font-size:14px';
    emptyEl.innerHTML = '<p>No flashcards yet.</p><p>Click <strong>Extract Q&amp;A</strong> to generate cards from your conversation.</p>';

    var cardEl = document.createElement('div');
    cardEl.id = 'fc-card';
    cardEl.style.cssText = 'display:none;width:100%;max-width:400px;min-height:220px;perspective:800px;cursor:pointer';

    var cardInner = document.createElement('div');
    cardInner.id = 'fc-card-inner';
    cardInner.style.cssText = 'position:relative;width:100%;min-height:220px;transition:transform 0.5s;transform-style:preserve-3d';

    var front = document.createElement('div');
    front.id = 'fc-front';
    front.style.cssText = 'position:absolute;width:100%;min-height:220px;backface-visibility:hidden;background:var(--bg-secondary,#313244);border-radius:12px;padding:24px;display:flex;align-items:center;justify-content:center;text-align:center;font-size:15px;line-height:1.5;border:2px solid var(--accent,#89b4fa);box-sizing:border-box';

    var back = document.createElement('div');
    back.id = 'fc-back';
    back.style.cssText = 'position:absolute;width:100%;min-height:220px;backface-visibility:hidden;background:var(--bg-secondary,#313244);border-radius:12px;padding:24px;display:flex;align-items:center;justify-content:center;text-align:center;font-size:13px;line-height:1.5;border:2px solid var(--success,#a6e3a1);transform:rotateY(180deg);box-sizing:border-box;overflow-y:auto;max-height:350px';

    cardInner.appendChild(front);
    cardInner.appendChild(back);
    cardEl.appendChild(cardInner);
    cardArea.appendChild(emptyEl);
    cardArea.appendChild(cardEl);
    _panel.appendChild(cardArea);

    // Controls
    var controls = document.createElement('div');
    controls.id = 'fc-controls';
    controls.style.cssText = 'display:none;padding:12px 20px;border-top:1px solid var(--border-color,#45475a);text-align:center';

    var navRow = document.createElement('div');
    navRow.style.cssText = 'display:flex;align-items:center;justify-content:center;gap:16px;margin-bottom:8px';
    var prevBtn = document.createElement('button');
    prevBtn.id = 'fc-prev';
    prevBtn.textContent = '\u2190 Prev';
    prevBtn.style.cssText = 'background:none;border:1px solid var(--border-color,#45475a);color:var(--text-primary,#cdd6f4);border-radius:6px;padding:6px 16px;cursor:pointer;font-size:14px';
    var counter = document.createElement('span');
    counter.id = 'fc-counter';
    counter.style.cssText = 'font-size:13px;opacity:0.7';
    counter.textContent = '0 / 0';
    var nextBtn = document.createElement('button');
    nextBtn.id = 'fc-next';
    nextBtn.textContent = 'Next \u2192';
    nextBtn.style.cssText = 'background:none;border:1px solid var(--border-color,#45475a);color:var(--text-primary,#cdd6f4);border-radius:6px;padding:6px 16px;cursor:pointer;font-size:14px';
    navRow.appendChild(prevBtn);
    navRow.appendChild(counter);
    navRow.appendChild(nextBtn);
    controls.appendChild(navRow);

    var hint = document.createElement('div');
    hint.style.cssText = 'font-size:11px;opacity:0.5';
    hint.textContent = 'Space to flip \u00b7 \u2190 \u2192 to navigate \u00b7 Del to remove card';
    controls.appendChild(hint);
    _panel.appendChild(controls);

    // Event listeners
    closeBtn.addEventListener('click', close);
    extractBtn.addEventListener('click', function() {
      var cards = extractFromConversation();
      if (cards.length === 0) {
        _showEmpty('No Q&A pairs found. Try asking some questions first!');
        return;
      }
      _currentDeck = cards;
      _cardIndex = 0;
      _flipped = false;
      _renderCard();
    });
    saveBtn.addEventListener('click', _saveDeck);
    delBtn.addEventListener('click', _deleteSelectedDeck);
    select.addEventListener('change', _loadSelectedDeck);
    cardEl.addEventListener('click', _flipCard);
    prevBtn.addEventListener('click', _prevCard);
    nextBtn.addEventListener('click', _nextCard);

    document.body.appendChild(_panel);
    return _panel;
  }

  function _showEmpty(msg) {
    var emptyEl = _panel.querySelector('#fc-empty');
    var cardEl = _panel.querySelector('#fc-card');
    var controls = _panel.querySelector('#fc-controls');
    emptyEl.innerHTML = '<p>' + _escHtml(msg) + '</p>';
    emptyEl.style.display = 'block';
    cardEl.style.display = 'none';
    controls.style.display = 'none';
  }

  function _renderCard() {
    if (!_panel || _currentDeck.length === 0) return;
    _panel.querySelector('#fc-empty').style.display = 'none';
    _panel.querySelector('#fc-card').style.display = 'block';
    _panel.querySelector('#fc-controls').style.display = 'block';
    var card = _currentDeck[_cardIndex];
    _panel.querySelector('#fc-front').textContent = card.front;
    _panel.querySelector('#fc-back').textContent = card.back;
    _panel.querySelector('#fc-counter').textContent = (_cardIndex + 1) + ' / ' + _currentDeck.length;
    _flipped = false;
    _panel.querySelector('#fc-card-inner').style.transform = '';
  }

  function _flipCard() {
    _flipped = !_flipped;
    _panel.querySelector('#fc-card-inner').style.transform = _flipped ? 'rotateY(180deg)' : '';
  }

  function _prevCard() {
    if (_currentDeck.length === 0) return;
    _cardIndex = (_cardIndex - 1 + _currentDeck.length) % _currentDeck.length;
    _flipped = false;
    _renderCard();
  }

  function _nextCard() {
    if (_currentDeck.length === 0) return;
    _cardIndex = (_cardIndex + 1) % _currentDeck.length;
    _flipped = false;
    _renderCard();
  }

  function _removeCurrentCard() {
    if (_currentDeck.length === 0) return;
    _currentDeck.splice(_cardIndex, 1);
    if (_currentDeck.length === 0) {
      _showEmpty('All cards removed from this deck.');
      return;
    }
    if (_cardIndex >= _currentDeck.length) _cardIndex = _currentDeck.length - 1;
    _renderCard();
  }

  function _saveDeck() {
    if (_currentDeck.length === 0) return;
    var name = prompt('Deck name:');
    if (!name || !name.trim()) return;
    var decks = _loadDecks();
    decks.unshift({ name: name.trim(), cards: _currentDeck.slice(), created: Date.now(), count: _currentDeck.length });
    _saveDecks(decks);
    _refreshDeckList();
  }

  function _refreshDeckList() {
    if (!_panel) return;
    var sel = _panel.querySelector('#fc-deck-list');
    var decks = _loadDecks();
    sel.innerHTML = '<option value="">\u2014 current extraction \u2014</option>';
    decks.forEach(function(d, i) {
      var opt = document.createElement('option');
      opt.value = String(i);
      opt.textContent = d.name + ' (' + d.count + ' cards)';
      sel.appendChild(opt);
    });
  }

  function _loadSelectedDeck() {
    var sel = _panel.querySelector('#fc-deck-list');
    var idx = parseInt(sel.value, 10);
    if (isNaN(idx)) return;
    var decks = _loadDecks();
    if (!decks[idx]) return;
    _currentDeck = decks[idx].cards.slice();
    _cardIndex = 0;
    _flipped = false;
    if (_currentDeck.length === 0) { _showEmpty('This deck is empty.'); }
    else { _renderCard(); }
  }

  function _deleteSelectedDeck() {
    var sel = _panel.querySelector('#fc-deck-list');
    var idx = parseInt(sel.value, 10);
    if (isNaN(idx)) return;
    var decks = _loadDecks();
    if (!decks[idx]) return;
    if (!confirm('Delete deck "' + decks[idx].name + '"?')) return;
    decks.splice(idx, 1);
    _saveDecks(decks);
    _refreshDeckList();
    sel.value = '';
  }

  /* ---- keyboard ---- */
  function _onKey(e) {
    if (!_visible) return;
    if (e.key === ' ' || e.code === 'Space') { e.preventDefault(); _flipCard(); }
    else if (e.key === 'ArrowLeft') { e.preventDefault(); _prevCard(); }
    else if (e.key === 'ArrowRight') { e.preventDefault(); _nextCard(); }
    else if (e.key === 'Delete') { e.preventDefault(); _removeCurrentCard(); }
    else if (e.key === 'Escape') { e.preventDefault(); close(); }
  }

  /* ---- public ---- */
  function open() {
    _createPanel();
    _panel.style.display = 'flex';
    _visible = true;
    _refreshDeckList();
    document.addEventListener('keydown', _onKey);
  }

  function close() {
    if (_panel) _panel.style.display = 'none';
    _visible = false;
    document.removeEventListener('keydown', _onKey);
  }

  function toggle() { _visible ? close() : open(); }

  function getDecks() { return _loadDecks(); }
  function getCurrentDeck() { return _currentDeck.slice(); }
  function getCardCount() { return _currentDeck.length; }

  function init() {
    if (typeof SlashCommands !== 'undefined' && SlashCommands.register) {
      SlashCommands.register({
        command: '/flashcards',
        description: 'Open flashcard study deck from conversation Q&A',
        action: open
      });
    }
    document.addEventListener('keydown', function(e) {
      if (e.altKey && e.key === 'f') { e.preventDefault(); toggle(); }
    });
    if (typeof CommandPalette !== 'undefined' && CommandPalette.registerCommand) {
      CommandPalette.registerCommand({ id: 'flashcards', label: '\uD83C\uDCCF Conversation Flashcards', action: open });
    }
  }

  return {
    init: init, open: open, close: close, toggle: toggle,
    extractFromConversation: extractFromConversation,
    getDecks: getDecks, getCurrentDeck: getCurrentDeck, getCardCount: getCardCount,
    _loadDecks: _loadDecks, _saveDecks: _saveDecks
  };
})();

document.addEventListener('DOMContentLoaded', ConversationFlashcards.init);


/* ============================================================
 * SmartPaste - intelligent paste formatting for chat input
 *
 * Detects pasted content type (URL, JSON, code, CSV, SQL,
 * stack trace, key-value config, markdown table) and auto-wraps
 * it with appropriate markdown formatting. Shows a toast with
 * the detected type. Users can undo with Ctrl+Z.
 *
 * Shortcut: none (activates on paste into chat input)
 * ============================================================ */

const SmartPaste = (() => {
  const MAX_PASTE_LENGTH = 50000;
  let _enabled = true;
  let _toastTimeout = null;

  /* ---- detection helpers ---- */

  function _isURL(text) {
    var t = text.trim();
    return /^https?:\/\/[^\s]+$/i.test(t) && t.length < 2048;
  }

  function _isMultiURL(text) {
    var lines = text.trim().split(/\n/);
    if (lines.length < 2 || lines.length > 20) return false;
    return lines.every(function(l) { return /^https?:\/\/[^\s]+$/i.test(l.trim()); });
  }

  function _isJSON(text) {
    var t = text.trim();
    if (!(t[0] === '{' || t[0] === '[')) return false;
    try { JSON.parse(t); return t.length > 5; } catch(e) { return false; }
  }

  function _isCSV(text) {
    var lines = text.trim().split(/\n/);
    if (lines.length < 2) return false;
    var commas = (lines[0].match(/,/g) || []).length;
    if (commas < 1) return false;
    var consistent = 0;
    for (var i = 1; i < Math.min(lines.length, 6); i++) {
      if ((lines[i].match(/,/g) || []).length === commas) consistent++;
    }
    return consistent >= Math.min(lines.length - 1, 3);
  }

  function _isSQL(text) {
    var t = text.trim();
    return /^(SELECT|INSERT|UPDATE|DELETE|CREATE|ALTER|DROP|WITH)\s/i.test(t) && t.length > 15;
  }

  function _isStackTrace(text) {
    var t = text.trim();
    // Java/Python/JS/C# stack traces
    return (
      (t.match(/\bat\s+[\w.$<>]+\s*\(/gm) || []).length >= 2 ||
      (t.match(/File\s+"[^"]+",\s+line\s+\d+/gm) || []).length >= 2 ||
      (t.match(/Traceback\s+\(most\s+recent/i) !== null) ||
      (t.match(/^\s+at\s+/gm) || []).length >= 3
    );
  }

  function _isCodeBlock(text) {
    var t = text.trim();
    var lines = t.split(/\n/);
    if (lines.length < 3) return false;
    var codeSignals = 0;
    var patterns = [
      /^(import|from|require|include|using|package)\s/,
      /^(def|function|fn|func|class|struct|enum|interface|trait)\s/,
      /[{};]\s*$/,
      /^\s*(if|else|for|while|switch|case|return|try|catch)\s*[\({]/,
      /^\s*(const|let|var|int|str|bool|float|double|string|void)\s/,
      /=>\s*[{(]/,
      /^\s*#(include|define|ifdef|pragma)/,
      /^\s*@(Override|Test|Component|Service)/
    ];
    for (var i = 0; i < lines.length; i++) {
      for (var p = 0; p < patterns.length; p++) {
        if (patterns[p].test(lines[i])) { codeSignals++; break; }
      }
    }
    return codeSignals >= 2;
  }

  function _isKeyValue(text) {
    var lines = text.trim().split(/\n/).filter(function(l) { return l.trim(); });
    if (lines.length < 2) return false;
    var kvCount = 0;
    for (var i = 0; i < lines.length; i++) {
      if (/^[\w./-]+\s*[=:]\s*.+/.test(lines[i].trim())) kvCount++;
    }
    return kvCount >= lines.length * 0.7;
  }

  function _guessLanguage(text) {
    var t = text.trim();
    if (/^(import\s+(React|useState|{)|export\s+(default|const|function)|=>\s*[{(]|const\s+\w+\s*=\s*require)/.test(t)) return 'javascript';
    if (/^(from\s+\w+\s+import|import\s+\w+|def\s+\w+\s*\(|class\s+\w+[:(])/.test(t)) return 'python';
    if (/^(package\s+\w+|import\s+"|\bfunc\s+\w+\s*\()/.test(t)) return 'go';
    if (/^(use\s+\w+|fn\s+\w+|let\s+mut\s|impl\s)/.test(t)) return 'rust';
    if (/^(using\s+System|namespace\s+\w+|public\s+(class|static|async))/.test(t)) return 'csharp';
    if (/^(#include|#define|int\s+main\s*\()/.test(t)) return 'c';
    if (/^\s*<[a-zA-Z][\s\S]*>/.test(t) && /<\/[a-zA-Z]+>\s*$/.test(t)) return 'html';
    if (/^\s*[\w-]+\s*{[\s\S]*}/.test(t) && /:\s*[^;]+;/.test(t)) return 'css';
    if (_isSQL(t)) return 'sql';
    return '';
  }

  /* ---- formatting ---- */

  function _formatPaste(text) {
    if (!text || text.length > MAX_PASTE_LENGTH) return null;
    var t = text.trim();
    if (!t) return null;

    // Single URL
    if (_isURL(t)) {
      return { formatted: t + '\n', type: 'URL' };
    }

    // Multiple URLs
    if (_isMultiURL(t)) {
      var urls = t.split(/\n/).map(function(l) { return '- ' + l.trim(); }).join('\n');
      return { formatted: urls + '\n', type: 'URL list' };
    }

    // JSON
    if (_isJSON(t)) {
      try {
        var pretty = JSON.stringify(JSON.parse(t), null, 2);
        return { formatted: '```json\n' + pretty + '\n```', type: 'JSON' };
      } catch(e) {
        return { formatted: '```json\n' + t + '\n```', type: 'JSON' };
      }
    }

    // Stack trace
    if (_isStackTrace(t)) {
      return { formatted: '```\n' + t + '\n```', type: 'Stack trace' };
    }

    // SQL
    if (_isSQL(t)) {
      return { formatted: '```sql\n' + t + '\n```', type: 'SQL' };
    }

    // CSV
    if (_isCSV(t)) {
      return { formatted: '```csv\n' + t + '\n```', type: 'CSV data' };
    }

    // Code block
    if (_isCodeBlock(t)) {
      var lang = _guessLanguage(t);
      return { formatted: '```' + lang + '\n' + t + '\n```', type: lang ? lang.charAt(0).toUpperCase() + lang.slice(1) + ' code' : 'Code' };
    }

    // Key-value config
    if (_isKeyValue(t)) {
      return { formatted: '```\n' + t + '\n```', type: 'Config / key-value' };
    }

    return null;
  }

  /* ---- toast ---- */

  function _showToast(typeLabel) {
    ToastManager.show('\u2728 Smart Paste: ' + typeLabel + ' detected', { id: 'smartpaste-toast', durationMs: 2500 });
  }

  /* ---- paste handler ---- */

  function _onPaste(e) {
    if (!_enabled) return;
    var clipboardData = e.clipboardData || (window.clipboardData);
    if (!clipboardData) return;
    var text = clipboardData.getData('text/plain');
    if (!text || text.trim().length < 5) return;
    // Don't format if it's just a short single-line string
    var lines = text.trim().split(/\n/);
    if (lines.length === 1 && !_isURL(text.trim()) && text.trim().length < 80) return;

    var result = _formatPaste(text);
    if (!result) return;

    e.preventDefault();
    var input = e.target;

    if (input.tagName === 'INPUT' || input.tagName === 'TEXTAREA') {
      // For <input> and <textarea>, insert at cursor position
      var start = input.selectionStart || 0;
      var end = input.selectionEnd || 0;
      var val = input.value;
      input.value = val.slice(0, start) + result.formatted + val.slice(end);
      var newPos = start + result.formatted.length;
      input.setSelectionRange(newPos, newPos);
    } else if (input.isContentEditable) {
      document.execCommand('insertText', false, result.formatted);
    }

    // Dispatch input event so other modules notice the change
    input.dispatchEvent(new Event('input', { bubbles: true }));

    _showToast(result.type);
  }

  /* ---- public API ---- */

  function enable() { _enabled = true; }
  function disable() { _enabled = false; }
  function isEnabled() { return _enabled; }
  function setEnabled(val) { _enabled = !!val; }

  function formatText(text) {
    var result = _formatPaste(text);
    return result ? result.formatted : text;
  }

  function detectType(text) {
    var result = _formatPaste(text);
    return result ? result.type : null;
  }

  function init() {
    var chatInput = DOMCache.get('chat-input');
    if (chatInput) {
      chatInput.addEventListener('paste', _onPaste);
    }

    if (typeof SlashCommands !== 'undefined' && SlashCommands.register) {
      SlashCommands.register({
        command: '/smartpaste',
        description: 'Toggle Smart Paste auto-formatting on/off',
        action: function() {
          _enabled = !_enabled;
          _showToast('Smart Paste ' + (_enabled ? 'enabled' : 'disabled'));
        }
      });
    }

    if (typeof CommandPalette !== 'undefined' && CommandPalette.registerCommand) {
      CommandPalette.registerCommand({
        id: 'smartpaste-toggle',
        label: '\u2728 Toggle Smart Paste',
        action: function() {
          _enabled = !_enabled;
          _showToast('Smart Paste ' + (_enabled ? 'enabled' : 'disabled'));
        }
      });
    }

    // Respect preferences if available
    if (typeof PreferencesPanel !== 'undefined' && PreferencesPanel.registerPreference) {
      PreferencesPanel.registerPreference({
        id: 'smartpaste-enabled',
        label: 'Smart Paste auto-formatting',
        type: 'toggle',
        default: true,
        onChange: function(val) { _enabled = val; }
      });
    }
  }

  return {
    init: init,
    enable: enable,
    disable: disable,
    isEnabled: isEnabled,
    setEnabled: setEnabled,
    formatText: formatText,
    detectType: detectType,
    _isURL: _isURL,
    _isJSON: _isJSON,
    _isCSV: _isCSV,
    _isSQL: _isSQL,
    _isStackTrace: _isStackTrace,
    _isCodeBlock: _isCodeBlock,
    _isKeyValue: _isKeyValue,
    _guessLanguage: _guessLanguage,
    _formatPaste: _formatPaste
  };
})();

document.addEventListener('DOMContentLoaded', SmartPaste.init);

/* ============================================================
 * MessageContextMenu - right-click context menu for chat messages
 *
 * Provides a unified context menu when right-clicking on any chat
 * message, surfacing common per-message actions: copy, bookmark,
 * pin, annotate, translate, fork, read aloud, rate, edit, and more.
 *
 * @namespace MessageContextMenu
 * ============================================================ */
const MessageContextMenu = (() => {
  const MENU_ID = 'msg-context-menu';
  const STORAGE_KEY = 'ac-context-menu-enabled';
  let _enabled = true;
  let _menu = null;
  let _targetMsg = null;
  let _targetIndex = -1;

  /* ---- helpers ---- */

  /** Find the closest message element from a DOM node. */
  function _getMessageElement(el) {
    return el.closest('.msg-user, .msg-assistant, .msg-system, [data-msg-index]');
  }

  function _getMessageIndex(el) {
    const msgEl = _getMessageElement(el);
    if (!msgEl) return -1;
    if (msgEl.dataset.msgIndex !== undefined) return parseInt(msgEl.dataset.msgIndex, 10);
    const output = DOMCache.get('chat-output');
    if (!output) return -1;
    const children = Array.from(output.children);
    return children.indexOf(msgEl);
  }

  function _getMessageText(el) {
    const msgEl = _getMessageElement(el);
    if (!msgEl) return '';
    return msgEl.innerText || msgEl.textContent || '';
  }

  function _getMessageRole(el) {
    const msgEl = _getMessageElement(el);
    if (!msgEl) return 'unknown';
    if (msgEl.classList.contains('msg-user')) return 'user';
    if (msgEl.classList.contains('msg-assistant')) return 'assistant';
    if (msgEl.classList.contains('msg-system')) return 'system';
    return 'unknown';
  }

  /* ---- menu item definitions ---- */

  /**
   * Helper to create a context menu item that delegates to an optional module.
   * Reduces boilerplate: each item just declares the module reference, method,
   * and optional condition.
   */
  function _moduleItem(icon, label, id, moduleRef, methodName, opts) {
    const item = { icon: icon, label: label, id: id };
    if (opts && opts.condition) item.condition = opts.condition;
    item.action = function() {
      if (moduleRef && typeof moduleRef[methodName] === 'function') {
        moduleRef[methodName](_targetIndex);
      } else {
        _toast(label + ' not available');
      }
    };
    return item;
  }

  function _buildMenuItems() {
    const items = [];

    // Always available
    items.push({
      icon: '📋', label: 'Copy Text', id: 'ctx-copy',
      action: function() {
        var text = _getMessageText(_targetMsg);
        if (navigator.clipboard) {
          navigator.clipboard.writeText(text).then(function() { _toast('Copied to clipboard'); });
        }
      }
    });

    items.push({
      icon: '📋', label: 'Copy as Markdown', id: 'ctx-copy-md',
      action: function() {
        var role = _getMessageRole(_targetMsg);
        var text = _getMessageText(_targetMsg);
        var md = '**' + role.charAt(0).toUpperCase() + role.slice(1) + ':**\n' + text;
        if (navigator.clipboard) {
          navigator.clipboard.writeText(md).then(function() { _toast('Copied as Markdown'); });
        }
      }
    });

    items.push({ type: 'separator' });

    // Module-backed actions — declarative registration
    if (typeof ChatBookmarks !== 'undefined')
      items.push(_moduleItem('🔖', 'Bookmark', 'ctx-bookmark', ChatBookmarks, 'toggle'));

    if (typeof MessagePinning !== 'undefined')
      items.push(_moduleItem('📌', 'Pin Message', 'ctx-pin', MessagePinning, 'togglePin'));

    if (typeof MessageAnnotations !== 'undefined')
      items.push(_moduleItem('🏷️', 'Annotate', 'ctx-annotate', MessageAnnotations,
        MessageAnnotations.openAnnotation ? 'openAnnotation' : 'addAnnotation'));

    if (typeof MessageReactions !== 'undefined')
      items.push(_moduleItem('😀', 'React', 'ctx-react', MessageReactions, 'showPicker'));

    items.push({ type: 'separator' });

    if (typeof ReadAloud !== 'undefined')
      items.push(_moduleItem('🔊', 'Read Aloud', 'ctx-read', ReadAloud,
        ReadAloud.speak ? 'speak' : 'readMessage'));

    if (typeof MessageTranslator !== 'undefined')
      items.push(_moduleItem('🌐', 'Translate', 'ctx-translate', MessageTranslator, 'translateMessage'));

    if (typeof MessageDiff !== 'undefined')
      items.push(_moduleItem('🔀', 'Compare (Diff)', 'ctx-diff', MessageDiff, 'selectForDiff'));

    items.push({ type: 'separator' });

    if (typeof ConversationFork !== 'undefined')
      items.push(_moduleItem('🔱', 'Fork from Here', 'ctx-fork', ConversationFork, 'forkFrom'));

    // Edit & resend (user messages only)
    if (typeof MessageEditor !== 'undefined')
      items.push(_moduleItem('✏️', 'Edit & Resend', 'ctx-edit', MessageEditor, 'editMessage', {
        condition: function() { return _getMessageRole(_targetMsg) === 'user'; }
      }));

    // Rate (assistant messages only)
    if (typeof ResponseRating !== 'undefined')
      items.push(_moduleItem('⭐', 'Rate Response', 'ctx-rate', ResponseRating, 'rateMessage', {
        condition: function() { return _getMessageRole(_targetMsg) === 'assistant'; }
      }));

    return items;
  }

  /* ---- DOM creation ---- */

  function _createMenu() {
    if (_menu) return _menu;
    _menu = document.createElement('div');
    _menu.id = MENU_ID;
    _menu.className = 'msg-context-menu';
    _menu.setAttribute('role', 'menu');
    _menu.setAttribute('aria-label', 'Message actions');
    _menu.style.display = 'none';
    document.body.appendChild(_menu);
    return _menu;
  }

  function _renderMenu() {
    var items = _buildMenuItems();
    _menu.innerHTML = '';
    var count = 0;
    items.forEach(function(item) {
      if (item.type === 'separator') {
        if (count > 0) {
          var sep = document.createElement('div');
          sep.className = 'msg-context-menu__sep';
          sep.setAttribute('role', 'separator');
          _menu.appendChild(sep);
        }
        return;
      }
      // Check condition
      if (item.condition && !item.condition()) return;

      var btn = document.createElement('button');
      btn.className = 'msg-context-menu__item';
      btn.setAttribute('role', 'menuitem');
      btn.setAttribute('tabindex', '-1');
      btn.innerHTML = '<span class="msg-context-menu__icon">' + item.icon + '</span>' +
                      '<span class="msg-context-menu__label">' + item.label + '</span>';
      btn.addEventListener('click', function(e) {
        e.stopPropagation();
        _hide();
        item.action();
      });
      _menu.appendChild(btn);
      count++;
    });
  }

  /* ---- positioning ---- */

  function _show(x, y) {
    _createMenu();
    _renderMenu();
    _menu.style.display = 'block';
    // Position, keeping within viewport
    var rect = _menu.getBoundingClientRect();
    var vw = window.innerWidth;
    var vh = window.innerHeight;
    // Temporarily make visible to measure
    _menu.style.left = '0';
    _menu.style.top = '0';
    var menuW = _menu.offsetWidth;
    var menuH = _menu.offsetHeight;
    var posX = (x + menuW > vw) ? Math.max(0, x - menuW) : x;
    var posY = (y + menuH > vh) ? Math.max(0, y - menuH) : y;
    _menu.style.left = posX + 'px';
    _menu.style.top = posY + 'px';
    // Focus first item
    var first = _menu.querySelector('.msg-context-menu__item');
    if (first) first.focus();
  }

  function _hide() {
    if (_menu) _menu.style.display = 'none';
    _targetMsg = null;
    _targetIndex = -1;
  }

  /* ---- toast ---- */
  function _toast(msg) {
    ToastManager.show(msg, { id: 'ctx-menu-toast', className: 'msg-context-toast', durationMs: 2000 });
  }

  /* ---- keyboard nav ---- */

  function _handleKeydown(e) {
    if (!_menu || _menu.style.display === 'none') return;
    var items = Array.from(_menu.querySelectorAll('.msg-context-menu__item'));
    var idx = items.indexOf(document.activeElement);
    if (e.key === 'ArrowDown' || e.key === 'j') {
      e.preventDefault();
      var next = (idx + 1) % items.length;
      items[next].focus();
    } else if (e.key === 'ArrowUp' || e.key === 'k') {
      e.preventDefault();
      var prev = (idx - 1 + items.length) % items.length;
      items[prev].focus();
    } else if (e.key === 'Escape') {
      e.preventDefault();
      _hide();
    } else if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      if (idx >= 0) items[idx].click();
    }
  }

  /* ---- event handlers ---- */

  function _onContextMenu(e) {
    if (!_enabled) return;
    // Only activate on chat message elements
    var msgEl = e.target.closest('.msg-user, .msg-assistant, .msg-system, [data-msg-index]');
    if (!msgEl) return;
    // Must be inside chat output
    var output = DOMCache.get('chat-output');
    if (!output || !output.contains(msgEl)) return;

    e.preventDefault();
    _targetMsg = msgEl;
    _targetIndex = _getMessageIndex(msgEl);
    _show(e.clientX, e.clientY);
  }

  function _onDocClick(e) {
    if (_menu && _menu.style.display !== 'none' && !_menu.contains(e.target)) {
      _hide();
    }
  }

  /* ---- public API ---- */

  function init() {
    var stored = SafeStorage.get(STORAGE_KEY);
    if (stored !== null) _enabled = _safeParse(stored, _enabled);

    _createMenu();
    document.addEventListener('contextmenu', _onContextMenu);
    document.addEventListener('click', _onDocClick);
    document.addEventListener('keydown', _handleKeydown);

    // Slash command
    if (typeof SlashCommands !== 'undefined' && SlashCommands.register) {
      SlashCommands.register({
        command: '/contextmenu',
        description: 'Toggle right-click context menu on messages',
        action: function() {
          _enabled = !_enabled;
          SafeStorage.trySetJSON(STORAGE_KEY, _enabled);
          _toast('Context menu ' + (_enabled ? 'enabled' : 'disabled'));
        }
      });
    }

    // Command palette
    if (typeof CommandPalette !== 'undefined' && CommandPalette.registerCommand) {
      CommandPalette.registerCommand({
        id: 'context-menu-toggle',
        label: '🖱️ Toggle Message Context Menu',
        action: function() {
          _enabled = !_enabled;
          SafeStorage.trySetJSON(STORAGE_KEY, _enabled);
          _toast('Context menu ' + (_enabled ? 'enabled' : 'disabled'));
        }
      });
    }

    // Preferences
    if (typeof PreferencesPanel !== 'undefined' && PreferencesPanel.registerPreference) {
      PreferencesPanel.registerPreference({
        id: 'context-menu-enabled',
        label: 'Message right-click context menu',
        type: 'toggle',
        default: true,
        onChange: function(val) { _enabled = val; SafeStorage.trySetJSON(STORAGE_KEY, val); }
      });
    }
  }

  function enable()  { _enabled = true;  SafeStorage.trySet(STORAGE_KEY, 'true'); }
  function disable() { _enabled = false; SafeStorage.trySet(STORAGE_KEY, 'false'); }
  function isEnabled() { return _enabled; }

  return {
    init: init,
    enable: enable,
    disable: disable,
    isEnabled: isEnabled,
    show: _show,
    hide: _hide
  };
})();

document.addEventListener('DOMContentLoaded', MessageContextMenu.init);


/* ============================================================
 *  PromptABTester - compare two model responses side-by-side
 *  Shortcut: Ctrl+Shift+B
 * ============================================================ */
const PromptABTester = (() => {
  let _overlay = null;
  let _visible = false;
  const STORAGE_KEY = 'ac-ab-tester-history';
  const MAX_HISTORY = 20;

  function _getHistory() { return SafeStorage.getJSON(STORAGE_KEY, []); }
  function _saveHistory(h) { SafeStorage.setJSON(STORAGE_KEY, h.slice(0, MAX_HISTORY)); }

  function _build() {
    _overlay = document.createElement('div');
    _overlay.className = 'ab-tester-overlay';
    _overlay.innerHTML = `
      <div class="ab-tester-panel">
        <div class="ab-tester-header">
          <h3>⚖️ Prompt A/B Tester</h3>
          <div class="ab-tester-header-actions">
            <button class="ab-tester-history-btn" title="View comparison history">📋</button>
            <button class="ab-tester-close" title="Close">&times;</button>
          </div>
        </div>
        <div class="ab-tester-config">
          <div class="ab-tester-model-row">
            <label>Model A: <select class="ab-model-a"></select></label>
            <label>Model B: <select class="ab-model-b"></select></label>
          </div>
          <textarea class="ab-tester-prompt" placeholder="Enter your prompt here…" rows="3"></textarea>
          <div class="ab-tester-actions">
            <button class="ab-tester-run btn-primary">▶ Compare</button>
            <button class="ab-tester-swap btn-secondary" title="Swap models">🔄 Swap</button>
            <button class="ab-tester-clear btn-secondary">Clear</button>
          </div>
        </div>
        <div class="ab-tester-results" style="display:none">
          <div class="ab-tester-result-col ab-tester-col-a">
            <div class="ab-tester-col-header"><span class="ab-model-label-a"></span><span class="ab-tester-meta-a"></span></div>
            <div class="ab-tester-response-a"></div>
            <div class="ab-tester-vote">
              <button class="ab-vote-btn" data-vote="a" title="Model A is better">👍 A wins</button>
            </div>
          </div>
          <div class="ab-tester-result-col ab-tester-col-b">
            <div class="ab-tester-col-header"><span class="ab-model-label-b"></span><span class="ab-tester-meta-b"></span></div>
            <div class="ab-tester-response-b"></div>
            <div class="ab-tester-vote">
              <button class="ab-vote-btn" data-vote="b" title="Model B is better">👍 B wins</button>
            </div>
          </div>
        </div>
        <div class="ab-tester-history-panel" style="display:none">
          <h4>Comparison History</h4>
          <div class="ab-tester-history-list"></div>
          <button class="ab-tester-clear-history btn-secondary">Clear History</button>
        </div>
      </div>`;
    document.body.appendChild(_overlay);

    // Populate model selects
    const selA = _overlay.querySelector('.ab-model-a');
    const selB = _overlay.querySelector('.ab-model-b');
    ChatConfig.AVAILABLE_MODELS.forEach((m, i) => {
      selA.add(new Option(m.label, m.id));
      selB.add(new Option(m.label, m.id));
    });
    // Default: current model for A, next model for B
    selA.value = ChatConfig.MODEL;
    const models = ChatConfig.AVAILABLE_MODELS;
    const curIdx = models.findIndex(m => m.id === ChatConfig.MODEL);
    selB.value = models[(curIdx + 1) % models.length].id;

    // Events
    _overlay.querySelector('.ab-tester-close').onclick = toggle;
    _overlay.querySelector('.ab-tester-run').onclick = _run;
    _overlay.querySelector('.ab-tester-swap').onclick = () => {
      const tmp = selA.value; selA.value = selB.value; selB.value = tmp;
    };
    _overlay.querySelector('.ab-tester-clear').onclick = () => {
      _overlay.querySelector('.ab-tester-prompt').value = '';
      _overlay.querySelector('.ab-tester-results').style.display = 'none';
    };
    _overlay.querySelectorAll('.ab-vote-btn').forEach(btn => {
      btn.onclick = () => _vote(btn.dataset.vote);
    });
    _overlay.querySelector('.ab-tester-history-btn').onclick = _toggleHistory;
    _overlay.querySelector('.ab-tester-clear-history').onclick = () => {
      SafeStorage.remove(STORAGE_KEY);
      _renderHistory();
    };
    _overlay.addEventListener('click', e => { if (e.target === _overlay) toggle(); });
  }

  async function _callModel(key, model, prompt) {
    const messages = [
      { role: 'system', content: 'You are a helpful assistant.' },
      { role: 'user', content: prompt }
    ];
    const start = performance.now();
    const result = await OpenAIClient.complete({
      apiKey: key,
      model,
      messages,
      maxTokens: ChatConfig.MAX_TOKENS_RESPONSE,
    });
    const elapsed = Math.round(performance.now() - start);
    if (!result.ok) {
      return { ok: false, error: result.error, elapsed };
    }
    return { ok: true, text: result.content || '(empty response)', tokens: result.usage || {}, elapsed };
  }

  async function _run() {
    // Only use the session-scoped key from ApiKeyManager.
    // Previously this fell back to SafeStorage.get('ac-api-key') which
    // could read an API key persisted in localStorage in plain text —
    // a security risk since localStorage is accessible to any script
    // on the same origin and persists indefinitely.
    const key = ApiKeyManager?.getKey?.();
    if (!key) { alert('Please set your OpenAI API key first.'); return; }

    const prompt = _overlay.querySelector('.ab-tester-prompt').value.trim();
    if (!prompt) { alert('Enter a prompt to compare.'); return; }

    const modelA = _overlay.querySelector('.ab-model-a').value;
    const modelB = _overlay.querySelector('.ab-model-b').value;
    if (modelA === modelB) { alert('Select two different models to compare.'); return; }

    const results = _overlay.querySelector('.ab-tester-results');
    const respA = _overlay.querySelector('.ab-tester-response-a');
    const respB = _overlay.querySelector('.ab-tester-response-b');
    const metaA = _overlay.querySelector('.ab-tester-meta-a');
    const metaB = _overlay.querySelector('.ab-tester-meta-b');
    const lblA = _overlay.querySelector('.ab-model-label-a');
    const lblB = _overlay.querySelector('.ab-model-label-b');

    results.style.display = 'grid';
    respA.textContent = '⏳ Loading…';
    respB.textContent = '⏳ Loading…';
    lblA.textContent = modelA;
    lblB.textContent = modelB;
    metaA.textContent = '';
    metaB.textContent = '';

    _overlay.querySelector('.ab-tester-run').disabled = true;
    _overlay.querySelectorAll('.ab-vote-btn').forEach(b => { b.disabled = false; b.classList.remove('voted'); });

    const [rA, rB] = await Promise.all([
      _callModel(key, modelA, prompt),
      _callModel(key, modelB, prompt)
    ]);

    respA.textContent = rA.ok ? rA.text : `❌ ${rA.error}`;
    respB.textContent = rB.ok ? rB.text : `❌ ${rB.error}`;
    metaA.textContent = rA.ok ? ` - ${rA.elapsed}ms, ${rA.tokens.total_tokens || '?'} tok` : '';
    metaB.textContent = rB.ok ? ` - ${rB.elapsed}ms, ${rB.tokens.total_tokens || '?'} tok` : '';

    _overlay.querySelector('.ab-tester-run').disabled = false;

    // Save to history
    const entry = {
      ts: new Date().toISOString(),
      prompt: prompt.slice(0, 200),
      modelA, modelB,
      timeA: rA.elapsed, timeB: rB.elapsed,
      tokensA: rA.tokens?.total_tokens, tokensB: rB.tokens?.total_tokens,
      vote: null
    };
    _overlay._lastEntry = entry;
    const hist = _getHistory();
    hist.unshift(entry);
    _saveHistory(hist);
  }

  function _vote(winner) {
    if (!_overlay._lastEntry) return;
    const hist = _getHistory();
    if (hist.length && hist[0].ts === _overlay._lastEntry.ts) {
      hist[0].vote = winner;
      _saveHistory(hist);
    }
    _overlay.querySelectorAll('.ab-vote-btn').forEach(b => {
      b.disabled = true;
      if (b.dataset.vote === winner) b.classList.add('voted');
    });
  }

  function _toggleHistory() {
    const panel = _overlay.querySelector('.ab-tester-history-panel');
    const shown = panel.style.display !== 'none';
    panel.style.display = shown ? 'none' : 'block';
    if (!shown) _renderHistory();
  }

  function _renderHistory() {
    const list = _overlay.querySelector('.ab-tester-history-list');
    const hist = _getHistory();
    if (!hist.length) { list.innerHTML = '<p style="opacity:0.6">No comparisons yet.</p>'; return; }
    list.innerHTML = hist.map(h => `
      <div class="ab-history-item">
        <div class="ab-history-prompt">${_esc(h.prompt)}</div>
        <div class="ab-history-meta">
          ${h.modelA} (${h.timeA || '?'}ms) vs ${h.modelB} (${h.timeB || '?'}ms)
          ${h.vote ? `- <strong>${h.vote === 'a' ? h.modelA : h.modelB} won</strong>` : '- no vote'}
        </div>
      </div>
    `).join('');
  }

  const _esc = _escapeHtml;

  function toggle() {
    if (!_overlay) _build();
    _visible = !_visible;
    _overlay.classList.toggle('visible', _visible);
  }

  function init() {
    document.addEventListener('keydown', e => {
      if (e.ctrlKey && e.shiftKey && e.key === 'B') { e.preventDefault(); toggle(); }
    });
  }

  return { init, toggle };
})();

document.addEventListener('DOMContentLoaded', PromptABTester.init);

/* ---------- Smart Scroll ---------- */
/**
 * SmartScroll - floating "Jump to Latest" button, per-session scroll position
 * memory, and "new messages below" indicator.
 *
 * When the user scrolls away from the bottom of the chat output, a floating
 * button appears to quickly jump back.  An unread badge shows how many new
 * messages arrived while scrolled up.  Scroll positions are saved per session
 * so switching sessions restores where you left off.
 *
 * Shortcut: End key (when chat-input is not focused) jumps to bottom.
 *
 * @namespace SmartScroll
 */
const SmartScroll = (() => {
  const STORAGE_KEY = 'agenticchat_scroll_positions';
  const SCROLL_THRESHOLD = 200; // px from bottom to show button
  let _fab = null;
  let _badge = null;
  let _chatOutput = null;
  let _unreadCount = 0;
  let _isAtBottom = true;
  let _observer = null;

  /** Get saved scroll positions map. */
  function _getPositions() {
    return SafeStorage.getJSON(STORAGE_KEY, {});
  }

  /** Save scroll positions map. */
  function _savePositions(positions) {
    // Keep only most recent 100 entries to avoid bloat
    const keys = Object.keys(positions);
    if (keys.length > 100) {
      const sorted = keys.sort((a, b) => (positions[a].ts || 0) - (positions[b].ts || 0));
      const toRemove = sorted.slice(0, keys.length - 100);
      toRemove.forEach(k => delete positions[k]);
    }
    SafeStorage.setJSON(STORAGE_KEY, positions);
  }

  /** Save current scroll position for the active session. */
  function savePosition() {
    if (!_chatOutput) return;
    const activeId = SafeStorage.get('agenticchat_active_session');
    if (!activeId) return;
    const positions = _getPositions();
    positions[activeId] = {
      top: _chatOutput.scrollTop,
      ts: Date.now()
    };
    _savePositions(positions);
  }

  /** Restore scroll position for the active session. */
  function restorePosition() {
    if (!_chatOutput) return;
    const activeId = SafeStorage.get('agenticchat_active_session');
    if (!activeId) return;
    const positions = _getPositions();
    const saved = positions[activeId];
    if (saved && typeof saved.top === 'number') {
      _chatOutput.scrollTop = saved.top;
    }
  }

  /** Check if scrolled near bottom. */
  function _checkScrollPosition() {
    if (!_chatOutput) return;
    const distFromBottom = _chatOutput.scrollHeight - _chatOutput.scrollTop - _chatOutput.clientHeight;
    const wasAtBottom = _isAtBottom;
    _isAtBottom = distFromBottom < SCROLL_THRESHOLD;

    if (_fab) {
      _fab.classList.toggle('visible', !_isAtBottom);
    }

    // Clear unread when user scrolls to bottom
    if (_isAtBottom && !wasAtBottom) {
      _unreadCount = 0;
      _updateBadge();
    }
  }

  /** Update unread badge. */
  function _updateBadge() {
    if (!_badge) return;
    if (_unreadCount > 0) {
      _badge.textContent = _unreadCount > 99 ? '99+' : String(_unreadCount);
      _badge.style.display = 'flex';
    } else {
      _badge.style.display = 'none';
    }
  }

  /** Notify that a new message was added (called externally). */
  function onNewMessage() {
    if (!_isAtBottom) {
      _unreadCount++;
      _updateBadge();
    }
  }

  /** Scroll to bottom smoothly. */
  function scrollToBottom(smooth = true) {
    if (!_chatOutput) return;
    _chatOutput.scrollTo({
      top: _chatOutput.scrollHeight,
      behavior: smooth ? 'smooth' : 'instant'
    });
    _unreadCount = 0;
    _updateBadge();
  }

  /** Build the floating action button. */
  function _buildFAB() {
    _fab = document.createElement('div');
    _fab.id = 'smart-scroll-fab';
    _fab.className = 'smart-scroll-fab';
    _fab.setAttribute('role', 'button');
    _fab.setAttribute('aria-label', 'Jump to latest message');
    _fab.setAttribute('tabindex', '0');
    _fab.title = 'Jump to latest (End)';
    _fab.innerHTML = `<span class="smart-scroll-arrow">↓</span><span class="smart-scroll-badge" id="smart-scroll-badge"></span>`;

    _fab.addEventListener('click', () => scrollToBottom());
    _fab.addEventListener('keydown', e => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); scrollToBottom(); }
    });

    // Insert after chat output
    _chatOutput = DOMCache.get('chat-output');
    if (_chatOutput) {
      _chatOutput.parentElement.style.position = 'relative';
      _chatOutput.parentElement.appendChild(_fab);
      _badge = _fab.querySelector('#smart-scroll-badge');
    }
  }

  /** Observe new child elements in chat output for unread tracking. */
  function _observeNewMessages() {
    if (!_chatOutput || typeof MutationObserver === 'undefined') return;
    ChatOutputObserver.register('unreadTracking', function (mutations) {
      for (const m of mutations) {
        if (m.type === 'childList' && m.addedNodes.length > 0) {
          const added = [...m.addedNodes].filter(n => n.nodeType === Node.ELEMENT_NODE);
          if (added.length > 0 && !_isAtBottom) {
            _unreadCount += added.length;
            _updateBadge();
          }
        }
      }
    }, { subtree: false });
  }

  function init() {
    _chatOutput = DOMCache.get('chat-output');
    if (!_chatOutput) return;

    _buildFAB();
    _observeNewMessages();

    // Throttled scroll handler — combines position check and debounced save
    let _scrollTick = false;
    let _saveTick = null;
    _chatOutput.addEventListener('scroll', () => {
      if (!_scrollTick) {
        _scrollTick = true;
        requestAnimationFrame(() => {
          _checkScrollPosition();
          _scrollTick = false;
        });
      }
      clearTimeout(_saveTick);
      _saveTick = setTimeout(savePosition, 1000);
    }, { passive: true });
    window.addEventListener('beforeunload', savePosition);

    // End key shortcut
    document.addEventListener('keydown', e => {
      if (e.key === 'End' && document.activeElement?.id !== 'chat-input') {
        e.preventDefault();
        scrollToBottom();
      }
    });
  }

  return { init, scrollToBottom, onNewMessage, savePosition, restorePosition };
})();

document.addEventListener('DOMContentLoaded', SmartScroll.init);

// TextExpander.init already registered above (line ~22905) - skip duplicate

/* ---------- Message Reader View (module 65) ---------- */
/**
 * Opens any message in a clean, full-width reader overlay with larger text,
 * proper typography, and utility actions (copy, close). Especially useful
 * for long AI responses that are hard to read in the narrow chat column.
 *
 * Usage: double-click any message bubble, or click the 📖 expand icon that
 * appears on hover. Press Escape or click the backdrop to close.
 *
 * Public API:
 *   init()          - inject styles, wire event delegation
 *   open(el)        - open reader for a specific message element
 *   close()         - close the reader overlay
 *   toggle()        - open reader for the last assistant message, or close
 *   isOpen()        - whether the reader overlay is currently visible
 *
 * @namespace MessageReaderView
 */
const MessageReaderView = (() => {
  'use strict';

  let overlayEl = null;
  let currentSourceEl = null;

  // ── Styles ──

  function _injectStyles() {
    _injectCSS('reader-view-styles', `
      /* Reader overlay */
      .reader-overlay {
        position: fixed; inset: 0; z-index: 99999;
        background: rgba(0,0,0,0.7);
        display: flex; align-items: center; justify-content: center;
        opacity: 0; transition: opacity .2s ease;
        pointer-events: none;
      }
      .reader-overlay.active {
        opacity: 1; pointer-events: auto;
      }
      .reader-panel {
        background: var(--bg-primary, #1e1e2e);
        color: var(--text-primary, #cdd6f4);
        border-radius: 12px;
        width: min(90vw, 800px);
        max-height: 85vh;
        overflow-y: auto;
        padding: 2rem 2.5rem;
        box-shadow: 0 20px 60px rgba(0,0,0,0.5);
        font-size: 1.1rem;
        line-height: 1.8;
        position: relative;
      }
      .reader-panel pre {
        background: var(--bg-secondary, #181825);
        border-radius: 8px;
        padding: 1rem;
        overflow-x: auto;
        font-size: 0.95rem;
        line-height: 1.5;
      }
      .reader-panel code {
        font-family: 'Fira Code', 'Consolas', monospace;
      }
      .reader-panel p { margin: 0.8em 0; }
      .reader-panel h1, .reader-panel h2, .reader-panel h3 {
        margin-top: 1.2em; margin-bottom: 0.4em;
        color: var(--accent, #89b4fa);
      }
      .reader-panel ul, .reader-panel ol {
        padding-left: 1.5em; margin: 0.5em 0;
      }
      .reader-toolbar {
        display: flex; align-items: center; gap: 8px;
        margin-bottom: 1rem; padding-bottom: 0.8rem;
        border-bottom: 1px solid var(--border, #313244);
        position: sticky; top: 0;
        background: var(--bg-primary, #1e1e2e);
        z-index: 1;
      }
      .reader-toolbar .reader-label {
        flex: 1; font-size: 0.85rem; opacity: 0.6;
        text-transform: uppercase; letter-spacing: 0.05em;
      }
      .reader-toolbar button {
        background: var(--bg-secondary, #313244);
        color: var(--text-primary, #cdd6f4);
        border: none; border-radius: 6px;
        padding: 6px 14px; cursor: pointer;
        font-size: 0.85rem; transition: background .15s;
      }
      .reader-toolbar button:hover {
        background: var(--accent, #89b4fa);
        color: var(--bg-primary, #1e1e2e);
      }
      /* Hover expand icon on messages */
      .msg .reader-expand-icon {
        position: absolute; top: 4px; right: 4px;
        background: var(--bg-secondary, #313244);
        border: none; border-radius: 4px;
        color: var(--text-primary, #cdd6f4);
        font-size: 14px; padding: 2px 6px;
        cursor: pointer; opacity: 0;
        transition: opacity .15s;
        z-index: 10;
      }
      .msg:hover .reader-expand-icon { opacity: 0.7; }
      .msg .reader-expand-icon:hover { opacity: 1; }

      /* Font size controls */
      .reader-font-controls {
        display: flex; gap: 4px;
      }
      .reader-font-controls button {
        padding: 4px 10px; font-size: 0.8rem;
      }

      /* Light theme overrides */
      [data-theme="light"] .reader-panel {
        background: #fff; color: #1e1e2e;
        box-shadow: 0 20px 60px rgba(0,0,0,0.2);
      }
      [data-theme="light"] .reader-panel pre {
        background: #f5f5f5;
      }
      [data-theme="light"] .reader-toolbar {
        background: #fff;
        border-bottom-color: #e0e0e0;
      }
      [data-theme="light"] .reader-toolbar button {
        background: #e8e8e8; color: #333;
      }
    `);
  }

  // ── Overlay creation ──

  function _ensureOverlay() {
    if (overlayEl) return;
    overlayEl = document.createElement('div');
    overlayEl.className = 'reader-overlay';
    overlayEl.innerHTML = `
      <div class="reader-panel">
        <div class="reader-toolbar">
          <span class="reader-label">📖 Reader View</span>
          <div class="reader-font-controls">
            <button class="reader-font-down" title="Decrease font size">A-</button>
            <button class="reader-font-up" title="Increase font size">A+</button>
          </div>
          <button class="reader-copy-btn" title="Copy to clipboard">📋 Copy</button>
          <button class="reader-close-btn" title="Close (Escape)">✕</button>
        </div>
        <div class="reader-content"></div>
      </div>
    `;
    // Close on backdrop click
    overlayEl.addEventListener('click', e => {
      if (e.target === overlayEl) close();
    });
    // Close button
    overlayEl.querySelector('.reader-close-btn').addEventListener('click', close);
    // Copy button
    overlayEl.querySelector('.reader-copy-btn').addEventListener('click', () => {
      const content = overlayEl.querySelector('.reader-content');
      const text = content.innerText || content.textContent;
      const btn = overlayEl.querySelector('.reader-copy-btn');
      _copyToClipboard(text, { button: btn });
    });
    // Font size controls
    let fontSize = 1.1;
    overlayEl.querySelector('.reader-font-up').addEventListener('click', () => {
      fontSize = Math.min(fontSize + 0.1, 2.0);
      overlayEl.querySelector('.reader-content').style.fontSize = fontSize + 'rem';
    });
    overlayEl.querySelector('.reader-font-down').addEventListener('click', () => {
      fontSize = Math.max(fontSize - 0.1, 0.7);
      overlayEl.querySelector('.reader-content').style.fontSize = fontSize + 'rem';
    });

    document.body.appendChild(overlayEl);
  }

  // ── Public API ──

  function open(msgEl) {
    _injectStyles();
    _ensureOverlay();
    if (!msgEl) return;
    currentSourceEl = msgEl;
    const content = overlayEl.querySelector('.reader-content');
    // Clone the message content (innerHTML) for display
    content.innerHTML = msgEl.innerHTML;
    // Remove any existing expand icons from the cloned content
    content.querySelectorAll('.reader-expand-icon').forEach(el => el.remove());
    overlayEl.classList.add('active');
    // Trap focus
    overlayEl.querySelector('.reader-close-btn').focus();
  }

  function close() {
    if (overlayEl) {
      overlayEl.classList.remove('active');
    }
    currentSourceEl = null;
  }

  function toggle() {
    if (overlayEl && overlayEl.classList.contains('active')) {
      close();
      return;
    }
    // Open the last assistant message
    const msgs = document.querySelectorAll('.msg.assistant .content, .msg.assistant .msg-body');
    if (msgs.length > 0) {
      open(msgs[msgs.length - 1]);
    } else {
      // Fallback: try any message
      const all = document.querySelectorAll('.msg .content, .msg .msg-body');
      if (all.length > 0) open(all[all.length - 1]);
    }
  }

  function isOpen() {
    return !!(overlayEl && overlayEl.classList.contains('active'));
  }

  // ── Init: delegation + keyboard ──

  function init() {
    _injectStyles();

    // Double-click any message to open reader
    const chatArea = DOMCache.get('chat') || DOMCache.get('chat-output');
    if (chatArea) {
      chatArea.addEventListener('dblclick', e => {
        const msgEl = e.target.closest('.msg');
        if (!msgEl) return;
        const body = msgEl.querySelector('.content') || msgEl.querySelector('.msg-body') || msgEl;
        open(body);
      });
    }

    // Add expand icons to messages via MutationObserver
    function _addExpandIcon(msgEl) {
      if (msgEl.querySelector('.reader-expand-icon')) return;
      const btn = document.createElement('button');
      btn.className = 'reader-expand-icon';
      btn.textContent = '📖';
      btn.title = 'Open in Reader View';
      btn.addEventListener('click', e => {
        e.stopPropagation();
        const body = msgEl.querySelector('.content') || msgEl.querySelector('.msg-body') || msgEl;
        open(body);
      });
      msgEl.style.position = 'relative';
      msgEl.appendChild(btn);
    }

    if (chatArea) {
      // Add to existing messages
      chatArea.querySelectorAll('.msg').forEach(_addExpandIcon);
      // Watch for new messages
      ChatOutputObserver.register('readerViewExpand', function (mutations) {
        for (const m of mutations) {
          for (const node of m.addedNodes) {
            if (node.nodeType === 1) {
              if (node.classList && node.classList.contains('msg')) _addExpandIcon(node);
              else if (node.querySelectorAll) {
                node.querySelectorAll('.msg').forEach(_addExpandIcon);
              }
            }
          }
        }
      }, { subtree: true });
    }

    // Keyboard: Alt+R to toggle, Escape to close
    document.addEventListener('keydown', e => {
      if (e.altKey && e.key === 'r') {
        e.preventDefault();
        toggle();
      }
      if (e.key === 'Escape' && isOpen()) {
        e.preventDefault();
        close();
      }
    });
  }

  // Auto-init on DOM ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  return { init, open, close, toggle, isOpen };
})();


/* ============================================================
 *  ReadabilityAnalyzer - message readability scoring (Ctrl+Shift+R)
 *
 *  Computes Flesch-Kincaid grade level, reading ease, vocabulary
 *  diversity, average sentence/word lengths for user and assistant
 *  messages. Shows a slide-out panel with per-role stats and a
 *  per-message sparkline.
 * ============================================================ */
const ReadabilityAnalyzer = (() => {

  let panel = null;
  let visible = false;
  const STORAGE_KEY = 'ac-readability-visible';

  /* ── Syllable counter (English heuristic) ─────────────────── */
  function countSyllables(word) {
    word = word.toLowerCase().replace(/[^a-z]/g, '');
    if (word.length <= 2) return word.length ? 1 : 0;
    word = word.replace(/(?:[^laeiouy]es|ed|[^laeiouy]e)$/, '');
    word = word.replace(/^y/, '');
    const matches = word.match(/[aeiouy]{1,2}/g);
    return matches ? matches.length : 1;
  }

  /* ── Text metrics ─────────────────────────────────────────── */
  function analyzeText(text) {
    if (!text || !text.trim()) {
      return { sentences: 0, words: 0, syllables: 0, chars: 0, uniqueWords: 0,
               avgWordLen: 0, avgSentLen: 0, fleschEase: 0, fleschKincaid: 0, diversity: 0 };
    }

    // Strip code blocks to focus on prose
    const prose = text.replace(/```[\s\S]*?```/g, '').replace(/`[^`]+`/g, '').trim();
    if (!prose) {
      return { sentences: 0, words: 0, syllables: 0, chars: 0, uniqueWords: 0,
               avgWordLen: 0, avgSentLen: 0, fleschEase: 0, fleschKincaid: 0, diversity: 0 };
    }

    const sentences = prose.split(/[.!?]+/).filter(s => s.trim().length > 0);
    const words = prose.split(/\s+/).filter(w => /[a-zA-Z]/.test(w));

    const numSentences = Math.max(sentences.length, 1);
    const numWords = Math.max(words.length, 1);
    // Single pass over words: compute syllables, alpha-char count, and unique
    // lowercase forms in one iteration instead of three separate reduce/map calls.
    let totalSyllables = 0;
    let totalChars = 0;
    const wordSet = new Set();
    for (let i = 0; i < words.length; i++) {
      const w = words[i];
      totalSyllables += countSyllables(w);
      totalChars += w.replace(/[^a-zA-Z]/g, '').length;
      wordSet.add(w.toLowerCase().replace(/[^a-z]/g, ''));
    }

    const avgSentLen = numWords / numSentences;
    const avgSyllPerWord = totalSyllables / numWords;
    const avgWordLen = totalChars / numWords;

    // Flesch Reading Ease: 206.835 - 1.015*(words/sentences) - 84.6*(syllables/words)
    const fleschEase = Math.max(0, Math.min(100,
      206.835 - 1.015 * avgSentLen - 84.6 * avgSyllPerWord));

    // Flesch-Kincaid Grade Level: 0.39*(words/sentences) + 11.8*(syllables/words) - 15.59
    const fleschKincaid = Math.max(0,
      0.39 * avgSentLen + 11.8 * avgSyllPerWord - 15.59);

    const diversity = wordSet.size / numWords;

    return {
      sentences: numSentences, words: numWords, syllables: totalSyllables,
      chars: totalChars, uniqueWords: wordSet.size,
      avgWordLen: Math.round(avgWordLen * 10) / 10,
      avgSentLen: Math.round(avgSentLen * 10) / 10,
      fleschEase: Math.round(fleschEase * 10) / 10,
      fleschKincaid: Math.round(fleschKincaid * 10) / 10,
      diversity: Math.round(diversity * 100)
    };
  }

  function easeLabel(score) {
    if (score >= 80) return '📗 Very Easy';
    if (score >= 60) return '📘 Standard';
    if (score >= 40) return '📙 Fairly Difficult';
    if (score >= 20) return '📕 Difficult';
    return '📓 Very Difficult';
  }

  function gradeLabel(grade) {
    if (grade <= 5) return 'Elementary';
    if (grade <= 8) return 'Middle School';
    if (grade <= 12) return 'High School';
    if (grade <= 16) return 'College';
    return 'Post-Graduate';
  }

  /* ── Analysis across messages ─────────────────────────────── */
  function analyzeConversation() {
    const msgs = typeof ConversationManager !== 'undefined'
      ? ConversationManager.getUserMessages()
      : [];

    const userMsgs = msgs.filter(m => m.role === 'user');
    const assistantMsgs = msgs.filter(m => m.role === 'assistant');

    function aggregate(list) {
      if (list.length === 0) return analyzeText('');
      const metrics = list.map(m => analyzeText(m.content || ''));
      const total = key => metrics.reduce((s, m) => s + m[key], 0);
      const avg = key => Math.round((metrics.reduce((s, m) => s + m[key], 0) / metrics.length) * 10) / 10;
      return {
        msgCount: list.length,
        totalWords: total('words'),
        avgFleschEase: avg('fleschEase'),
        avgGrade: avg('fleschKincaid'),
        avgSentLen: avg('avgSentLen'),
        avgWordLen: avg('avgWordLen'),
        avgDiversity: avg('diversity'),
        perMessage: metrics
      };
    }

    return { user: aggregate(userMsgs), assistant: aggregate(assistantMsgs), all: msgs };
  }

  /* ── Sparkline renderer ───────────────────────────────────── */
  function sparkline(values, width, height, color) {
    if (values.length < 2) return '';
    // Use a loop instead of Math.min/max(...values) to avoid stack
    // overflow on large arrays (>100k response-time samples).
    let min = values[0], max = values[0];
    for (let i = 1; i < values.length; i++) {
      if (values[i] < min) min = values[i];
      if (values[i] > max) max = values[i];
    }
    const range = max - min || 1;
    const step = width / (values.length - 1);
    const points = values.map((v, i) =>
      `${(i * step).toFixed(1)},${(height - ((v - min) / range) * (height - 4) - 2).toFixed(1)}`
    ).join(' ');
    return `<svg width="${width}" height="${height}" style="display:block;margin:4px 0">
      <polyline points="${points}" fill="none" stroke="${color}" stroke-width="1.5"/>
    </svg>`;
  }

  /* ── Panel UI ─────────────────────────────────────────────── */
  function buildPanel() {
    if (panel) panel.remove();

    panel = document.createElement('div');
    panel.id = 'readability-panel';

    const style = document.createElement('style');
    style.textContent = `
      #readability-panel {
        position: fixed; top: 0; right: 0; width: 340px; height: 100vh;
        background: var(--bg-secondary, #1e1e2e); color: var(--text-primary, #cdd6f4);
        border-left: 1px solid var(--border-color, #45475a);
        z-index: 10200; display: flex; flex-direction: column;
        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        font-size: 13px; box-shadow: -4px 0 20px rgba(0,0,0,.3);
        transform: translateX(100%); transition: transform .25s ease;
      }
      #readability-panel.visible { transform: translateX(0); }
      #readability-panel .rp-header {
        display: flex; justify-content: space-between; align-items: center;
        padding: 14px 16px; border-bottom: 1px solid var(--border-color, #45475a);
        font-weight: 600; font-size: 15px;
      }
      #readability-panel .rp-close { cursor: pointer; background: none; border: none;
        color: inherit; font-size: 18px; padding: 4px 8px; border-radius: 4px; }
      #readability-panel .rp-close:hover { background: rgba(255,255,255,.1); }
      #readability-panel .rp-body { flex: 1; overflow-y: auto; padding: 12px 16px; }
      #readability-panel .rp-section { margin-bottom: 18px; }
      #readability-panel .rp-section h3 { font-size: 13px; text-transform: uppercase;
        letter-spacing: .5px; opacity: .7; margin: 0 0 8px; }
      #readability-panel .rp-row { display: flex; justify-content: space-between;
        padding: 3px 0; }
      #readability-panel .rp-label { opacity: .7; }
      #readability-panel .rp-value { font-weight: 600; }
      #readability-panel .rp-meter { height: 6px; border-radius: 3px;
        background: rgba(255,255,255,.1); margin: 4px 0 8px; }
      #readability-panel .rp-meter-fill { height: 100%; border-radius: 3px;
        transition: width .3s ease; }
      #readability-panel .rp-empty { text-align: center; padding: 40px 16px;
        opacity: .5; }
    `;
    panel.appendChild(style);

    const header = document.createElement('div');
    header.className = 'rp-header';
    header.innerHTML = '<span>📊 Readability</span>';
    const closeBtn = document.createElement('button');
    closeBtn.className = 'rp-close';
    closeBtn.textContent = '✕';
    closeBtn.addEventListener('click', toggle);
    header.appendChild(closeBtn);
    panel.appendChild(header);

    const body = document.createElement('div');
    body.className = 'rp-body';
    panel.appendChild(body);

    document.body.appendChild(panel);
    return panel;
  }

  function renderStats(data, container, label, color) {
    const sec = document.createElement('div');
    sec.className = 'rp-section';

    // Build all HTML in a single string to avoid repeated innerHTML +=
    // which forces the browser to re-parse and re-serialize the entire
    // subtree on every concatenation.
    const parts = [`<h3>${label}</h3>`];

    if (data.msgCount === 0) {
      parts.push('<div class="rp-empty">No messages yet</div>');
      sec.innerHTML = parts.join('');
      container.appendChild(sec);
      return;
    }

    const rows = [
      ['Messages', data.msgCount],
      ['Total Words', data.totalWords],
      ['Reading Ease', `${data.avgFleschEase} ${easeLabel(data.avgFleschEase).split(' ')[0]}`],
      ['Grade Level', `${data.avgGrade} (${gradeLabel(data.avgGrade)})`],
      ['Avg Sentence Len', `${data.avgSentLen} words`],
      ['Avg Word Len', `${data.avgWordLen} chars`],
      ['Vocabulary Diversity', `${data.avgDiversity}%`]
    ];

    rows.forEach(([lbl, val]) => {
      parts.push(`<div class="rp-row"><span class="rp-label">${lbl}</span><span class="rp-value">${val}</span></div>`);
    });

    // Reading ease meter
    parts.push(`<div class="rp-meter"><div class="rp-meter-fill" style="width:${data.avgFleschEase}%;background:${color}"></div></div>`);

    // Sparkline of per-message ease scores
    if (data.perMessage && data.perMessage.length >= 2) {
      const easeScores = data.perMessage.map(m => m.fleschEase);
      parts.push('<div class="rp-label" style="margin-top:8px">Ease over time:</div>');
      parts.push(sparkline(easeScores, 300, 40, color));
    }

    sec.innerHTML = parts.join('');
    container.appendChild(sec);
  }

  function refresh() {
    if (!panel) buildPanel();
    const body = panel.querySelector('.rp-body');
    body.innerHTML = '';

    const data = analyzeConversation();

    if (data.all.length === 0) {
      body.innerHTML = '<div class="rp-empty">Start a conversation to see readability stats</div>';
      return;
    }

    renderStats(data.user, body, '👤 Your Messages', '#89b4fa');
    renderStats(data.assistant, body, '🤖 AI Responses', '#a6e3a1');
  }

  function toggle() {
    if (!panel) buildPanel();
    visible = !visible;
    panel.classList.toggle('visible', visible);
    if (visible) refresh();
    SafeStorage.setJSON(STORAGE_KEY, visible);
  }

  function init() {
    // Keyboard shortcut: Ctrl+Shift+R
    document.addEventListener('keydown', e => {
      if (e.ctrlKey && e.shiftKey && e.key === 'R') {
        e.preventDefault();
        toggle();
      }
    });

    // Auto-refresh when messages change
    const chatArea = DOMCache.get('chat') || document.querySelector('.chat-area');
    if (chatArea) {
      const observer = new MutationObserver(() => { if (visible) refresh(); });
      observer.observe(chatArea, { childList: true, subtree: true });
    }

    // Restore visibility
    if (SafeStorage.getJSON(STORAGE_KEY, false)) {
      visible = true;
      buildPanel();
      panel.classList.add('visible');
      refresh();
    }
  }

  document.addEventListener('DOMContentLoaded', init);

  return { init, toggle, analyzeText, analyzeConversation, refresh };
})();

/* ---------- Message Diff Viewer ---------- */
/**
 * Compare any two messages side-by-side with word-level diff highlighting.
 * Useful for iterating on prompts or comparing assistant responses.
 *
 * Usage: Click the diff button (🔀) in the toolbar, then click two messages
 * to compare. Additions are highlighted green, deletions red.
 *
 * Keyboard shortcut: Ctrl+Shift+D
 *
 * @namespace MessageDiffViewer
 */
const MessageDiffViewer = (() => {
  let overlay = null;
  let selecting = false;
  let selectedIndices = [];
  const STORAGE_KEY = 'messageDiffHistory';
  const MAX_HISTORY = 20;

  /** Simple word-level diff using LCS (longest common subsequence). */
  function diffWords(textA, textB) {
    const wordsA = textA.split(/(\s+)/);
    const wordsB = textB.split(/(\s+)/);
    const m = wordsA.length, n = wordsB.length;

    // Build LCS table
    const dp = Array.from({ length: m + 1 }, () => new Uint16Array(n + 1));
    for (let i = 1; i <= m; i++) {
      for (let j = 1; j <= n; j++) {
        dp[i][j] = wordsA[i - 1] === wordsB[j - 1]
          ? dp[i - 1][j - 1] + 1
          : Math.max(dp[i - 1][j], dp[i][j - 1]);
      }
    }

    // Backtrack to produce diff
    const result = [];
    let i = m, j = n;
    while (i > 0 || j > 0) {
      if (i > 0 && j > 0 && wordsA[i - 1] === wordsB[j - 1]) {
        result.unshift({ type: 'equal', text: wordsA[i - 1] });
        i--; j--;
      } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
        result.unshift({ type: 'add', text: wordsB[j - 1] });
        j--;
      } else {
        result.unshift({ type: 'del', text: wordsA[i - 1] });
        i--;
      }
    }
    return result;
  }

  /** Render diff tokens to HTML. */
  function renderDiff(tokens) {
    return tokens.map(t => {
      if (t.type === 'add') return `<span style="background:#22543d;color:#68d391;text-decoration:none">${_escapeHtml(t.text)}</span>`;
      if (t.type === 'del') return `<span style="background:#553333;color:#fc8181;text-decoration:line-through">${_escapeHtml(t.text)}</span>`;
      return _escapeHtml(t.text);
    }).join('');
  }

  /** Compute diff stats. */
  function diffStats(tokens) {
    let added = 0, removed = 0, unchanged = 0;
    for (const t of tokens) {
      // Only count non-whitespace tokens
      if (t.text.trim() === '') continue;
      if (t.type === 'add') added++;
      else if (t.type === 'del') removed++;
      else unchanged++;
    }
    return { added, removed, unchanged, similarity: unchanged ? Math.round(unchanged / (unchanged + added + removed) * 100) : 0 };
  }

  /** Get message text content from DOM by index. */
  function getMessageText(index) {
    const output = DOMCache.get('chat-output');
    if (!output) return null;
    const msgs = output.querySelectorAll('.chat-msg');
    if (index < 0 || index >= msgs.length) return null;
    return msgs[index].textContent.trim();
  }

  /** Get message role from DOM. */
  function getMessageRole(index) {
    const output = DOMCache.get('chat-output');
    if (!output) return 'unknown';
    const msgs = output.querySelectorAll('.chat-msg');
    if (index < 0 || index >= msgs.length) return 'unknown';
    const text = msgs[index].textContent || '';
    return text.includes('You') ? 'user' : 'assistant';
  }

  /** Save diff to history. */
  function saveDiffHistory(indexA, indexB, stats) {
    try {
      const hist = SafeStorage.getJSON(STORAGE_KEY, []);
      hist.unshift({ indexA, indexB, stats, timestamp: Date.now() });
      if (hist.length > MAX_HISTORY) hist.length = MAX_HISTORY;
      SafeStorage.trySetJSON(STORAGE_KEY, hist);
    } catch (_) { /* ignore */ }
  }

  /** Start selection mode - user clicks two messages to compare. */
  function startSelection() {
    const output = DOMCache.get('chat-output');
    if (!output) return;
    const msgs = output.querySelectorAll('.chat-msg');
    if (msgs.length < 2) { alert('Need at least 2 messages to compare.'); return; }

    selecting = true;
    selectedIndices = [];

    // Add selection highlight styles
    msgs.forEach((msg, idx) => {
      msg.style.cursor = 'pointer';
      msg.style.transition = 'outline 0.15s';
      msg.dataset.diffIdx = idx;
      msg.addEventListener('click', _onMsgClick);
    });

    // Show instruction banner
    _showBanner('Click the first message to compare (1/2)');
  }

  function _onMsgClick(e) {
    const msg = e.currentTarget;
    const idx = parseInt(msg.dataset.diffIdx, 10);
    if (isNaN(idx)) return;

    selectedIndices.push(idx);
    msg.style.outline = '2px solid #38bdf8';

    if (selectedIndices.length === 1) {
      _showBanner('Click the second message to compare (2/2) - or Esc to cancel');
    } else if (selectedIndices.length >= 2) {
      _endSelection();
      showDiff(selectedIndices[0], selectedIndices[1]);
    }
  }

  function _endSelection() {
    selecting = false;
    const output = DOMCache.get('chat-output');
    if (output) {
      output.querySelectorAll('.chat-msg').forEach(msg => {
        msg.style.cursor = '';
        msg.style.outline = '';
        msg.removeEventListener('click', _onMsgClick);
        delete msg.dataset.diffIdx;
      });
    }
    _hideBanner();
  }

  function _showBanner(text) {
    let banner = DOMCache.get('diff-banner');
    if (!banner) {
      banner = document.createElement('div');
      banner.id = 'diff-banner';
      banner.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:10001;background:#1e3a5f;color:#fff;text-align:center;padding:10px 16px;font-size:14px;box-shadow:0 2px 8px rgba(0,0,0,0.3)';
      document.body.appendChild(banner);
    }
    banner.textContent = text;
    banner.style.display = 'block';
  }

  function _hideBanner() {
    const banner = DOMCache.get('diff-banner');
    if (banner) banner.style.display = 'none';
  }

  /** Show the diff overlay for two message indices. */
  function showDiff(indexA, indexB) {
    const textA = getMessageText(indexA);
    const textB = getMessageText(indexB);
    if (textA == null || textB == null) { alert('Could not read messages.'); return; }

    const roleA = getMessageRole(indexA);
    const roleB = getMessageRole(indexB);
    const tokens = diffWords(textA, textB);
    const stats = diffStats(tokens);
    saveDiffHistory(indexA, indexB, stats);

    // Build overlay using shared helper
    if (overlay) overlay.remove();
    const { overlay: _ov, modal: panel, close: _close } = createModalOverlay({
      overlayId: 'diff-viewer-overlay',
      maxWidth: '900px',
      background: '#1a1a2e',
    });
    overlay = _ov;
    overlay.style.padding = '20px';
    overlay.style.background = 'rgba(0,0,0,0.85)';
    panel.style.cssText = 'background:#1a1a2e;border:1px solid #333;border-radius:12px;width:90vw;max-width:900px;max-height:85vh;display:flex;flex-direction:column;overflow:hidden;padding:0';

    // Header
    const header = document.createElement('div');
    header.style.cssText = 'display:flex;justify-content:space-between;align-items:center;padding:16px 20px;border-bottom:1px solid #333';
    header.innerHTML = `
      <div>
        <span style="font-size:18px;font-weight:600">🔀 Message Diff</span>
        <span style="font-size:13px;color:#888;margin-left:12px">
          Message #${indexA + 1} (${roleA}) → #${indexB + 1} (${roleB})
        </span>
      </div>
      <button id="diff-close-btn" style="background:none;border:none;color:#aaa;font-size:20px;cursor:pointer" title="Close (Esc)">✕</button>
    `;

    // Stats bar
    const statsBar = document.createElement('div');
    statsBar.style.cssText = 'display:flex;gap:16px;padding:10px 20px;background:#111;font-size:13px;color:#aaa;border-bottom:1px solid #333';
    statsBar.innerHTML = `
      <span style="color:#68d391">+${stats.added} added</span>
      <span style="color:#fc8181">-${stats.removed} removed</span>
      <span>${stats.unchanged} unchanged</span>
      <span style="color:#63b3ed">${stats.similarity}% similar</span>
    `;

    // Tabs: unified / side-by-side
    const tabs = document.createElement('div');
    tabs.style.cssText = 'display:flex;gap:0;border-bottom:1px solid #333';
    tabs.innerHTML = `
      <button class="diff-tab active" data-view="unified" style="flex:1;padding:8px;background:#1a1a2e;border:none;border-bottom:2px solid #38bdf8;color:#fff;cursor:pointer;font-size:13px">Unified</button>
      <button class="diff-tab" data-view="sidebyside" style="flex:1;padding:8px;background:#1a1a2e;border:none;border-bottom:2px solid transparent;color:#888;cursor:pointer;font-size:13px">Side by Side</button>
    `;

    // Content area
    const content = document.createElement('div');
    content.style.cssText = 'flex:1;overflow-y:auto;padding:20px';

    function renderUnified() {
      content.innerHTML = `<div style="white-space:pre-wrap;line-height:1.8;font-size:14px;font-family:ui-monospace,'Cascadia Code',monospace">${renderDiff(tokens)}</div>`;
    }

    function renderSideBySide() {
      content.innerHTML = `
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
          <div>
            <div style="font-size:12px;color:#888;margin-bottom:8px;text-transform:uppercase">Message #${indexA + 1} (${roleA})</div>
            <div style="white-space:pre-wrap;line-height:1.6;font-size:13px;background:#111;padding:12px;border-radius:8px;border:1px solid #333;max-height:50vh;overflow-y:auto">${_escapeHtml(textA)}</div>
          </div>
          <div>
            <div style="font-size:12px;color:#888;margin-bottom:8px;text-transform:uppercase">Message #${indexB + 1} (${roleB})</div>
            <div style="white-space:pre-wrap;line-height:1.6;font-size:13px;background:#111;padding:12px;border-radius:8px;border:1px solid #333;max-height:50vh;overflow-y:auto">${_escapeHtml(textB)}</div>
          </div>
        </div>
      `;
    }

    renderUnified();

    tabs.addEventListener('click', e => {
      const btn = e.target.closest('.diff-tab');
      if (!btn) return;
      tabs.querySelectorAll('.diff-tab').forEach(t => {
        t.style.borderBottomColor = 'transparent';
        t.style.color = '#888';
        t.classList.remove('active');
      });
      btn.style.borderBottomColor = '#38bdf8';
      btn.style.color = '#fff';
      btn.classList.add('active');
      if (btn.dataset.view === 'unified') renderUnified();
      else renderSideBySide();
    });

    panel.appendChild(header);
    panel.appendChild(statsBar);
    panel.appendChild(tabs);
    panel.appendChild(content);

    // Close button
    header.querySelector('#diff-close-btn').addEventListener('click', close);
  }

  function close() {
    if (overlay) { overlay.remove(); overlay = null; }
  }

  function toggle() {
    if (overlay) { close(); return; }
    startSelection();
  }

  function init() {
    // Keyboard shortcut: Ctrl+Shift+D
    document.addEventListener('keydown', e => {
      if (e.ctrlKey && e.shiftKey && e.key === 'D') {
        e.preventDefault();
        toggle();
      }
      // Esc to cancel selection or close overlay
      if (e.key === 'Escape') {
        if (selecting) _endSelection();
        else if (overlay) close();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { init, toggle, showDiff, close, startSelection };
})();

/* ---------- Tone Adjuster ---------- */
/**
 * ToneAdjuster - rewrite assistant messages in different tones via the OpenAI API.
 *
 * Adds a 🎭 button to each assistant message in the history panel.
 * Clicking opens a tone picker (Formal, Casual, Concise, Detailed, ELI5, Poetic).
 * The selected tone rewrites the message content using the configured model.
 *
 * Keyboard shortcut: Alt+T (when hovering a message)
 *
 * @namespace ToneAdjuster
 */
const ToneAdjuster = (() => {
  const TONES = [
    { id: 'formal',   label: '🎩 Formal',   prompt: 'Rewrite the following text in a formal, professional tone. Preserve all information and meaning.' },
    { id: 'casual',   label: '😎 Casual',   prompt: 'Rewrite the following text in a casual, friendly, conversational tone. Preserve all information.' },
    { id: 'concise',  label: '✂️ Concise',   prompt: 'Rewrite the following text to be as concise as possible. Remove filler, keep all key information.' },
    { id: 'detailed', label: '📝 Detailed',  prompt: 'Rewrite the following text with more detail and explanation. Expand on key points.' },
    { id: 'eli5',     label: '🧒 ELI5',      prompt: 'Rewrite the following text as if explaining to a 5-year-old. Use simple words and analogies.' },
    { id: 'poetic',   label: '🎭 Poetic',    prompt: 'Rewrite the following text in a poetic, literary style with vivid language and metaphors.' },
  ];

  const CACHE_KEY = 'ac-tone-cache';
  let _cache = {};
  let _activePicker = null;

  function _loadCache() {
    try { _cache = SafeStorage.getJSON(CACHE_KEY, {}); } catch (_) { _cache = {}; }
  }
  function _saveCache() {
    SafeStorage.trySetJSON(CACHE_KEY, _cache);
  }

  /**
   * Generate a cache key for a message + tone combination.
   * @param {string} content - Original message content.
   * @param {string} toneId - Tone identifier.
   * @returns {string}
   */
  function _cacheKey(content, toneId) {
    // Simple hash: first 100 chars + length + tone
    return `${toneId}:${content.length}:${content.substring(0, 100)}`;
  }

  /**
   * Call the OpenAI API to rewrite text in the given tone.
   * @param {string} text - Original text to rewrite.
   * @param {Object} tone - Tone object with prompt.
   * @returns {Promise<string>} Rewritten text.
   */
  async function _rewrite(text, tone) {
    const key = _cacheKey(text, tone.id);
    if (_cache[key]) return _cache[key];

    const result = await OpenAIClient.complete({
      messages: [
        { role: 'system', content: tone.prompt },
        { role: 'user', content: text }
      ],
      maxTokens: 2048,
    });

    if (!result.ok) {
      throw new Error(result.error);
    }

    const rewritten = result.content || text;

    // Cache the result
    _cache[key] = result;
    _saveCache();

    // Track cost if CostDashboard is available
    if (typeof CostDashboard !== 'undefined' && data.usage) {
      CostDashboard.trackUsage(data.usage);
    }

    return result;
  }

  /**
   * Close the active tone picker dropdown.
   */
  function _closePicker() {
    if (_activePicker) {
      _activePicker.remove();
      _activePicker = null;
    }
  }

  /**
   * Show the tone picker dropdown near the button.
   * @param {HTMLElement} btn - The 🎭 button element.
   * @param {number} msgIndex - Index into displayed (non-system) messages.
   */
  function _showPicker(btn, msgIndex) {
    _closePicker();

    const history = typeof ConversationManager !== 'undefined' ? ConversationManager.getHistory() : [];
    // Map non-system index to actual history index
    let actualIdx = -1;
    let nonSysCount = 0;
    for (let i = 0; i < history.length; i++) {
      if (history[i].role === 'system') continue;
      if (nonSysCount === msgIndex) { actualIdx = i; break; }
      nonSysCount++;
    }
    if (actualIdx < 0 || history[actualIdx].role !== 'assistant') return;

    const originalContent = history[actualIdx].content;

    const picker = document.createElement('div');
    picker.className = 'tone-picker';
    picker.style.cssText = 'position:absolute;z-index:10000;background:#1a1a2e;border:1px solid #333;border-radius:8px;padding:6px 0;box-shadow:0 4px 16px rgba(0,0,0,0.4);min-width:160px;';

    // Title
    const title = document.createElement('div');
    title.textContent = '🎭 Adjust Tone';
    title.style.cssText = 'padding:6px 12px;font-size:11px;text-transform:uppercase;letter-spacing:0.05em;color:#888;border-bottom:1px solid #333;margin-bottom:4px;';
    picker.appendChild(title);

    for (const tone of TONES) {
      const item = document.createElement('div');
      item.textContent = tone.label;
      item.style.cssText = 'padding:8px 14px;cursor:pointer;font-size:13px;color:#e0e0e0;transition:background 0.15s;';
      item.addEventListener('mouseenter', () => { item.style.background = '#2a2a4a'; });
      item.addEventListener('mouseleave', () => { item.style.background = 'transparent'; });
      item.addEventListener('click', async () => {
        _closePicker();
        // Show loading state on the button
        const origBtnText = btn.textContent;
        btn.textContent = '⏳';
        btn.style.pointerEvents = 'none';
        try {
          const rewritten = await _rewrite(originalContent, tone);
          // Update the message in history
          history[actualIdx].content = rewritten;
          history[actualIdx]._originalContent = history[actualIdx]._originalContent || originalContent;
          history[actualIdx]._appliedTone = tone.id;
          // Re-render the history panel
          if (typeof HistoryPanel !== 'undefined' && HistoryPanel.refresh) {
            HistoryPanel.refresh();
          }
        } catch (err) {
          alert('Tone adjustment failed: ' + err.message);
        } finally {
          btn.textContent = origBtnText;
          btn.style.pointerEvents = '';
        }
      });
      picker.appendChild(item);
    }

    // "Restore Original" option if tone was already applied
    if (history[actualIdx]._originalContent) {
      const sep = document.createElement('div');
      sep.style.cssText = 'border-top:1px solid #333;margin:4px 0;';
      picker.appendChild(sep);

      const restore = document.createElement('div');
      restore.textContent = '↩️ Restore Original';
      restore.style.cssText = 'padding:8px 14px;cursor:pointer;font-size:13px;color:#f59e0b;transition:background 0.15s;';
      restore.addEventListener('mouseenter', () => { restore.style.background = '#2a2a4a'; });
      restore.addEventListener('mouseleave', () => { restore.style.background = 'transparent'; });
      restore.addEventListener('click', () => {
        _closePicker();
        history[actualIdx].content = history[actualIdx]._originalContent;
        delete history[actualIdx]._originalContent;
        delete history[actualIdx]._appliedTone;
        if (typeof HistoryPanel !== 'undefined' && HistoryPanel.refresh) {
          HistoryPanel.refresh();
        }
      });
      picker.appendChild(restore);
    }

    // Position the picker
    const rect = btn.getBoundingClientRect();
    picker.style.top = (rect.bottom + window.scrollY + 4) + 'px';
    picker.style.left = (rect.left + window.scrollX) + 'px';
    document.body.appendChild(picker);
    _activePicker = picker;

    // Close on outside click
    setTimeout(() => {
      const handler = (e) => {
        if (!picker.contains(e.target) && e.target !== btn) {
          _closePicker();
          document.removeEventListener('click', handler);
        }
      };
      document.addEventListener('click', handler);
    }, 0);
  }

  /**
   * Decorate a single assistant message element with the 🎭 tone button.
   * Called from _decorateAllMessages.
   * @param {HTMLElement} msgEl - The .history-msg element.
   * @param {number} displayIndex - Non-system message index.
   */
  function decorateOne(msgEl, displayIndex) {
    if (msgEl.querySelector('.tone-btn')) return; // already decorated

    const btn = document.createElement('button');
    btn.className = 'tone-btn';
    btn.textContent = '🎭';
    btn.title = 'Adjust message tone (Alt+T)';
    btn.style.cssText = 'background:none;border:none;cursor:pointer;font-size:14px;padding:2px 4px;opacity:0.5;transition:opacity 0.2s;margin-left:6px;';
    btn.addEventListener('mouseenter', () => { btn.style.opacity = '1'; });
    btn.addEventListener('mouseleave', () => { btn.style.opacity = '0.5'; });
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      _showPicker(btn, displayIndex);
    });

    // Insert after the role label
    const roleLabel = msgEl.querySelector('.msg-role');
    if (roleLabel) {
      roleLabel.appendChild(btn);
    } else {
      msgEl.insertBefore(btn, msgEl.firstChild);
    }
  }

  function init() {
    _loadCache();

    // Close picker on Escape
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && _activePicker) {
        _closePicker();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { init, decorateOne, TONES };
})();

/* ---------- Response Length Presets ---------- */
/**
 * Pre-send response length control. Lets users choose how verbose
 * the AI's responses should be (Concise / Normal / Detailed / Exhaustive).
 *
 * Adjusts ChatConfig.MAX_TOKENS_RESPONSE and prepends a length instruction
 * to the system prompt so the model follows the desired verbosity.
 * Persists preference to localStorage. Toggle with Alt+L.
 *
 * @namespace ResponseLengthPresets
 */
const ResponseLengthPresets = (() => {
  const STORAGE_KEY = 'ac-response-length';
  const PRESETS = [
    {
      id: 'concise',
      label: 'Concise',
      icon: '⚡',
      maxTokens: 1024,
      instruction: 'Keep your response very concise and to the point. Use short sentences, minimal explanation. Aim for the shortest useful answer.',
      description: 'Short & direct - bullet points, minimal prose'
    },
    {
      id: 'normal',
      label: 'Normal',
      icon: '💬',
      maxTokens: 4096,
      instruction: '',
      description: 'Default response length - balanced detail'
    },
    {
      id: 'detailed',
      label: 'Detailed',
      icon: '📖',
      maxTokens: 8192,
      instruction: 'Provide a thorough, detailed response. Include explanations, examples, and context. Cover edge cases when relevant.',
      description: 'Thorough - examples, explanations, context'
    },
    {
      id: 'exhaustive',
      label: 'Exhaustive',
      icon: '📚',
      maxTokens: 16384,
      instruction: 'Provide the most comprehensive, exhaustive response possible. Cover all aspects in depth with extensive examples, step-by-step breakdowns, alternative approaches, trade-offs, and edge cases. Leave nothing out.',
      description: 'Maximum depth - comprehensive coverage'
    }
  ];

  let currentPreset = 'normal';
  let panelEl = null;
  let isOpen = false;

  // Original system prompt (without length instruction)
  let _baseSystemPrompt = null;

  function _load() {
    try {
      const saved = SafeStorage.get(STORAGE_KEY);
      if (saved && PRESETS.some(p => p.id === saved)) {
        currentPreset = saved;
      }
    } catch (_) {}
  }

  function _save() {
    SafeStorage.trySet(STORAGE_KEY, currentPreset);
  }

  function _getPreset(id) {
    return PRESETS.find(p => p.id === id) || PRESETS[1];
  }

  function _apply() {
    const preset = _getPreset(currentPreset);

    // Update max tokens
    ChatConfig.MAX_TOKENS_RESPONSE = preset.maxTokens;

    // Update system prompt: strip any previous length instruction, then prepend new one
    if (_baseSystemPrompt === null) {
      _baseSystemPrompt = ChatConfig.SYSTEM_PROMPT;
    }

    if (preset.instruction) {
      ChatConfig.SYSTEM_PROMPT = `[Response length: ${preset.label}] ${preset.instruction}\n\n${_baseSystemPrompt}`;
    } else {
      ChatConfig.SYSTEM_PROMPT = _baseSystemPrompt;
    }

    // Update the system message in conversation history
    const msgs = ConversationManager.getMessages();
    if (msgs.length > 0 && msgs[0].role === 'system') {
      ConversationManager.setSystemPrompt(ChatConfig.SYSTEM_PROMPT);
    }

    // Update button label
    const label = DOMCache.get('length-label');
    if (label) label.textContent = preset.label;

    _save();
  }

  function _createPanel() {
    if (panelEl) return panelEl;

    panelEl = document.createElement('div');
    panelEl.className = 'length-preset-panel';
    panelEl.setAttribute('role', 'dialog');
    panelEl.setAttribute('aria-label', 'Response Length Presets');

    let html = '<div class="length-preset-header">📏 Response Length</div>';
    html += '<div class="length-preset-list">';

    for (const preset of PRESETS) {
      html += `<button class="length-preset-option" data-preset="${preset.id}" title="${preset.description}">
        <span class="length-preset-icon">${preset.icon}</span>
        <div class="length-preset-info">
          <span class="length-preset-name">${preset.label}</span>
          <span class="length-preset-desc">${preset.description}</span>
        </div>
        <span class="length-preset-check" style="visibility:hidden">✓</span>
      </button>`;
    }

    html += '</div>';
    html += '<div class="length-preset-footer">Adjusts response verbosity and max tokens</div>';
    panelEl.innerHTML = html;

    panelEl.addEventListener('click', (e) => {
      const btn = e.target.closest('.length-preset-option');
      if (!btn) return;
      const id = btn.dataset.preset;
      if (id) {
        currentPreset = id;
        _apply();
        _updateChecks();
        // Brief visual feedback before closing
        setTimeout(() => toggle(), 150);
      }
    });

    document.body.appendChild(panelEl);
    return panelEl;
  }

  function _updateChecks() {
    if (!panelEl) return;
    panelEl.querySelectorAll('.length-preset-check').forEach(el => {
      el.style.visibility = 'hidden';
    });
    const active = panelEl.querySelector(`[data-preset="${currentPreset}"] .length-preset-check`);
    if (active) active.style.visibility = 'visible';
  }

  function _positionPanel() {
    const btn = DOMCache.get('length-preset-btn');
    if (!btn || !panelEl) return;
    const rect = btn.getBoundingClientRect();
    panelEl.style.top = (rect.bottom + 6) + 'px';
    panelEl.style.left = Math.max(8, rect.left - 100) + 'px';
  }

  function toggle() {
    _createPanel();
    isOpen = !isOpen;
    panelEl.style.display = isOpen ? 'block' : 'none';
    if (isOpen) {
      _updateChecks();
      _positionPanel();
    }
  }

  function getCurrentPreset() {
    return currentPreset;
  }

  function init() {
    _load();
    _apply();

    // Close on outside click
    document.addEventListener('click', (e) => {
      if (isOpen && panelEl && !panelEl.contains(e.target) &&
          !e.target.closest('#length-preset-btn')) {
        isOpen = false;
        panelEl.style.display = 'none';
      }
    });

    // Alt+L shortcut
    document.addEventListener('keydown', (e) => {
      if (e.altKey && e.key.toLowerCase() === 'l' && !e.ctrlKey && !e.shiftKey && !e.metaKey) {
        e.preventDefault();
        toggle();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { toggle, getCurrentPreset, PRESETS, init };
})();

/* ---------- Session Archive ---------- */
/**
 * Archive sessions to hide them from the main sessions list without
 * deleting them. Archived sessions can be revealed via a toggle in the
 * sessions toolbar. Each session card gets an archive/unarchive button.
 *
 * Storage: a JSON array of archived session IDs in localStorage.
 *
 * Keyboard shortcut: none (accessed via sessions panel UI).
 *
 * @namespace SessionArchive
 */
const SessionArchive = (() => {
  const STORAGE_KEY = 'agenticchat_archived_sessions';
  let _showArchived = false;

  /** Load archived IDs set. */
  function _load() {
    try {
      const raw = SafeStorage.get(STORAGE_KEY);
      return new Set(_safeParse(raw, []));
    } catch { return new Set(); }
  }

  /** Save archived IDs set. */
  function _save(ids) {
    SafeStorage.trySetJSON(STORAGE_KEY, [...ids]);
  }

  /** Check if a session is archived. */
  function isArchived(id) {
    return _load().has(id);
  }

  /** Archive a session. */
  function archive(id) {
    const ids = _load();
    ids.add(id);
    _save(ids);
  }

  /** Unarchive a session. */
  function unarchive(id) {
    const ids = _load();
    ids.delete(id);
    _save(ids);
  }

  /** Toggle archive state for a session. Returns new archived state. */
  function toggle(id) {
    const ids = _load();
    if (ids.has(id)) {
      ids.delete(id);
      _save(ids);
      return false;
    } else {
      ids.add(id);
      _save(ids);
      return true;
    }
  }

  /** Whether the panel is showing archived sessions. */
  function isShowingArchived() { return _showArchived; }

  /** Toggle visibility of archived sessions. */
  function toggleShowArchived() {
    _showArchived = !_showArchived;
    return _showArchived;
  }

  /** Set showing state explicitly. */
  function setShowArchived(val) { _showArchived = !!val; }

  /** Filter sessions based on archive state. */
  function filterSessions(sessions) {
    const archivedIds = _load();
    if (_showArchived) {
      // Show only archived
      return sessions.filter(s => archivedIds.has(s.id));
    }
    // Default: hide archived
    return sessions.filter(s => !archivedIds.has(s.id));
  }

  /** Get count of archived sessions. */
  function getArchivedCount() {
    return _load().size;
  }

  /** Clean up archived IDs for sessions that no longer exist. */
  function cleanup(existingIds) {
    const archived = _load();
    const existing = new Set(existingIds);
    let changed = false;
    for (const id of archived) {
      if (!existing.has(id)) {
        archived.delete(id);
        changed = true;
      }
    }
    if (changed) _save(archived);
  }

  return {
    isArchived, archive, unarchive, toggle,
    isShowingArchived, toggleShowArchived, setShowArchived,
    filterSessions, getArchivedCount, cleanup
  };
})();

/* ---------- Session Calendar ---------- */
/**
 * Visual month-calendar showing sessions by date. Click a day to see
 * its sessions; click a session to load it. Navigate months with arrows.
 *
 * Keyboard shortcut: Alt+C
 *
 * @namespace SessionCalendar
 */
const SessionCalendar = (() => {
  let isOpen = false;
  let viewYear, viewMonth; // 0-indexed month
  let selectedDate = null; // 'YYYY-MM-DD'

  function _allSessions() {
    try {
      const raw = SafeStorage.get('agenticchat_sessions');
      return _safeParse(raw, []);
    } catch { return []; }
  }

  /** Build a map of 'YYYY-MM-DD' → [sessions]. */
  function _sessionsByDate(sessions) {
    const map = {};
    for (const s of sessions) {
      const ts = s.updatedAt || s.createdAt || s.savedAt;
      if (!ts) continue;
      const d = new Date(ts);
      if (isNaN(d)) continue;
      const key = d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
      (map[key] = map[key] || []).push(s);
    }
    return map;
  }

  function _render() {
    const grid = DOMCache.get('calendar-grid');
    const titleEl = DOMCache.get('calendar-title');
    const dayPanel = DOMCache.get('calendar-day-sessions');
    if (!grid || !titleEl) return;

    const sessions = _allSessions();
    const dateMap = _sessionsByDate(sessions);

    const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
    titleEl.textContent = months[viewMonth] + ' ' + viewYear;

    const today = new Date();
    const todayKey = today.getFullYear() + '-' + String(today.getMonth() + 1).padStart(2, '0') + '-' + String(today.getDate()).padStart(2, '0');

    const firstDay = new Date(viewYear, viewMonth, 1).getDay();
    const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();
    const daysInPrev = new Date(viewYear, viewMonth, 0).getDate();

    let html = '';
    const dayNames = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    for (const dn of dayNames) html += `<div class="cal-head">${dn}</div>`;

    for (let i = firstDay - 1; i >= 0; i--) {
      html += `<div class="cal-day empty other-month">${daysInPrev - i}</div>`;
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const key = viewYear + '-' + String(viewMonth + 1).padStart(2, '0') + '-' + String(d).padStart(2, '0');
      const cls = [];
      if (key === todayKey) cls.push('today');
      if (dateMap[key]) cls.push('has-sessions');
      if (key === selectedDate) cls.push('selected');
      html += `<div class="cal-day ${cls.join(' ')}" data-date="${key}">${d}</div>`;
    }

    const totalCells = firstDay + daysInMonth;
    const remaining = totalCells % 7 === 0 ? 0 : 7 - (totalCells % 7);
    for (let d = 1; d <= remaining; d++) {
      html += `<div class="cal-day empty other-month">${d}</div>`;
    }

    grid.innerHTML = html;

    grid.querySelectorAll('.cal-day:not(.empty)').forEach(el => {
      el.addEventListener('click', () => {
        const date = el.dataset.date;
        if (!date) return;
        selectedDate = date;
        _render();
        _renderDaySessions(dateMap[date] || []);
      });
    });

    if (selectedDate && dateMap[selectedDate]) {
      _renderDaySessions(dateMap[selectedDate]);
    } else if (dayPanel) {
      dayPanel.innerHTML = '<div class="cal-no-sessions">Click a day to see sessions</div>';
    }
  }

  function _renderDaySessions(sessions) {
    const dayPanel = DOMCache.get('calendar-day-sessions');
    if (!dayPanel) return;
    if (!sessions.length) {
      dayPanel.innerHTML = '<div class="cal-no-sessions">No sessions on this day</div>';
      return;
    }
    sessions.sort((a, b) => new Date(b.updatedAt || b.createdAt || 0) - new Date(a.updatedAt || a.createdAt || 0));
    let html = '';
    for (const s of sessions) {
      const name = s.name || 'Untitled';
      const msgCount = (s.messages || s.history || []).length;
      const time = new Date(s.updatedAt || s.createdAt || 0);
      const timeStr = time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
      html += `<div class="cal-session-item" data-sid="${s.id}">
        <span class="cal-session-name">${name}</span>
        <span class="cal-session-msgs">${timeStr} · ${msgCount} msgs</span>
      </div>`;
    }
    dayPanel.innerHTML = html;

    dayPanel.querySelectorAll('.cal-session-item').forEach(el => {
      el.addEventListener('click', () => {
        const sid = el.dataset.sid;
        if (sid && typeof SessionManager !== 'undefined' && SessionManager.load) {
          SessionManager.load(sid);
          close();
        }
      });
    });
  }

  function open() {
    const now = new Date();
    if (viewYear == null) { viewYear = now.getFullYear(); viewMonth = now.getMonth(); }
    isOpen = true;
    const panel = DOMCache.get('calendar-panel');
    const overlay = DOMCache.get('calendar-overlay');
    if (panel) panel.style.display = 'block';
    if (overlay) overlay.style.display = 'block';
    _render();
  }

  function close() {
    isOpen = false;
    const panel = DOMCache.get('calendar-panel');
    const overlay = DOMCache.get('calendar-overlay');
    if (panel) panel.style.display = 'none';
    if (overlay) overlay.style.display = 'none';
  }

  function toggle() { isOpen ? close() : open(); }

  function init() {
    DOMCache.get('calendar-prev')?.addEventListener('click', () => {
      viewMonth--;
      if (viewMonth < 0) { viewMonth = 11; viewYear--; }
      selectedDate = null;
      _render();
    });
    DOMCache.get('calendar-next')?.addEventListener('click', () => {
      viewMonth++;
      if (viewMonth > 11) { viewMonth = 0; viewYear++; }
      selectedDate = null;
      _render();
    });
    DOMCache.get('calendar-today-btn')?.addEventListener('click', () => {
      const now = new Date();
      viewYear = now.getFullYear(); viewMonth = now.getMonth();
      selectedDate = null;
      _render();
    });
    DOMCache.get('calendar-close-btn')?.addEventListener('click', close);
    DOMCache.get('calendar-overlay')?.addEventListener('click', close);

    document.addEventListener('keydown', (e) => {
      if (e.altKey && e.key.toLowerCase() === 'c' && !e.ctrlKey && !e.shiftKey && !e.metaKey) {
        e.preventDefault();
        toggle();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { open, close, toggle, init };
})();

/* ============================================================
 *  WordCloudGenerator  (Alt+W)
 *  Generates a visual word cloud from conversation messages
 *  using HTML5 Canvas. No external dependencies.
 * ============================================================ */
const WordCloudGenerator = (() => {
  let isOpen = false;
  const STOP_WORDS = new Set([...COMMON_STOP_WORDS,
    'year', 'else', 'dont', 'im', 'youre', 'hes', 'shes',
    'theyre', 'wont', 'cant', 'isnt', 'arent', 'wasnt',
    'werent', 'hasnt', 'havent', 'hadnt', 'doesnt', 'didnt',
    'thats', 'whats', 'whos', 'wheres', 'whens', 'hows',
    'doing', 'done', 'said', 'went', 'going', 'got', 'getting',
  ]);

  /**
   * Build word-frequency list for the word cloud.
   * Optimised: builds frequency map in a single pass per message
   * without concatenating all content into one giant string.
   * Eliminates the intermediate filtered array, the joined text
   * string, the lowercased copy, the replaced copy, the split
   * array, and the filter pass — each of which previously
   * allocated O(totalChars) or O(totalWords) temporaries.
   */
  const _WCG_WORD_RE = /[a-z0-9'-]{3,}/g;
  function _extractWords(source) {
    const messages = (typeof ConversationManager !== 'undefined' && ConversationManager.getHistory)
      ? ConversationManager.getHistory() : [];
    const freq = Object.create(null);
    for (let i = 0; i < messages.length; i++) {
      const m = messages[i];
      if (source === 'user' && m.role !== 'user') continue;
      if (source === 'assistant' && m.role !== 'assistant') continue;
      if (m.role !== 'user' && m.role !== 'assistant') continue;
      const lower = (m.content || '').toLowerCase();
      _WCG_WORD_RE.lastIndex = 0;
      let match;
      while ((match = _WCG_WORD_RE.exec(lower)) !== null) {
        const w = match[0];
        if (!STOP_WORDS.has(w)) freq[w] = (freq[w] || 0) + 1;
      }
    }
    return Object.entries(freq).sort((a, b) => b[1] - a[1]).slice(0, 80);
  }

  // Cached DOM references — avoids repeated getElementById on every
  // render/open/close/download cycle (this module was the last holdout
  // still using raw getElementById instead of DOMCache).
  let _els = null;
  function _dom(id) {
    if (!_els) _els = {};
    if (!_els[id]) _els[id] = DOMCache.get(id);
    return _els[id];
  }

  function _render() {
    const canvas = _dom('wordcloud-canvas');
    const emptyEl = _dom('wordcloud-empty');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const source = _dom('wordcloud-source')?.value || 'all';
    const words = _extractWords(source);
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    if (words.length === 0) {
      canvas.style.display = 'none';
      if (emptyEl) emptyEl.style.display = '';
      return;
    }
    canvas.style.display = '';
    if (emptyEl) emptyEl.style.display = 'none';

    const maxFreq = words[0][1];
    const minSize = 12, maxSize = 56;
    const colors = ['#FF6B6B','#4ECDC4','#45B7D1','#96CEB4','#FFEAA7','#DDA0DD','#98D8C8','#F7DC6F','#BB8FCE','#85C1E9','#F0B27A','#82E0AA'];
    const isDark = !document.body.classList.contains('light');
    // Spatial grid for O(1) amortised collision detection instead of
    // O(placed) linear scan per candidate position.  Each cell is 64px;
    // only cells overlapping a candidate rectangle are checked.
    const CELL = 64;
    const gridCols = Math.ceil(canvas.width / CELL);
    const gridRows = Math.ceil(canvas.height / CELL);
    const grid = Array.from({ length: gridRows * gridCols }, () => []);

    function _gridInsert(rect) {
      const c0 = Math.max(0, (rect.x / CELL) | 0);
      const c1 = Math.min(gridCols - 1, ((rect.x + rect.w) / CELL) | 0);
      const r0 = Math.max(0, ((rect.y - rect.h) / CELL) | 0);
      const r1 = Math.min(gridRows - 1, (rect.y / CELL) | 0);
      for (let r = r0; r <= r1; r++) {
        for (let c = c0; c <= c1; c++) {
          grid[r * gridCols + c].push(rect);
        }
      }
    }

    // Generation counter for deduplication — avoids allocating a new Set
    // on every _gridOverlaps call (thousands of calls during spiral placement).
    let _overlapGen = 0;

    function _gridOverlaps(x, y, w, h) {
      const c0 = Math.max(0, (x / CELL) | 0);
      const c1 = Math.min(gridCols - 1, ((x + w) / CELL) | 0);
      const r0 = Math.max(0, ((y - h) / CELL) | 0);
      const r1 = Math.min(gridRows - 1, (y / CELL) | 0);
      const gen = ++_overlapGen;
      for (let r = r0; r <= r1; r++) {
        for (let c = c0; c <= c1; c++) {
          const bucket = grid[r * gridCols + c];
          for (let i = 0; i < bucket.length; i++) {
            const p = bucket[i];
            if (p._gen === gen) continue;
            p._gen = gen;
            if (!(x + w < p.x || x > p.x + p.w || y - h > p.y || y < p.y - p.h)) return true;
          }
        }
      }
      return false;
    }

    words.forEach(([word, freq], idx) => {
      const size = Math.max(minSize, Math.round((freq / maxFreq) * maxSize));
      const color = isDark ? colors[idx % colors.length] : colors[(idx + 3) % colors.length];
      ctx.font = `bold ${size}px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif`;
      const metrics = ctx.measureText(word);
      const w = metrics.width + 4;
      const h = size + 4;

      let bestX = canvas.width / 2, bestY = canvas.height / 2;
      let foundSpot = false;
      // Spiral placement with spatial-grid collision detection
      for (let r = 0; r < 300 && !foundSpot; r += 2) {
        for (let a = 0; a < 360 && !foundSpot; a += 15) {
          const rad = (a * Math.PI) / 180;
          const x = canvas.width / 2 + r * Math.cos(rad) - w / 2;
          const y = canvas.height / 2 + r * Math.sin(rad) + h / 4;
          if (x < 5 || y < 5 || x + w > canvas.width - 5 || y > canvas.height - 5 || y - h < 0) continue;
          if (!_gridOverlaps(x, y, w, h)) {
            bestX = x; bestY = y; foundSpot = true;
          }
        }
      }
      if (foundSpot) {
        ctx.fillStyle = color;
        ctx.font = `bold ${size}px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif`;
        ctx.fillText(word, bestX, bestY);
        const rect = { x: bestX, y: bestY, w, h };
        _gridInsert(rect);
      }
    });
  }

  function open() {
    isOpen = true;
    const panel = _dom('wordcloud-panel');
    const overlay = _dom('wordcloud-overlay');
    if (panel) panel.style.display = '';
    if (overlay) overlay.style.display = '';
    _render();
  }

  function close() {
    isOpen = false;
    const panel = _dom('wordcloud-panel');
    const overlay = _dom('wordcloud-overlay');
    if (panel) panel.style.display = 'none';
    if (overlay) overlay.style.display = 'none';
  }

  function toggle() { isOpen ? close() : open(); }

  function download() {
    const canvas = _dom('wordcloud-canvas');
    if (!canvas) return;
    const a = document.createElement('a');
    a.download = 'word-cloud.png';
    a.href = canvas.toDataURL('image/png');
    a.click();
  }

  function init() {
    _dom('wordcloud-close')?.addEventListener('click', close);
    _dom('wordcloud-overlay')?.addEventListener('click', close);
    _dom('wordcloud-refresh')?.addEventListener('click', _render);
    _dom('wordcloud-download')?.addEventListener('click', download);
    _dom('wordcloud-source')?.addEventListener('change', _render);
    document.addEventListener('keydown', (e) => {
      if (e.altKey && e.key.toLowerCase() === 'w' && !e.ctrlKey && !e.shiftKey && !e.metaKey) {
        e.preventDefault();
        toggle();
      }
    });
  }

  document.addEventListener('DOMContentLoaded', init);

  return { open, close, toggle, init };
})();

/**
 * TypingIndicatorBubble — animated "AI is thinking" indicator.
 *
 * Shows a three-dot bounce animation with a randomly selected label
 * (e.g. "Generating response…") inside #chat-output while waiting for
 * the API response. Accessible via role="status" and aria-label.
 * Automatically removed when the response arrives or on manual hide().
 *
 * @module TypingIndicatorBubble
 * @returns {{ show: Function, hide: Function, isVisible: Function }}
 */
// ── Pin Board ──────────────────────────────────────────────────
const TypingIndicatorBubble = (() => {
  let _el = null;
  const LABELS = [
    'AI is thinking…',
    'Generating response…',
    'Processing your request…',
    'Crafting a reply…',
    'Working on it…',
  ];

  function _randomLabel() {
    return LABELS[Math.floor(Math.random() * LABELS.length)];
  }

  /** Show the typing indicator bubble inside #chat-output. */
  function show() {
    hide(); // remove any existing
    _el = document.createElement('div');
    _el.className = 'typing-indicator';
    _el.setAttribute('role', 'status');
    _el.setAttribute('aria-label', 'AI is typing');
    _el.innerHTML =
      '<div class="typing-indicator__dots">' +
        '<span class="typing-indicator__dot"></span>' +
        '<span class="typing-indicator__dot"></span>' +
        '<span class="typing-indicator__dot"></span>' +
      '</div>' +
      '<span class="typing-indicator__label">' + _randomLabel() + '</span>';
    const chatOutput = DOMCache.get('chat-output');
    if (chatOutput) {
      chatOutput.appendChild(_el);
      _el.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }

  /** Remove the typing indicator bubble. */
  function hide() {
    if (_el && _el.parentNode) {
      _el.parentNode.removeChild(_el);
    }
    _el = null;
  }

  /** Check if currently visible. */
  function isVisible() { return !!_el && !!_el.parentNode; }

  return { show, hide, isVisible };
})();

/**
 * PinBoard — persistent cross-session message pin collection.
 *
 * Allows users to pin any message (user or assistant) to a global board
 * that persists across sessions. Each pin records role, content (truncated
 * to 5 KB), optional notes, tags, and the originating session name.
 * Provides a slide-out panel with search, tag filtering, copy-to-clipboard,
 * and CSV/JSON export. Pins are stored in SafeStorage under a dedicated key.
 *
 * @module PinBoard
 * @returns {{ pinMessage: Function, unpinMessage: Function, toggle: Function, getPins: Function }}
 */
const PinBoard = (() => {
  const STORAGE_KEY = 'agenticchat_pinboard';
  let isOpen = false;

  function _load() {
    return SafeStorage.getJSON(STORAGE_KEY, []);
  }

  function _save(pins) {
    SafeStorage.trySetJSON(STORAGE_KEY, pins);
  }

  function pinMessage(role, content, opts = {}) {
    const pins = _load();
    const pin = {
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
      role: role || 'user',
      content: (content || '').slice(0, 5000),
      note: opts.note || '',
      tags: opts.tags || [],
      session: opts.session || (typeof SessionManager !== 'undefined' && SessionManager.current ? SessionManager.current.name : ''),
      pinnedAt: new Date().toISOString()
    };
    pins.unshift(pin);
    _save(pins);
    if (isOpen) _render();
    return pin;
  }

  function unpinMessage(id) {
    const pins = _load().filter(p => p.id !== id);
    _save(pins);
    _render();
  }

  function updateNote(id, note) {
    const pins = _load();
    const pin = pins.find(p => p.id === id);
    if (pin) { pin.note = note; _save(pins); _render(); }
  }

  function addTag(id, tag) {
    const pins = _load();
    const pin = pins.find(p => p.id === id);
    if (pin && tag && !pin.tags.includes(tag)) { pin.tags.push(tag); _save(pins); _render(); }
  }

  function removeTag(id, tag) {
    const pins = _load();
    const pin = pins.find(p => p.id === id);
    if (pin) { pin.tags = pin.tags.filter(t => t !== tag); _save(pins); _render(); }
  }

  function _render() {
    const list = DOMCache.get('pinboard-list');
    const empty = DOMCache.get('pinboard-empty');
    const filter = DOMCache.get('pinboard-filter')?.value || 'all';
    const search = (DOMCache.get('pinboard-search')?.value || '').toLowerCase();
    if (!list) return;

    let pins = _load();
    if (filter !== 'all') pins = pins.filter(p => p.role === filter);
    if (search) pins = pins.filter(p => p.content.toLowerCase().includes(search) || p.note.toLowerCase().includes(search) || p.tags.some(t => t.toLowerCase().includes(search)));

    if (pins.length === 0) {
      list.innerHTML = '';
      if (empty) empty.style.display = '';
      return;
    }
    if (empty) empty.style.display = 'none';

    list.innerHTML = pins.map(pin => {
      const date = new Date(pin.pinnedAt);
      const dateStr = date.toLocaleDateString() + ' ' + date.toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'});
      const tagsHtml = pin.tags.map(t => `<span class="pinboard-tag">${_esc(t)} <span style="cursor:pointer" class="pinboard-remove-tag" data-pin-id="${_esc(pin.id)}" data-tag="${_esc(t)}">&times;</span></span>`).join('');
      const preview = pin.content.length > 300 ? pin.content.slice(0, 300) + '…' : pin.content;
      return `<div class="pinboard-item" data-id="${_esc(pin.id)}">
        <div class="pinboard-item-header">
          <span class="pinboard-item-role ${_esc(pin.role)}">${_esc(pin.role)}</span>
          <span>${pin.session ? _esc(pin.session) + ' · ' : ''}${dateStr}</span>
          <div class="pinboard-item-actions">
            <button class="pinboard-action" data-action="note" data-pin-id="${_esc(pin.id)}" title="Add/edit note">📝</button>
            <button class="pinboard-action" data-action="tag" data-pin-id="${_esc(pin.id)}" title="Add tag">🏷️</button>
            <button class="pinboard-action" data-action="copy" data-pin-id="${_esc(pin.id)}" title="Copy content">📋</button>
            <button class="pinboard-action" data-action="unpin" data-pin-id="${_esc(pin.id)}" title="Unpin">❌</button>
          </div>
        </div>
        <div class="pinboard-item-content">${_esc(preview)}</div>
        ${tagsHtml ? '<div style="margin-top:6px">' + tagsHtml + '</div>' : ''}
        ${pin.note ? '<div class="pinboard-item-note">📝 ' + _esc(pin.note) + '</div>' : ''}
      </div>`;
    }).join('');

    // Bind actions via event delegation instead of inline onclick handlers
    list.querySelectorAll('.pinboard-action').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        const action = btn.dataset.action;
        const pinId = btn.dataset.pinId;
        if (action === 'note') PinBoard.promptNote(pinId);
        else if (action === 'tag') PinBoard.promptTag(pinId);
        else if (action === 'copy') PinBoard.copyPin(pinId);
        else if (action === 'unpin') PinBoard.unpinMessage(pinId);
      });
    });
    list.querySelectorAll('.pinboard-remove-tag').forEach(el => {
      el.addEventListener('click', (e) => {
        e.stopPropagation();
        PinBoard.removeTag(el.dataset.pinId, el.dataset.tag);
      });
    });
  }

  const _esc = _escapeHtml;

  function promptNote(id) {
    const pins = _load();
    const pin = pins.find(p => p.id === id);
    const note = prompt('Add a note to this pin:', pin?.note || '');
    if (note !== null) updateNote(id, note);
  }

  function promptTag(id) {
    const tag = prompt('Add a tag:');
    if (tag && tag.trim()) addTag(id, tag.trim());
  }

  function copyPin(id) {
    const pin = _load().find(p => p.id === id);
    if (pin) navigator.clipboard.writeText(pin.content).catch(() => {});
  }

  function exportPins() {
    const pins = _load();
    downloadBlob('pinboard-export.json', JSON.stringify(pins, null, 2), 'application/json');
  }

  function clearAll() {
    if (confirm('Remove all pinned messages?')) { _save([]); _render(); }
  }

  function open() {
    isOpen = true;
    const panel = DOMCache.get('pinboard-panel');
    const overlay = DOMCache.get('pinboard-overlay');
    if (panel) panel.style.display = '';
    if (overlay) overlay.style.display = '';
    _render();
  }

  function close() {
    isOpen = false;
    const panel = DOMCache.get('pinboard-panel');
    const overlay = DOMCache.get('pinboard-overlay');
    if (panel) panel.style.display = 'none';
    if (overlay) overlay.style.display = 'none';
  }

  function toggle() { isOpen ? close() : open(); }

  function init() {
    DOMCache.get('pinboard-close')?.addEventListener('click', close);
    DOMCache.get('pinboard-overlay')?.addEventListener('click', close);
    DOMCache.get('pinboard-export')?.addEventListener('click', exportPins);
    DOMCache.get('pinboard-clear')?.addEventListener('click', clearAll);
    DOMCache.get('pinboard-filter')?.addEventListener('change', _render);
    DOMCache.get('pinboard-search')?.addEventListener('input', _render);
    document.addEventListener('keydown', (e) => {
      if (e.altKey && e.key.toLowerCase() === 'p' && !e.ctrlKey && !e.shiftKey && !e.metaKey) {
        e.preventDefault();
        toggle();
      }
    });

    // Add "Pin" option to message context menus if they exist
    document.addEventListener('contextmenu', (e) => {
      const msgEl = e.target.closest('.message, .chat-message, [data-role]');
      if (!msgEl) return;
      // We don't override the context menu, but we inject pin buttons into messages below
    });
  }

  // Inject pin buttons into chat output messages
  function _injectPinButtons() {
    document.querySelectorAll('#chat-output .message, #chat-output .chat-message, #chat-output [data-role]').forEach(el => {
      if (el.dataset.pinReady) return;
      el.dataset.pinReady = '1';
      const pinBtn = document.createElement('button');
      pinBtn.textContent = '📌';
      pinBtn.title = 'Pin this message';
      pinBtn.style.cssText = 'position:absolute;top:4px;right:4px;background:none;border:none;cursor:pointer;opacity:0;transition:opacity .2s;font-size:.85rem;z-index:1;';
      el.style.position = 'relative';
      el.appendChild(pinBtn);
      el.addEventListener('mouseenter', () => pinBtn.style.opacity = '0.7');
      el.addEventListener('mouseleave', () => pinBtn.style.opacity = '0');
      pinBtn.addEventListener('click', (ev) => {
        ev.stopPropagation();
        const role = el.dataset.role || el.classList.contains('user') ? 'user' : 'assistant';
        const content = el.textContent.replace('📌', '').trim();
        pinMessage(role, content);
        pinBtn.textContent = '✅';
        setTimeout(() => pinBtn.textContent = '📌', 1200);
      });
    });
  }

  // Debounced pin-button injection to avoid per-mutation querySelectorAll
  // during streaming responses (previously fired hundreds of times/sec).
  let _pinInjectTimer = null;
  function _scheduleInjectPinButtons() {
    if (_pinInjectTimer) return;
    _pinInjectTimer = requestAnimationFrame(() => {
      _pinInjectTimer = null;
      _injectPinButtons();
    });
  }

  document.addEventListener('DOMContentLoaded', () => {
    init();
    ChatOutputObserver.register('messagePinning', function () { _scheduleInjectPinButtons(); }, { subtree: true });
  });

  return { open, close, toggle, init, pinMessage, unpinMessage, updateNote, addTag, removeTag, promptNote, promptTag, copyPin, exportPins, clearAll };
})();

