      '.sco-explore-btn{background:rgba(124,58,237,.2);border:none;color:#a855f7;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:14px}',
      '.sco-explore-btn:hover{background:rgba(124,58,237,.4)}',
